module decoder_64b66b (
    input  logic         clk_in,              // Clock signal
    input  logic         rst_in,              // Asynchronous reset (active high)
    input  logic [65:0]  decoder_data_in,     // 66-bit encoded input
    output logic [63:0]  decoder_data_out,    // Decoded 64-bit data output
    output logic         sync_error           // Sync error flag
);

    // Extract the sync header and data from the input word
    logic [1:0] sync_header; 
    logic [63:0] data_in;    

    assign sync_header = decoder_data_in[65:64];
    assign data_in     = decoder_data_in[63:0];

    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            decoder_data_out <= 64'b0; 
            sync_error       <= 1'b0;        
        end else begin
            if (sync_header == 2'b01) begin
                decoder_data_out <= data_in;
                sync_error       <= 1'b0;
            end else begin
                decoder_data_out <= 64'b0;
                sync_error       <= 1'b1;
            end
        end
    end

endmodule

output.rtl/encoder_64b66b.sv:
module encoder_64b66b (
    input  logic          clk_in,
    input  logic          rst_in,
    input  logic [63:0]   encoder_data_in,
    input  logic [7:0]    encoder_control_in,
    output logic [65:0]   encoder_data_out
);

  always_ff @(posedge clk_in or posedge rst_in) begin
    if (rst_in) begin
      encoder_data_out <= 66'd0;
    end else begin
      // Pure data encoding: if all control bits are 0
      if (encoder_control_in == 8'b00000000) begin
        encoder_data_out <= {2'b01, encoder_data_in};
      end else begin
        // Unsupported control word encoding: output sync word 2'b10 and zero data
        encoder_data_out <= {2'b10, 64'd0};
      end
    end
  end

endmodule

