output.rtl/priority_encoder.v:
module takes an 8-bit input vector "in" where in[7] has the highest priority
 * and in[0] has the lowest priority. The output "out" is a 3-bit binary code representing
 * the index of the highest active input line.
 *
 * Priority mapping:
 *   in[7] -> 3'b111
 *   in[6] -> 3'b110
 *   in[5] -> 3'b101
 *   in[4] -> 3'b100
 *   in[3] -> 3'b011
 *   in[2] -> 3'b010
 *   in[1] -> 3'b001
 *   in[0] -> 3'b000
 *
 * If no input is active (all zeros), the output defaults to 3'b000.
 */

module priority_encoder_8x3(
    input  [7:0] in,
    output reg [2:0] out
);

    always @(*) begin
        // Default: if no input is active, output is 3'b000.
        out = 3'b000;
        if (in[7])
            out = 3'b111;
        else if (in[6])
            out = 3'b110;
        else if (in[5])
            out = 3'b101;
        else if (in[4])
            out = 3'b100;
        else if (in[3])
            out = 3'b011;
        else if (in[2])
            out = 3'b010;
        else if (in[1])
            out = 3'b001;
        // in[0] is already handled by the default assignment (3'b000)
    end

endmodule

input.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

endmodule

output.rtl/cascaded_encoder.v:
module
// This module is parameterized with an input width N and an output width M = log2(N)
// It outputs the index of the first active input (MSB has highest priority)
// If no inputs are active, it defaults to 0.
////////////////////////////////////////////////////////////////////////////////
module priority_encoder #(parameter N = 8, parameter M = $clog2(N)) (
    input  [N-1:0] input_signal,
    output reg [M-1:0] out
);
    integer i;
    always @(*) begin
        out = 0;
        // Iterate from MSB to LSB to find the first active bit.
        for(i = N-1; i >= 0; i = i - 1) begin
            if (input_signal[i] && out == 0)
                out = i;
        end
    end
endmodule

////////////////////////////////////////////////////////////////////////////////
// New cascaded_encoder module
// This module handles a large input_signal by dividing it into two halves:
// - Upper half: Most significant half
// - Lower half: Least significant half
// Each half is processed by an instance of priority_encoder.
// The final output 'out' represents the index (in the full input width) of the
// highest-priority active input. Additionally, the outputs 'out_upper_half' and
// 'out_lower_half' provide the index within each half for debug purposes.
// If no inputs are active in either half, the output defaults to 0.
////////////////////////////////////////////////////////////////////////////////
module cascaded_encoder #(parameter N = 8, parameter M = $clog2(N)) (
    input  [N-1:0] input_signal,
    output [M-1:0] out,
    output [M-2:0] out_upper_half,
    output [M-2:0] out_lower_half
);
    // Define the size of each half (assumes N is even)
    localparam half_size = N/2;

    // Wires to capture the priority indices from each half.
    wire [M-2:0] upper_priority;
    wire [M-2:0] lower_priority;

    // Instance for the upper half: bits from N-1 downto half_size
    priority_encoder #(.N(half_size), .M($clog2(half_size))) upper_encoder (
        .input_signal(input_signal[N-1:half_size]),
        .out(upper_priority)
    );

    // Instance for the lower half: bits from half_size-1 downto 0
    priority_encoder #(.N(half_size), .M($clog2(half_size))) lower_encoder (
        .input_signal(input_signal[half_size-1:0]),
        .out(lower_priority)
    );

    // Final output: if an active bit is found in the upper half, use that index;
    // otherwise, add half_size to the lower half's index.
    always @(*) begin
        if (upper_priority != 0)
            out = upper_priority;
        else
            out = lower_priority + half_size;
    end
endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

  // Internal Signals
  reg        clk_div2;
  reg  [1:0] current_state, next_state;
  reg  [4:0] shift_reg;
  reg  [2:0] bit_count;
  reg  [4:0] old_data;
  reg        latch_counter; // Used to generate a one-cycle pulse in LATCH state

  // Parameters for FSM States
  localparam IDLE  = 2'b00,
             LOAD  = 2'b01,
             SHIFT = 2'b10,
             LATCH = 2'b11;

  // Clock Divider: Generate a slower clock (divide system clock by 2)
  always @(posedge clk or posedge reset) begin
    if (reset)
      clk_div2 <= 1'b0;
    else
      clk_div2 <= ~clk_div2;
  end

  // FSM for serial data shifting and latching
  always @(posedge clk_div2 or posedge reset) begin
    if (reset) begin
      current_state   <= IDLE;
      ATTN_CLK        <= 1'b0;
      ATTN_DATA       <= 1'b0;
      ATTN_LE         <= 1'b0;
      shift_reg       <= 5'b00000;
      bit_count       <= 3'd0;
      old_data        <= 5'b00000;
      latch_counter   <= 1'b0;
    end else begin
      current_state <= next_state;
      case (current_state)
        IDLE: begin
          // Transition to LOAD if new data is detected
          if (data != old_data)
            next_state = LOAD;
          else
            next_state = IDLE;
          ATTN_CLK  <= 1'b0;
          ATTN_DATA <= 1'b0;
          ATTN_LE   <= 1'b0;
        end
        LOAD: begin
          // Capture new data and reset the bit counter
          shift_reg <= data;
          bit_count <= 3'd0;
          old_data  <= data;
          next_state = SHIFT;
          ATTN_CLK  <= 1'b0;
          ATTN_DATA <= 1'b0;
          ATTN_LE   <= 1'b0;
        end
        SHIFT: begin
          // Output the LSB of the shift register
          ATTN_DATA <= shift_reg[0];
          // Drive the attenuator clock using the divided clock signal
          ATTN_CLK  <= clk_div2;
          // Shift the register right by one bit
          shift_reg <= shift_reg >> 1;
          // Increment the bit counter
          bit_count <= bit_count + 1;
          // After shifting 5 bits, transition to LATCH state
          if (bit_count == 4)
            next_state = LATCH;
          else
            next_state = SHIFT;
        end
        LATCH: begin
          // Generate a one-cycle pulse on ATTN_LE
          if (latch_counter == 1'b0) begin
            ATTN_LE    <= 1'b1;
            latch_counter <= 1'b1;
            next_state = LATCH; // Remain in LATCH for one more cycle
          end else begin
            ATTN_LE    <= 1'b0;
            latch_counter <= 1'b0;
            next_state = IDLE;
          end
          ATTN_DATA <= 1'b0;
          ATTN_CLK  <= 1'b0;
        end
      endcase
    end
  end

endmodule

output.rtl/GP.v:
module GP (
    input  i_A,
    input  i_B,
    input  i_Cin,
    output o_generate,
    output o_propagate,
    output o_Cout
);

    // Generate is true if both inputs are 1.
    assign o_generate = i_A & i_B;

    // Propagate is true if either input is 1.
    assign o_propagate = i_A | i_B;

    // Carry-out is generated if generate is true, or if propagate is true and carry-in is high.
    assign o_Cout = o_generate | (o_propagate & i_Cin);

endmodule

input.rtl/pipelined_adder_32bit.sv:
module pipelined_adder_32bit (
    input clk,       // Synchronous to posedge of clk 
    input reset,     // Synchronous active high reset
    input [31:0] A,  // 32 bit operand for addition  
    input [31:0] B,  // 32 bit operand for addition  
    input start,     // Active high signal to indicate when valid input data is provided
    output [31:0] S, // Final sum or result 
    output Co,       // Final carry out 
    output done      // Completion signal, active high when computation is complete    
);

    wire [7:0] A1, B1, A2, B2, A3, B3;
    wire carry1, carry2, carry3;
    wire [7:0] s13, s23, s12, A21, B21, A31, B31, A32, B32;
    wire [7:0] s1, s2, s3;
    wire control2, control1, control3, control4;

    dff #(1) FF00 (.clk(clk), .reset(reset), .D(1'b1), .Q(control1));

    dff #(8) FF11 (.clk(clk), .reset(reset), .D(A[15:8]), .Q(A1));
    dff #(8) FF12 (.clk(clk), .reset(reset), .D(B[15:8]), .Q(B1));
    dff #(8) FF13 (.clk(clk), .reset(reset), .D(A[23:16]), .Q(A2));
    dff #(8) FF14 (.clk(clk), .reset(reset), .D(B[23:16]), .Q(B2));
    dff #(8) FF15 (.clk(clk), .reset(reset), .D(A[31:24]), .Q(A3));
    dff #(8) FF16 (.clk(clk), .reset(reset), .D(B[31:24]), .Q(B3));

    carry_lookahead_adder #(8) ADD1 (.clk(clk), .reset(reset), .A(A[7:0]), .B(B[7:0]), .Cin(1'b0), .S(s1), .carry(carry1));

