    parameter signed [15:0] a6 = -16'h0300;

    parameter logic [7:0] unused_param = 8'hFF;

    logic signed [15:0] x_prev1, x_prev2, x_prev3, x_prev4, x_prev5, x_prev6;
    logic signed [15:0] y_prev1, y_prev2, y_prev3, y_prev4, y_prev5, y_prev6;

    logic signed [31:0] temp_y;
    logic undriven_signal;

    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            x_prev1 <= 0; x_prev2 <= 0; x_prev3 <= 0;
            x_prev4 <= 0; x_prev5 <= 0; x_prev6 <= 0;
            y_prev1 <= 0; y_prev2 <= 0; y_prev3 <= 0;
            y_prev4 <= 0; y_prev5 <= 0; y_prev6 <= 0;
        end else begin
            temp_y = (b0 * x + b1 * x_prev1 + b2 * x_prev2 + b3 * x_prev3 +
                      b4 * x_prev4 + b5 * x_prev5 + b6 * x_prev6 -
                      a1 * y_prev1 - a2 * y_prev2 - a3 * y_prev3 -
                      a4 * y_prev4 - a5 * y_prev5 - a6 * y_prev6) >>> 16;

            y <= temp_y; 

            if (x > 16'h8000) 
                y <= 16'h7FFF; 

            undriven_signal = y_prev3 ^ y_prev5;

            x_prev6 <= x_prev5; x_prev5 <= x_prev4; x_prev4 <= x_prev3;
            x_prev3 <= x_prev2; x_prev2 <= x_prev1; x_prev1 <= x;
            y_prev6 <= y_prev5; y_prev5 <= y_prev4; y_prev4 <= y_prev3;
            y_prev3 <= y_prev2; y_prev2 <= y_prev1; y_prev1 <= y;
        end
    end

endmodule

output.rtl/iir_filter.sv:
module iir_filter (
    input  logic         clk,
    input  logic         rst,
    input  logic signed  [15:0] x,    
    output logic signed  [15:0] y    
);

    // Filter coefficients
    parameter signed [15:0] b0 = 16'h0F00;
    parameter signed [15:0] b1 = 16'h0E00;
    parameter signed [15:0] b2 = 16'h0D00;
    parameter signed [15:0] b3 = 16'h0C00;
    parameter signed [15:0] b4 = 16'h0B00;
    parameter signed [15:0] b5 = 16'h0A00;
    parameter signed [15:0] b6 = 16'h0900;
    parameter signed [15:0] a1 = -16'h0800;
    parameter signed [15:0] a2 = -16'h0700;
    parameter signed [15:0] a3 = -16'h0600;
    parameter signed [15:0] a4 = -16'h0500;
    parameter signed [15:0] a5 = -16'h0400;
    parameter signed [15:0] a6 = -16'h0300;

    // Delay registers for input and output
    logic signed [15:0] x_prev1, x_prev2, x_prev3, x_prev4, x_prev5, x_prev6;
    logic signed [15:0] y_prev1, y_prev2, y_prev3, y_prev4, y_prev5, y_prev6;

    // Intermediate result (32-bit to accommodate multiplication)
    logic signed [31:0] temp_y;

    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            x_prev1 <= 0; x_prev2 <= 0; x_prev3 <= 0;
            x_prev4 <= 0; x_prev5 <= 0; x_prev6 <= 0;
            y_prev1 <= 0; y_prev2 <= 0; y_prev3 <= 0;
            y_prev4 <= 0; y_prev5 <= 0; y_prev6 <= 0;
        end else begin
            // Compute the filter output
            temp_y = (b0 * x + b1 * x_prev1 + b2 * x_prev2 + b3 * x_prev3 +
                      b4 * x_prev4 + b5 * x_prev5 + b6 * x_prev6 -
                      a1 * y_prev1 - a2 * y_prev2 - a3 * y_prev3 -
                      a4 * y_prev4 - a5 * y_prev5 - a6 * y_prev6) >>> 16;

            // Use an if-else block to avoid multiple assignments to y
            if (x > 16'h8000) begin
                y <= 16'h7FFF;
            end else begin
                y <= temp_y[15:0];
            end

            // Shift delay registers
            x_prev6 <= x_prev5; x_prev5 <= x_prev4; x_prev4 <= x_prev3;
            x_prev3 <= x_prev2; x_prev2 <= x_prev1; x_prev1 <= x;
            y_prev6 <= y_prev5; y_prev5 <= y_prev4; y_prev4 <= y_prev3;
            y_prev3 <= y_prev2; y_prev2 <= y_prev1; y_prev1 <= y;
        end
    end

endmodule

output.rtl/serial_line_code_converter.sv:
module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ encoding output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Cumulative XOR for parity calculation
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Clock Pulse Generation
    // Divide the system clock by CLK_DIV and generate a pulse when the counter reaches CLK_DIV - 1.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            clk_counter <= 0;
        else begin
            if (clk_counter == CLK_DIV - 1)
                clk_counter <= 0;
            else
                clk_counter <= clk_counter + 1;
        end
    end

    assign clk_pulse = (clk_counter == CLK_DIV - 1);

    // Previous Serial Input Tracking for edge detection
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            prev_value <= 0;
            prev_serial_in <= 0;
        end else begin
            prev_value <= serial_in;
            prev_serial_in <= prev_value;
        end
    end

    // NRZ Pass-Through (direct output of serial_in)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            nrz_out <= 0;
        else
            nrz_out <= serial_in;
    end

    // Return-to-Zero (RZ) Encoding
    // Output high only during the first half of the clock cycle when serial_in is high.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            rz_out <= 0;
        else begin
            if (clk_pulse)
                rz_out <= serial_in;  // Sample serial_in on clk_pulse
            else
                rz_out <= 0;
        end
    end

    // Differential Encoding
    // Compute the output by XORing the current serial_in with the previous serial input.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            diff_out <= 0;
        else
            diff_out <= serial_in ^ prev_serial_in;
    end

    // Inverted NRZ Encoding
    // Generate the output by inverting the serial_in signal.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            inv_nrz_out <= 0;
        else
            inv_nrz_out <= ~serial_in;
    end

    // NRZ with Alternating Bit Inversion
    // Toggle inversion on each clock cycle: alternate between inverted and non-inverted serial_in.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_state <= 0;
            alt_invert_out <= 0;
        end else begin
            alt_invert_state <= ~alt_invert_state;  // Toggle state each cycle
            if (alt_invert_state)
                alt_invert_out <= ~serial_in;
            else
                alt_invert_out <= serial_in;
        end
    end

    // Parity Bit Output (Odd Parity Calculation)
    // Generate an odd parity bit by computing the cumulative XOR of received bits.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            parity_out <= 0;
        else
            parity_out <= parity_out ^ serial_in;
    end

    // Scrambled NRZ (Simple XOR with a fixed pattern)
    // XOR serial_in with the LSB of the clock counter to scramble the signal.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            scrambled_out <= 0;
        else
            scrambled_out <= serial_in ^ clk_counter[0];
    end

    // Edge-Triggered NRZ
    // Detect rising edges of serial_in and output accordingly.
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            edge_triggered_out <= 0;
        else
            edge_triggered_out <= (serial_in & ~prev_serial_in);
    end

    // Output Multiplexer: Select the encoding output based on the mode input.
    // Valid modes: 000: NRZ, 001: RZ, 010: Differential, 011: Inverted NRZ,
    // 100: Alternating Bit Inversion, 101: Odd Parity, 110: Scrambled NRZ, 111: Edge-Triggered NRZ.
    always_comb begin
        case(mode)
            3'd0: serial_out = nrz_out;         // NRZ
            3'd1: serial_out = rz_out;          // RZ
            3'd2: serial_out = diff_out;        // Differential Encoding
            3'd3: serial_out = inv_nrz_out;     // Inverted NRZ
            3'd4: serial_out = alt_invert_out;  // NRZ with Alternating Bit Inversion
            3'd5: serial_out = ~parity_out;     // Odd Parity Bit Output (complement of cumulative XOR)
            3'd6: serial_out = scrambled_out;   // Scrambled NRZ
            3'd7: serial_out = edge_triggered_out; // Edge-Triggered NRZ
            default: serial_out = 1'b0;         // Invalid mode defaults to 0.
        endcase
    end

endmodule

input.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

