module alphablending #(
    parameter H = 5,
    parameter N = 3,
    parameter W = 8
) (
    input clk,
    input reset,
    input start,
    input [(24*H*W)-1:0] pixel_in,    // N pixels, each 24-bit RGB
    input [(8*H*W)-1:0] alpha_in,     // N alpha values, each 8-bit
    input [(24*H*W)-1:0] bg_pixel_in, // N background pixels, each 24-bit RGB
    output reg [(24*H*W)-1:0] blended_out, // N blended output pixels
    output reg done
);

  // State Encoding
  localparam IDLE    = 2'b00;
  localparam LOAD    = 2'b01;
  localparam COMPUTE = 2'b10;
  localparam COMPLETE= 2'b11; // Removed duplicate STORE state

  reg [1:0] state, next_state;

  // Registers for inputs and outputs
  reg [23:0] pixel [0:H*W-1];       // Individual pixels (24-bit each)
  reg [7:0] alpha [0:H*W-1];        // Individual alpha values (8-bit each)
  reg [23:0] bg_pixel [0:H*W-1];    // Individual background pixels (24-bit each)
  reg [23:0] blended [0:H*W-1];     // Individual blended results (24-bit each)

  // Pixel count and padding logic
  integer i;
  integer pixel_count;
  integer total_pixels;
  integer padded_pixels;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      pixel_count   <= 0;
      total_pixels  <= 0;
      padded_pixels <= 0;
    end else if (state == IDLE && start) begin
      pixel_count   <= 0;
      total_pixels  <= H * W;
      padded_pixels <= (((H * W + N - 1) / N) * N) - (H * W);
    end else if (state == COMPUTE && pixel_count < total_pixels + padded_pixels) begin
      pixel_count <= pixel_count + N;
    end
  end

  // State Transition Logic
  always @(posedge clk or posedge reset) begin
    if (reset)
      state <= IDLE;
    else
      state <= next_state;
  end

  // Next State Logic
  always @(*) begin
    case (state)
      IDLE:    next_state = (start) ? LOAD : IDLE;
      LOAD:    next_state = COMPUTE;
      COMPUTE: next_state = (pixel_count < total_pixels + padded_pixels) ? LOAD : COMPLETE;
      COMPLETE: next_state = IDLE;
      default: next_state = IDLE;
    endcase
  end

  // Combined Alpha Blending and Output Logic with asynchronous reset
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      // Optionally, reset internal arrays if needed
      done         <= 0;
      blended_out  <= 0;
    end else begin
      case (state)
        LOAD: begin
          // Unpack inputs into arrays
          for (i = 0; i < N; i = i + 1) begin
            if (pixel_count + i < total_pixels) begin
              pixel[i]   <= pixel_in[(pixel_count + i)*24 +: 24];
              alpha[i]   <= alpha_in[(pixel_count + i)*8 +: 8];
              bg_pixel[i] <= bg_pixel_in[(pixel_count + i)*24 +: 24];
            end else begin
              pixel[i]   <= 24'd0; // Pad with 0 if out of bounds
              alpha[i]   <= 8'd0;
              bg_pixel[i] <= 24'd0;
            end
          end
        end
        COMPUTE: begin
          for (i = 0; i < N; i = i + 1) begin
            blended[pixel_count + i][23:16] <= (alpha[i] * pixel[i][23:16] + (255 - alpha[i]) * bg_pixel[i][23:16]) / 255;
            blended[pixel_count + i][15:8]  <= (alpha[i] * pixel[i][15:8]  + (255 - alpha[i]) * bg_pixel[i][15:8])  / 255;
            blended[pixel_count + i][7:0]   <= (alpha[i] * pixel[i][7:0]   + (255 - alpha[i]) * bg_pixel[i][7:0])   / 255;
          end
        end
        COMPLETE: begin
          // Pack blended results into output
          for (i = 0; i < H*W; i = i + 1) begin
            blended_out[i*24 +: 24] <= blended[i];
          end
          done <= 1;
        end
        default: begin
          done <= 0;
        end
      endcase
    end
  end

endmodule

input.rtl/apb_dsp_op.sv:
// APB DSP Operation Module
module apb_dsp_op #(
    parameter ADDR_WIDTH = 'd8,
    parameter DATA_WIDTH = 'd32
) (
    input  logic                  clk_dsp,    // Faster clock to DSP operation
    input  logic                  en_clk_dsp, // Enable DSP operation with faster clock
    input  logic                  PCLK,       // APB clock
    input  logic                  PRESETn,    // Active low asynchronous APB Reset
    input  logic [ADDR_WIDTH-1:0] PADDR,      // APB address
    input  logic                  PWRITE,     // Write/Read enable
    input  logic [DATA_WIDTH-1:0] PWDATA,     // Write data
    input  logic                  PSEL,       // DSP selector
    input  logic                  PENABLE,    // APB enable
    output logic [DATA_WIDTH-1:0] PRDATA,     // Read data
    output logic                  PREADY      // Ready signal
);

    // Clock sel logic
    assign dsp_clk_sel = (en_clk_dsp) ? clk_dsp : PCLK;

    // Internal registers address map
    localparam ADDRESS_A         = 32'h0;  // 0x00
    localparam ADDRESS_B         = 32'h4;  // 0x04
    localparam ADDRESS_C         = 32'h8;  // 0x08
    localparam ADDRESS_O         = 32'hC;  // 0x0C
    localparam ADDRESS_CONTROL   = 32'h10; // 0x10
    localparam ADDRESS_WDATA     = 32'h14; // 0x14
    localparam ADDRESS_SRAM_ADDR = 32'h18; // 0x18

    // Control modes
    localparam SRAM_WRITE     = 32'd1;
    localparam SRAM_READ      = 32'd2;
    localparam DSP_READ_OP_A  = 32'd3;
    localparam DSP_READ_OP_B  = 32'd4;
    localparam DSP_READ_OP_C  = 32'd5;
    localparam DSP_WRITE_OP_O = 32'd6;

    // Internal signals
    logic [DATA_WIDTH-1:0] reg_operand_a;
    logic [DATA_WIDTH-1:0] reg_operand_b;
    logic [DATA_WIDTH-1:0] reg_operand_c;
    logic [DATA_WIDTH-1:0] reg_operand_o;
    logic [DATA_WIDTH-1:0] reg_control;
    logic [DATA_WIDTH-1:0] reg_wdata_sram;
    logic [DATA_WIDTH-1:0] reg_addr_sram;

    logic signed [DATA_WIDTH-1:0] wire_op_a;
    logic signed [DATA_WIDTH-1:0] wire_op_b;
    logic signed [DATA_WIDTH-1:0] wire_op_c;
    logic signed [DATA_WIDTH-1:0] wire_op_o;
    logic        [DATA_WIDTH-1:0] sram_data_in;
    logic                         sram_we;
    logic        [DATA_WIDTH-1:0] sram_addr;
    logic        [DATA_WIDTH-1:0] sram_data_out;

    // APB interface logic
    always_ff @(posedge PCLK or negedge PRESETn) begin
        if (!PRESETn) begin
            reg_operand_a  <= 'd0;
            reg_operand_b  <= 'd0;
            reg_operand_c  <= 'd0;
            reg_operand_o  <= 'd0;
            reg_control    <= 'd0;
            reg_wdata_sram <= 'd0;
            reg_addr_sram  <= 'd0;
            PREADY <= 1'b0;
        end else if (PENABLE & PSEL) begin
            PREADY <= 1'b1;
            if (PWRITE) begin
                case (PADDR)
                    ADDRESS_A         : reg_operand_a  <= PWDATA;
                    ADDRESS_B         : reg_operand_b  <= PWDATA;
                    ADDRESS_C         : reg_operand_c  <= PWDATA;
                    ADDRESS_O         : reg_operand_o  <= PWDATA;
                    ADDRESS_CONTROL   : reg_control    <= PWDATA;
                    ADDRESS_WDATA     : reg_wdata_sram <= PWDATA;
                    ADDRESS_SRAM_ADDR : reg_addr_sram  <= PWDATA;
                endcase
            end else begin
                if (reg_control == SRAM_READ) begin
                    PRDATA <= sram_data_out;
                end else begin
                    case (PADDR)
                        ADDRESS_A         : PRDATA <= reg_operand_a;
                        ADDRESS_B         : PRDATA <= reg_operand_b;
                        ADDRESS_C         : PRDATA <= reg_operand_c;
                        ADDRESS_O         : PRDATA <= reg_operand_o;
                        ADDRESS_CONTROL   : PRDATA <= reg_control;
                        ADDRESS_WDATA     : PRDATA <= reg_wdata_sram;
                        ADDRESS_SRAM_ADDR : PRDATA <= reg_addr_sram;
                    endcase
                end               
            end
        end
    end

    // SRAM logic
    logic [DATA_WIDTH-1:0] mem [63:0];

    always_comb begin
        sram_data_in = (reg_control == SRAM_WRITE) ? reg_wdata_sram : wire_op_o;

        if ((reg_control == SRAM_WRITE) || (reg_control == DSP_WRITE_OP_O)) begin
            sram_we = 1'b1;
        end else begin
            sram_we = 1'b0;
        end

        case (reg_control)
            DSP_READ_OP_A  : sram_addr = reg_operand_a;
            DSP_READ_OP_B  : sram_addr = reg_operand_b;
            DSP_READ_OP_C  : sram_addr = reg_operand_c;
            DSP_WRITE_OP_O : sram_addr = reg_operand_o;
            default        : sram_addr = reg_addr_sram;
        endcase
    end

    always_ff @(posedge PCLK) begin
        if (sram_we) begin
            mem[sram_addr] <= sram_data_in;
        end else begin
            sram_data_out <= mem[sram_addr];
        end
    end

    // DSP operation
    always_ff @(posedge dsp_clk_sel) begin
        case (reg_control)
            DSP_READ_OP_A  : wire_op_a <= sram_data_out;
            DSP_READ_OP_B  : wire_op_b <= sram_data_out;
            DSP_READ_OP_C  : wire_op_c <= sram_data_out;
        endcase
    end

    assign wire_op_o = (wire_op_a * wire_op_b) + wire_op_c;

endmodule

