output.rtl/apb_dsp_unit.v:
module implements configuration registers and supports two modes:
//   - Arithmetic mode (Addition or Multiplication): Operands are read from an internal 1KB SRAM
//     using addresses specified by r_operand_1 and r_operand_2. The computed result is stored
//     in the computed_result register (accessible via APB at address 0x5).
//   - Data Writing mode: When r_Enable==3, the data in r_write_data is written to the SRAM
//     at the address specified by r_write_address.
// APB addresses 0x00 to 0x05 are reserved for configuration registers.
// Other addresses (0x06 to 0xFF) are mapped to the internal SRAM.
//
// APB Signals:
//   pclk         : APB clock (synchronous operations)
//   presetn      : Active-low asynchronous reset
//   paddr        : 10-bit address bus (APB)
//   pselx        : APB select signal (indicates CSR/memory selection)
//   penable      : APB enable signal (transaction progression)
//   pwrite       : Write enable (high for write, low for read)
//   pwdata       : 8-bit write data bus
//   pready       : Ready signal (always high after two cycles)
//   prdata       : 8-bit read data bus
//   pslverr      : Error signal (invalid address or unsupported operation)
//
// SRAM Interface:
//   sram_valid   : When high, the data in r_write_data is latched to the SRAM at address r_write_address.
//
// Note: This design implements a simple two-cycle state machine for APB transactions.
//       All APB read/write operations complete in two clock cycles with PREADY always driven high.
//       Arithmetic operations (addition/multiplication) are performed on data read from the internal SRAM.
//       The internal SRAM is modeled as a 1024-word (1KB) array of 8-bit words.
//
// Register Map (APB addresses):
//   0x00: r_operand_1   - Address for first operand (8-bit, used as SRAM address with upper bits = 0)
//   0x01: r_operand_2   - Address for second operand
//   0x02: r_Enable      - Operational mode:
//                           0: DSP disabled
//                           1: Addition mode
//                           2: Multiplication mode
//                           3: Data Writing mode
//   0x03: r_write_address - Address in SRAM where data will be written (only lower 8 bits used)
//   0x04: r_write_data    - Data to be written into SRAM
//   0x05: computed_result - Result of arithmetic operation (addition or multiplication)
//
// For addresses >= 6, the APB interface directly accesses the internal SRAM.
//------------------------------------------------------------

module apb_dsp_unit (
    input  wire         pclk,
    input  wire         presetn,
    input  wire [9:0]   paddr,
    input  wire         pselx,
    input  wire         penable,
    input  wire         pwrite,
    input  wire [7:0]   pwdata,
    output reg          pready,
    output reg [7:0]    prdata,
    output reg          pslverr,
    output reg          sram_valid
);

  //-------------------------------------------------------------------------
  // Internal State Machine for APB Transactions
  //-------------------------------------------------------------------------
  localparam IDLE  = 2'd0,
             ACCESS = 2'd1;
  reg [1:0] state;

  // Latch registers for APB transaction
  reg [9:0] addr_latch;
  reg [7:0] data_latch;
  reg [7:0] data_out;  // For read data

  //-------------------------------------------------------------------------
  // Configuration Registers
  //-------------------------------------------------------------------------
  reg [7:0] r_operand_1;      // APB address 0x00
  reg [7:0] r_operand_2;      // APB address 0x01
  reg [7:0] r_Enable;         // APB address 0x02
  reg [7:0] r_write_address;  // APB address 0x03
  reg [7:0] r_write_data;     // APB address 0x04
  reg [7:0] computed_result;  // APB address 0x05

  //-------------------------------------------------------------------------
  // Internal SRAM (1KB)
  //-------------------------------------------------------------------------
  reg [7:0] sram_mem [0:1023];

  //-------------------------------------------------------------------------
  // Main Sequential Process: APB Transaction and Functionality
  //-------------------------------------------------------------------------
  always @(posedge pclk or negedge presetn) begin
    if (!presetn) begin
      // Reset all registers and signals to default values
      r_operand_1      <= 8'd0;
      r_operand_2      <= 8'd0;
      r_Enable         <= 8'd0;
      r_write_address  <= 8'd0;
      r_write_data     <= 8'd0;
      computed_result  <= 8'd0;
      pslverr          <= 1'b0;
      pready           <= 1'b1;
      sram_valid       <= 1'b0;
      state            <= IDLE;
    end
    else begin
      // Default assignments
      pready  <= 1'b1;
      pslverr <= 1'b0;
      sram_valid <= 1'b0;

      //-----------------------------
      // APB Transaction State Machine
      //-----------------------------
      case (state)
        IDLE: begin
          if (pselx && penable) begin
            // Latch the current APB address and data
            addr_latch <= paddr;
            data_latch <= pwdata;
            state      <= ACCESS;
          end
        end

        ACCESS: begin
          // Check if the accessed address is a configuration register (0x00-0x05)
          if (addr_latch < 6) begin
            // Configuration register access
            if (pwrite) begin
              case (addr_latch)
                10'd0: r_operand_1      <= data_latch;
                10'd1: r_operand_2      <= data_latch;
                10'd2: r_Enable         <= data_latch;
                10'd3: r_write_address  <= data_latch;
                10'd4: r_write_data     <= data_latch;
                10'd5: computed_result  <= data_latch; // Allow override if needed
                default: pslverr         <= 1'b1;
              endcase
            end
            else begin
              case (addr_latch)
                10'd0: data_out <= r_operand_1;
                10'd1: data_out <= r_operand_2;
                10'd2: data_out <= r_Enable;
                10'd3: data_out <= r_write_address;
                10'd4: data_out <= r_write_data;
                10'd5: data_out <= computed_result;
                default: pslverr <= 1'b1;
              endcase
            end
          end
          else begin
            // Memory access: addresses 0x06 to 0xFF (i.e. 6 to 1023)
            if (pwrite) begin
              sram_mem[addr_latch] <= data_latch;
            end
            else begin
              data_out <= sram_mem[addr_latch];
            end
          end
          state <= IDLE;
        end

        default: state <= IDLE;
      endcase

      //-------------------------------------------------------------------------
      // Indirect SRAM Write: Triggered when DSP is in Data Writing mode
      //-------------------------------------------------------------------------
      if (r_Enable == 8'd3) begin
        sram_valid <= 1'b1;
        // Use the lower 8 bits of r_write_address as the SRAM address.
        sram_mem[{2'b0, r_write_address}] <= r_write_data;
      end
      else begin
        sram_valid <= 1'b0;
      end

      //-------------------------------------------------------------------------
      // Arithmetic Operations: Addition or Multiplication
      //-------------------------------------------------------------------------
      if (r_Enable == 8'd1 || r_Enable == 8'd2) begin
        // Read operands from SRAM using addresses specified in r_operand_1 and r_operand_2.
        // Note: r_operand_1 and r_operand_2 are 8-bit values; the upper 2 bits are assumed 0.
        if (r_Enable == 8'd1) begin
          computed_result <= sram_mem[{2'b0, r_operand_1}] + sram_mem[{2'b0, r_operand_2}];
        end
        else begin
          computed_result <= sram_mem[{2'b0, r_operand_1}] * sram_mem[{2'b0, r_operand_2}];
        end
      end
    end
  end

  //-------------------------------------------------------------------------
  // Drive the prdata output based on the current state.
  // In the ACCESS state, prdata is driven by the latched read data.
  //-------------------------------------------------------------------------
  always @(*) begin
    prdata = (state == ACCESS) ? data_out : 8'd0;
  end

endmodule

output.rtl/cvdp_copilot_apb_gpio.sv:
module compliant with the Advanced Peripheral Bus (APB)
//              protocol. Supports configurable GPIO width, bidirectional control, interrupt
//              generation (both edge‐ and level‐sensitive) with polarity configuration, and
//              robust two‐stage synchronization.
//              
//              Register Map:
//                0x00: GPIO Input Data       (Read-only; reflects synchronized gpio_in)
//                0x04: GPIO Output Data      (Writes drive gpio_out)
//                0x08: GPIO Output Enable    (Configures direction: High = Output, Low = Input)
//                0x0C: GPIO Interrupt Enable (Enables/disables per-pin interrupts)
//                0x10: GPIO Interrupt Type   (0 = Level sensitive, 1 = Edge sensitive)
//                0x14: GPIO Interrupt Polarity (1 = Active high, 0 = Active low)
//                0x18: GPIO Interrupt State  (Read-only; reflects current interrupt status)
//
//              APB Behavior:
//                - Always-high ready (pready = 1)
//                - No errors (pslverr = 0)
//                - Write transactions update registers; read transactions return the content
//                  of the addressed register.
//                - Undefined addresses return prdata = 0.
//
//              Interrupt Logic:
//                For each GPIO pin, if enabled:
//                  • In Level Sensitive mode (reg_int_type = 0):
//                      - If polarity is active high, an interrupt is asserted when the input is high.
//                      - If polarity is active low, an interrupt is asserted when the input is low.
//                  • In Edge Sensitive mode (reg_int_type = 1):
//                      - If polarity is active high, a rising edge triggers an interrupt.
//                      - If polarity is active low, a falling edge triggers an interrupt.
//                The combined interrupt (comb_int) is the logical OR of all individual interrupts.
//
//              Reset:
//                All registers and internal signals are reset to 0 when preset_n is low.
//
// Parameters:
//   GPIO_WIDTH: Default width is 8; can be reconfigured.
//
module cvdp_copilot_apb_gpio #(
    parameter GPIO_WIDTH = 8
)
(
    input  wire                   pclk,
    input  wire                   preset_n,  // Active-low asynchronous reset
    input  wire                   psel,
    input  wire [7:0]             paddr,     // Only lower 6 bits [7:2] are used for addressing
    input  wire                   penable,
    input  wire                   pwrite,
    input  wire [31:0]            pwdata,
    input  wire [GPIO_WIDTH-1:0]  gpio_in,
    output reg  [31:0]            prdata,
    output reg                    pready,
    output reg                    pslverr,
    output reg  [GPIO_WIDTH-1:0]  gpio_out,
    output reg  [GPIO_WIDTH-1:0]  gpio_enable,
    output reg  [GPIO_WIDTH-1:0]  gpio_int,
    output wire                   comb_int
);

    //-------------------------------------------------------------------------
    // Internal 32-bit registers for APB access (only lower GPIO_WIDTH bits are used)
    //-------------------------------------------------------------------------
    reg [31:0] reg_in;           // 0x00: GPIO Input Data (read-only)
    reg [31:0] reg_out;          // 0x04: GPIO Output Data
    reg [31:0] reg_enable;       // 0x08: GPIO Output Enable
    reg [31:0] reg_int_enable;   // 0x0C: GPIO Interrupt Enable
    reg [31:0] reg_int_type;     // 0x10: GPIO Interrupt Type (0 = level, 1 = edge)
    reg [31:0] reg_int_polarity; // 0x14: GPIO Interrupt Polarity (1 = active high, 0 = active low)
    reg [31:0] reg_int_state;    // 0x18: GPIO Interrupt State (read-only)

    //-------------------------------------------------------------------------
    // Two-stage synchronization for gpio_in to mitigate metastability.
    //-------------------------------------------------------------------------
    reg [GPIO_WIDTH-1:0] gpio_in_sync;
    reg [GPIO_WIDTH-1:0] gpio_in_sync_prev;

    //-------------------------------------------------------------------------
    // Output assignments for APB protocol.
    //-------------------------------------------------------------------------
    // Always-ready and no-error signals.
    assign pready = 1'b1;
    assign pslverr = 1'b0;
    // Combined interrupt: logical OR of all individual gpio_int signals.
    assign comb_int = |gpio_int;

    //-------------------------------------------------------------------------
    // Interrupt Generation Logic:
    // For each GPIO pin:
    //   - If interrupt is enabled, then:
    //       • In Level Sensitive mode (reg_int_type = 0):
    //             If polarity is active high, assert interrupt when input is high.
    //             If polarity is active low, assert interrupt when input is low.
    //       • In Edge Sensitive mode (reg_int_type = 1):
    //             If polarity is active high, detect rising edge (transition 0->1).
    //             If polarity is active low, detect falling edge (transition 1->0).
    //-------------------------------------------------------------------------
    always_comb begin
        for (int i = 0; i < GPIO_WIDTH; i++) begin
            if (reg_int_enable[i]) begin
                if (!reg_int_type[i]) begin  // Level-sensitive mode
                    if (reg_int_polarity[i])
                        gpio_int[i] = gpio_in_sync[i];
                    else
                        gpio_int[i] = ~gpio_in_sync[i];
                end else begin  // Edge-sensitive mode
                    if (reg_int_polarity[i])
                        gpio_int[i] = (~gpio_in_sync_prev[i] & gpio_in_sync[i]); // Rising edge
                    else
                        gpio_int[i] = (gpio_in_sync_prev[i] & ~gpio_in_sync[i]); // Falling edge
                end
            end else begin
                gpio_int[i] = 1'b0;
            end
        end
    end

    //-------------------------------------------------------------------------
    // Main Sequential Block:
    // Handles APB transactions, register updates, and gpio_in synchronization.
    //-------------------------------------------------------------------------
    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n) begin
            // Asynchronous reset: clear all registers and synchronization flip-flops.
            reg_in          <= 32'd0;
            reg_out         <= 32'd0;
            reg_enable      <= 32'd0;
            reg_int_enable  <= 32'd0;
            reg_int_type    <= 32'd0;
            reg_int_polarity<= 32'd0;
            reg_int_state   <= 32'd0;
            gpio_in_sync    <= {GPIO_WIDTH{1'b0}};
            gpio_in_sync_prev <= {GPIO_WIDTH{1'b0}};
            prdata          <= 32'd0;
        end else begin
            // Two-stage synchronization for gpio_in.
            gpio_in_sync_prev <= gpio_in_sync;
            gpio_in_sync      <= gpio_in;
            // Update the read-only GPIO input register.
            reg_in <= {24'd0, gpio_in_sync};

            // Default prdata assignment to avoid latching an old value.
            prdata <= reg_in;

            // Process APB transactions only when psel and penable are asserted.
            if (psel && penable) begin
                case(paddr[7:2])
                    6'd0: begin
                        // 0x00: GPIO Input Data (read-only)
                        // Writes are ignored.
                        prdata <= reg_in;
                    end
                    6'd4: begin
                        // 0x04: GPIO Output Data
                        if (pwrite) begin
                            reg_out <= {24'd0, pwdata[GPIO_WIDTH-1:0]};
                        end
                        prdata <= reg_out;
                    end
                    6'd8: begin
                        // 0x08: GPIO Output Enable
                        if (pwrite) begin
                            reg_enable <= {24'd0, pwdata[GPIO_WIDTH-1:0]};
                        end
                        prdata <= reg_enable;
                    end
                    6'd12: begin
                        // 0x0C: GPIO Interrupt Enable
                        if (pwrite) begin
                            reg_int_enable <= {24'd0, pwdata[GPIO_WIDTH-1:0]};
                        end
                        prdata <= reg_int_enable;
                    end
                    6'd16: begin
                        // 0x10: GPIO Interrupt Type (0 = level, 1 = edge)
                        if (pwrite) begin
                            reg_int_type <= {24'd0, pwdata[GPIO_WIDTH-1:0]};
                        end
                        prdata <= reg_int_type;
                    end
                    6'd20: begin
                        // 0x14: GPIO Interrupt Polarity (1 = active high, 0 = active low)
                        if (pwrite) begin
                            reg_int_polarity <= {24'd0, pwdata[GPIO_WIDTH-1:0]};
                        end
                        prdata <= reg_int_polarity;
                    end
                    6'd24: begin
                        // 0x18: GPIO Interrupt State (read-only)
                        prdata <= {24'd0, gpio_int};
                    end
                    default: begin
                        // Undefined address: no effect; prdata returns 0.
                        prdata <= 32'd0;
                    end
                endcase
            end
        end
    end

    //-------------------------------------------------------------------------
    // Drive GPIO Output and Direction based on registered values.
    //-------------------------------------------------------------------------
    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n)
            gpio_out <= {GPIO_WIDTH{1'b0}};
        else
            gpio_out <= reg_out[GPIO_WIDTH-1:0];
    end

    always_ff @(posedge pclk or negedge preset_n) begin
        if (!preset_n)
            gpio_enable <= {GPIO_WIDTH{1'b0}};
        else
            gpio_enable <= reg_enable[GPIO_WIDTH-1:0];
    end

endmodule

input.rtl/cvdp_copilot_apb_gpio.sv:
module cvdp_copilot_apb_gpio #(
  parameter GPIO_WIDTH = 8
)(
  // Clock and Reset Signals
  input logic pclk,       // Clock signal
  input logic preset_n,   // Active-low reset signal

  // APB Interface Inputs
  input logic psel,           // Peripheral select
  input logic [7:2] paddr,    // APB address bus (bits [7:2])
  input logic penable,        // Transfer control signal
  input logic pwrite,         // Write control signal
  input logic [31:0] pwdata,  // Write data bus

  // APB Interface Outputs
  output logic [31:0] prdata, // Read data bus
  output logic pready,        // Device ready signal
  output logic pslverr,       // Device error response

  // GPIO Interface Inputs and Outputs
  input logic [GPIO_WIDTH-1:0] gpio_in,     // GPIO input signals
  output logic [GPIO_WIDTH-1:0] gpio_out,   // GPIO output signals
  output logic [GPIO_WIDTH-1:0] gpio_enable, // GPIO output enable signals

  // Interrupt Outputs
  output logic [GPIO_WIDTH-1:0] gpio_int, // Individual interrupt outputs
  output logic comb_int                   // Combined interrupt output
);

  // Signals for Read/Write Controls
  logic read_enable;                     // Read enable signal
  logic write_enable;                    // Write enable signal
  logic write_enable_reg_04;             // Write enable for Data Output register
  logic write_enable_reg_08;             // Write enable for Output Enable register
  logic write_enable_reg_0C;             // Write enable for Interrupt Enable register
  logic write_enable_reg_10;             // Write enable for Interrupt Type register
  logic write_enable_reg_14;             // Write enable for Interrupt Polarity register
  logic write_enable_reg_18;             // Write enable for Interrupt State register
  logic [GPIO_WIDTH-1:0] read_mux;       // Read data multiplexer
  logic [GPIO_WIDTH-1:0] read_mux_d1;    // Registered read data

  // Control Registers
  logic [GPIO_WIDTH-1:0] reg_dout;       // Data Output register
  logic [GPIO_WIDTH-1:0] reg_dout_en;    // Output Enable register
  logic [GPIO_WIDTH-1:0] reg_int_en;     // Interrupt Enable register
  logic [GPIO_WIDTH-1:0] reg_int_type;   // Interrupt Type register
  logic [GPIO_WIDTH-1:0] reg_int_pol;    // Interrupt Polarity register
  logic [GPIO_WIDTH-1:0] reg_int_state;  // Interrupt State register

  // I/O Signal Path and Interrupt Logic
  logic [GPIO_WIDTH-1:0] data_in_sync1;            // First stage of input synchronization
  logic [GPIO_WIDTH-1:0] data_in_sync2;            // Second stage of input synchronization
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted;     // Polarity-adjusted input data
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted_dly; // Delayed version of polarity-adjusted input data
  logic [GPIO_WIDTH-1:0] edge_detect;              // Edge detection signals
  logic [GPIO_WIDTH-1:0] raw_int;                  // Raw interrupt signals
  logic [GPIO_WIDTH-1:0] int_masked;               // Masked interrupt signals
  logic [GPIO_WIDTH-1:0] clear_interrupt;          // Clear interrupt signals

  // Read and Write Control Signals
  assign read_enable = psel & (~pwrite); // Read enable
  assign write_enable = psel & (~penable) & pwrite; // Write enable

  // Write Enable Signals for Specific Registers
  assign write_enable_reg_04 = write_enable & (paddr[7:2] == 6'd1); // Address 0x04
  assign write_enable_reg_08 = write_enable & (paddr[7:2] == 6'd2); // Address 0x08
  assign write_enable_reg_0C = write_enable & (paddr[7:2] == 6'd3); // Address 0x0C
  assign write_enable_reg_10 = write_enable & (paddr[7:2] == 6'd4); // Address 0x10
  assign write_enable_reg_14 = write_enable & (paddr[7:2] == 6'd5); // Address 0x14
  assign write_enable_reg_18 = write_enable & (paddr[7:2] == 6'd6); // Address 0x18

  // Write Operations for Control Registers

  // Data Output Register (reg_dout)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_04)
      reg_dout <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Output Enable Register (reg_dout_en)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout_en <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_08)
      reg_dout_en <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Enable Register (reg_int_en)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_en <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_0C)
      reg_int_en <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Type Register (reg_int_type)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_type <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_10)
      reg_int_type <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Polarity Register (reg_int_pol)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_pol <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_14)
      reg_int_pol <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Read Operation: Multiplexing Register Data Based on Address
  always_comb begin
    case (paddr[7:2])
      6'd0: read_mux = data_in_sync2;   // Input Data Register at address 0x00
      6'd1: read_mux = reg_dout;        // Data Output Register at address 0x04
      6'd2: read_mux = reg_dout_en;     // Output Enable Register at address 0x08
      6'd3: read_mux = reg_int_en;      // Interrupt Enable Register at address 0x0C
      6'd4: read_mux = reg_int_type;    // Interrupt Type Register at address 0x10
      6'd5: read_mux = reg_int_pol;     // Interrupt Polarity Register at address 0x14
      6'd6: read_mux = reg_int_state;   // Interrupt State Register at address 0x18
      default: read_mux = {GPIO_WIDTH{1'b0}}; // Default to zeros if address is invalid
    endcase
  end

  // Registering Read Data for Timing Alignment
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      read_mux_d1 <= {GPIO_WIDTH{1'b0}};
    else
      read_mux_d1 <= read_mux;
  end

  // Output Read Data to APB Interface
  assign prdata = (read_enable) ? {{(32-GPIO_WIDTH){1'b0}}, read_mux_d1} : {32{1'b0}};
  assign pready = 1'b1; // Always ready
  assign pslverr = 1'b0; // No error

  // Driving GPIO Outputs and Output Enables
  assign gpio_enable = reg_dout_en; // Output enable signals
  assign gpio_out = reg_dout;       // Output data signals

  // Input Synchronization to Avoid Metastability
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_sync1 <= {GPIO_WIDTH{1'b0}};
      data_in_sync2 <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_sync1 <= gpio_in;
      data_in_sync2 <= data_in_sync1;
    end
  end

  // Interrupt Logic

  // Adjusting Input Data Based on Interrupt Polarity
  assign data_in_pol_adjusted = data_in_sync2 ^ reg_int_pol; // Polarity adjustment

  // Registering Polarity-Adjusted Input Data and Delaying for Edge Detection
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_pol_adjusted_dly <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_pol_adjusted_dly <= data_in_pol_adjusted;
    end
  end

  // Edge Detection Logic for Interrupts
  assign edge_detect = data_in_pol_adjusted & (~data_in_pol_adjusted_dly); // Rising edge detection

  // Selecting Interrupt Type (Edge or Level-Triggered)
  assign raw_int = (reg_int_type & edge_detect) | (~reg_int_type & data_in_pol_adjusted); // Interrupt source

  // Applying Interrupt Enable Mask
  assign int_masked = raw_int & reg_int_en; // Masked interrupts

  // Clear Interrupt Signals
  assign clear_interrupt = pwdata[GPIO_WIDTH-1:0] & {GPIO_WIDTH{write_enable_reg_18}};

  // Updating Interrupt State Register (Corrected Logic)
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      reg_int_state <= {GPIO_WIDTH{1'b0}};
    end else begin
      integer i;
      for (i = 0; i < GPIO_WIDTH; i = i + 1) begin
        if (reg_int_type[i]) begin
          // Edge-triggered interrupt
          if (clear_interrupt[i]) begin
            reg_int_state[i] <= 1'b0;
          end else if (int_masked[i]) begin
            reg_int_state[i] <= 1'b1;
          end
        end else begin
          // Level-triggered interrupt
          reg_int_state[i] <= int_masked[i];
        end
      end
    end
  end

  // Connecting Interrupt Outputs
  assign gpio_int = reg_int_state;     // Individual interrupt outputs
  assign comb_int = |reg_int_state;    // Combined interrupt output

endmodule

output.rtl/cvdp_copilot_apb_gpio.sv:
module cvdp_copilot_apb_gpio #(
  parameter GPIO_WIDTH = 8
)(
  // Clock and Reset Signals
  input logic pclk,       // Clock signal
  input logic preset_n,   // Active-low reset signal

  // APB Interface Inputs
  input logic psel,           // Peripheral select
  input logic [7:2] paddr,    // APB address bus (bits [7:2])
  input logic penable,        // Transfer control signal
  input logic pwrite,         // Write control signal
  input logic [31:0] pwdata,  // Write data bus

  // APB Interface Outputs
  output logic [31:0] prdata, // Read data bus
  output logic pready,        // Device ready signal
  output logic pslverr,       // Device error response

  // GPIO Interface Inputs and Outputs (Bidirectional)
  inout logic [GPIO_WIDTH-1:0] gpio,    // Bidirectional GPIO pins

  // Interrupt Outputs
  output logic [GPIO_WIDTH-1:0] gpio_int, // Individual interrupt outputs
  output logic comb_int                   // Combined interrupt output
);

  // Internal signals for Read/Write Controls
  logic read_enable;                     
  logic write_enable;                    
  logic write_enable_reg_04;             
  logic write_enable_reg_08;             
  logic write_enable_reg_0C;             
  logic write_enable_reg_10;             
  logic write_enable_reg_14;             
  logic write_enable_reg_18;             
  logic write_enable_reg_1C;             // New: Direction Control Register (0x1C)
  logic write_enable_reg_20;             // New: Power Management Register (0x20)
  logic write_enable_reg_24;             // New: Interrupt Reset Register (0x24)
  logic [GPIO_WIDTH-1:0] read_mux;       
  logic [GPIO_WIDTH-1:0] read_mux_d1;    

  // Control Registers
  logic [GPIO_WIDTH-1:0] reg_dout;       // Data Output register
  logic [GPIO_WIDTH-1:0] reg_dout_en;    // Output Enable register
  logic [GPIO_WIDTH-1:0] reg_int_en;     // Interrupt Enable register
  logic [GPIO_WIDTH-1:0] reg_int_type;   // Interrupt Type register
  logic [GPIO_WIDTH-1:0] reg_int_pol;    // Interrupt Polarity register
  logic [GPIO_WIDTH-1:0] reg_int_state;  // Interrupt State register

  // New Registers
  logic [GPIO_WIDTH-1:0] reg_dir;        // Direction Control Register (0x1C)
  logic [31:0] reg_pm;                   // Power Management Register (0x20)
  logic [GPIO_WIDTH-1:0] reg_int_reset;  // Interrupt Reset Register (0x24)

  // I/O Signal Path and Interrupt Logic
  logic [GPIO_WIDTH-1:0] data_in_sync1;            
  logic [GPIO_WIDTH-1:0] data_in_sync2;            
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted;     
  logic [GPIO_WIDTH-1:0] data_in_pol_adjusted_dly; 
  logic [GPIO_WIDTH-1:0] edge_detect;              
  logic [GPIO_WIDTH-1:0] raw_int;                  
  logic [GPIO_WIDTH-1:0] int_masked;               
  logic [GPIO_WIDTH-1:0] clear_interrupt;          
  logic [GPIO_WIDTH-1:0] clear_interrupt_reg;      // (From previous write to 0x18)

  // Read and Write Control Signals
  assign read_enable = psel & (~pwrite); // Read enable
  assign write_enable = psel & (~penable) & pwrite; // Write enable

  // Write Enable Signals for Specific Registers
  assign write_enable_reg_04 = write_enable & (paddr[7:2] == 6'd1); // Address 0x04
  assign write_enable_reg_08 = write_enable & (paddr[7:2] == 6'd2); // Address 0x08
  assign write_enable_reg_0C = write_enable & (paddr[7:2] == 6'd3); // Address 0x0C
  assign write_enable_reg_10 = write_enable & (paddr[7:2] == 6'd4); // Address 0x10
  assign write_enable_reg_14 = write_enable & (paddr[7:2] == 6'd5); // Address 0x14
  assign write_enable_reg_18 = write_enable & (paddr[7:2] == 6'd6); // Address 0x18

  // New Write Enable Signals for Added Registers
  assign write_enable_reg_1C = write_enable & (paddr[7:2] == 6'd7); // Address 0x1C: Direction Control
  assign write_enable_reg_20 = write_enable & (paddr[7:2] == 6'd8); // Address 0x20: Power Management
  assign write_enable_reg_24 = write_enable & (paddr[7:2] == 6'd9); // Address 0x24: Interrupt Reset

  // Write Operations for Control Registers

  // Data Output Register (reg_dout) at 0x04
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_04)
      reg_dout <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Output Enable Register (reg_dout_en) at 0x08
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dout_en <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_08)
      reg_dout_en <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Enable Register (reg_int_en) at 0x0C
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_en <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_0C)
      reg_int_en <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Type Register (reg_int_type) at 0x10
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_type <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_10)
      reg_int_type <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt Polarity Register (reg_int_pol) at 0x14
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_pol <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_14)
      reg_int_pol <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Interrupt State Register (reg_int_state) at 0x18
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      reg_int_state <= {GPIO_WIDTH{1'b0}};
    end else begin
      integer i;
      for (i = 0; i < GPIO_WIDTH; i = i + 1) begin
        // Software-controlled reset has highest priority
        if (reg_int_reset[i])
          reg_int_state[i] <= 1'b0;
        else if (reg_int_type[i]) begin
          // Edge-triggered interrupt
          if (clear_interrupt[i])
            reg_int_state[i] <= 1'b0;
          else if (int_masked[i])
            reg_int_state[i] <= 1'b1;
        end else begin
          // Level-triggered interrupt
          reg_int_state[i] <= int_masked[i];
        end
      end
    end
  end

  // New Register: Direction Control Register (reg_dir) at 0x1C
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_dir <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_1C)
      reg_dir <= pwdata[(GPIO_WIDTH-1):0];
  end

  // New Register: Power Management Register (reg_pm) at 0x20
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_pm <= {1'b0, 31'b0};
    else if (write_enable_reg_20)
      // Only bit[0] is used; ignore bits[31:1]
      reg_pm <= {31'b0, pwdata[0]};
  end

  // New Register: Interrupt Reset Register (reg_int_reset) at 0x24
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      reg_int_reset <= {GPIO_WIDTH{1'b0}};
    else if (write_enable_reg_24)
      reg_int_reset <= pwdata[(GPIO_WIDTH-1):0];
  end

  // Read Operation: Multiplexing Register Data Based on Address
  always_comb begin
    case (paddr[7:2])
      6'd0: read_mux = data_in_sync2;   // Input Data Register at address 0x00
      6'd1: read_mux = reg_dout;        // Data Output Register at address 0x04
      6'd2: read_mux = reg_dout_en;     // Output Enable Register at address 0x08
      6'd3: read_mux = reg_int_en;      // Interrupt Enable Register at address 0x0C
      6'd4: read_mux = reg_int_type;    // Interrupt Type Register at address 0x10
      6'd5: read_mux = reg_int_pol;     // Interrupt Polarity Register at address 0x14
      6'd6: read_mux = reg_int_state;   // Interrupt State Register at address 0x18
      6'd7: read_mux = reg_dir;         // Direction Control Register at address 0x1C
      6'd8: read_mux = reg_pm;          // Power Management Register at address 0x20
      6'd9: read_mux = reg_int_reset;   // Interrupt Reset Register at address 0x24
      default: read_mux = {GPIO_WIDTH{1'b0}}; // Default to zeros if address is invalid
    endcase
  end

  // Registering Read Data for Timing Alignment
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n)
      read_mux_d1 <= {GPIO_WIDTH{1'b0}};
    else
      read_mux_d1 <= read_mux;
  end

  // Output Read Data to APB Interface
  assign prdata = (read_enable) ? {{(32-GPIO_WIDTH){1'b0}}, read_mux_d1} : {32{1'b0}};
  assign pready = 1'b1; // Always ready
  assign pslverr = 1'b0; // No error

  // Driving GPIO Outputs and Output Enables
  assign gpio_enable = reg_dout_en; // Output enable signals

  // Bidirectional GPIO Output with Direction and Power Management
  // When a pin is configured as output (reg_dir[i] == 1) and global power is enabled (reg_pm[0] == 0),
  // the output is driven by reg_dout. Otherwise, the pin is left in high impedance.
  genvar i;
  generate
    for (i = 0; i < GPIO_WIDTH; i = i + 1) begin : gpio_out_gen
      assign gpio[i] = (reg_pm[0] ? 1'bz : ((reg_dir[i] == 1) ? reg_dout[i] : 1'bz));
    end
  endgenerate

  // Input Synchronization to Avoid Metastability
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_sync1 <= {GPIO_WIDTH{1'b0}};
      data_in_sync2 <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_sync1 <= gpio;  // Note: using bidirectional gpio_in now comes from 'gpio'
      data_in_sync2 <= data_in_sync1;
    end
  end

  // Interrupt Logic

  // Adjusting Input Data Based on Interrupt Polarity
  assign data_in_pol_adjusted = data_in_sync2 ^ reg_int_pol; // Polarity adjustment

  // Registering Polarity-Adjusted Input Data and Delaying for Edge Detection
  always_ff @(posedge pclk or negedge preset_n) begin
    if (~preset_n) begin
      data_in_pol_adjusted_dly <= {GPIO_WIDTH{1'b0}};
    end else begin
      data_in_pol_adjusted_dly <= data_in_pol_adjusted;
    end
  end

  // Edge Detection Logic for Interrupts
  assign edge_detect = data_in_pol_adjusted & (~data_in_pol_adjusted_dly); // Rising edge detection

  // Selecting Interrupt Type (Edge or Level-Triggered)
  assign raw_int = (reg_int_type & edge_detect) | (~reg_int_type & data_in_pol_adjusted); // Interrupt source

  // Applying Interrupt Enable Mask
  assign int_masked = raw_int & reg_int_en; // Masked interrupts

  // Clear Interrupt Signals (from previous write to 0x18)
  assign clear_interrupt = pwdata[GPIO_WIDTH-1:0] & {GPIO_WIDTH{write_enable_reg_18}};

  // Connecting Interrupt Outputs
  assign gpio_int = reg_int_state;     // Individual interrupt outputs
  assign comb_int = |reg_int_state;    // Combined interrupt output

endmodule

