    // AXI Interface
    input  wire        axi_awvalid_i,
    input  wire        axi_wvalid_i,
    input  wire        axi_bready_i,
    input  wire        axi_arvalid_i,
    input  wire        axi_rready_i,

    output wire        axi_awready_o,
    output wire        axi_wready_o,
    output wire        axi_bvalid_o,
    output wire        axi_arready_o,
    output wire        axi_rvalid_o,

    input  wire [31:0] axi_awaddr_i,
    input  wire [31:0] axi_wdata_i,
    input  wire [31:0] axi_araddr_i,

    input  wire [3:0]  axi_wstrb_i,
    output wire [31:0] axi_rdata_o,
    output wire [63:0] result_o
);

    wire        clk;
    wire [31:0] operand_a, operand_b, operand_c;
    wire [1:0]  op_select;
    wire        start, clock_control;
    wire [31:0] data_a;
    wire [31:0] data_b;
    wire [31:0] data_c;

    wire [31:0] operand_a_cdc, operand_b_cdc, operand_c_cdc;
    wire [1:0]  op_select_cdc;
    wire        start_cdc;
    wire [31:0] operand_a_sync, operand_b_sync, operand_c_sync;
    wire [1:0]  op_select_sync;
    wire        start_sync;

    clock_control u_clock_control (
        .axi_clk_in  (axi_clk_in),
        .fast_clk_in (fast_clk_in),
        .clk_ctrl    (clock_control),
        .clk         (clk)
    );

    axi_csr_block u_axi_csr_block (
        .axi_aclk_i    (axi_clk_in),
        .axi_areset_i  (reset_in),
        .axi_awvalid_i   (axi_awvalid_i),
        .axi_awready_o   (axi_awready_o),
        .axi_awaddr_i    (axi_awaddr_i),
        .axi_wvalid_i    (axi_wvalid_i),
        .axi_wready_o    (axi_wready_o),
        .axi_wdata_i     (axi_wdata_i),
        .axi_wstrb_i     (axi_wstrb_i),
        .axi_bvalid_o    (axi_bvalid_o),
        .axi_bready_i    (axi_bready_i),
        .axi_arvalid_i   (axi_arvalid_i),
        .axi_arready_o   (axi_arready_o),
        .axi_araddr_i    (axi_araddr_i),
        .axi_rvalid_o    (axi_rvalid_o),
        .axi_rready_i    (axi_rready_i),
        .axi_rdata_o     (axi_rdata_o),
        .operand_a     (operand_a_cdc),
        .operand_b     (operand_b_cdc),
        .operand_c     (operand_c_cdc),
        .op_select     (op_select_cdc),
        .start         (start_cdc),
        .clock_control (clock_control)
    );

    // CDC logic is only active when clock_control is HIGH
    assign operand_a = (clock_control) ? operand_a_sync : operand_a_cdc;
    assign operand_b = (clock_control) ? operand_b_sync : operand_b_cdc;
    assign operand_c = (clock_control) ? operand_c_sync : operand_c_cdc;
    assign op_select = (clock_control) ? op_select_sync : op_select_cdc;
    assign start     = (clock_control) ? start_sync : start_cdc;

    // CDC Synchronizers (only used when fast_clk is selected)
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_a (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_a_cdc), .data_out(operand_a_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_b (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_b_cdc), .data_out(operand_b_sync));
    cdc_synchronizer #(.WIDTH(32)) u_cdc_operand_c (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(operand_c_cdc), .data_out(operand_c_sync));
    cdc_synchronizer #(.WIDTH(2))  u_cdc_op_select  (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(op_select_cdc), .data_out(op_select_sync));
    cdc_synchronizer #(.WIDTH(1))  u_cdc_start      (.clk_src(axi_clk_in), .clk_dst(clk), .reset_in(reset_in), .data_in(start_cdc), .data_out(start_sync));

    memory_block u_memory_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .address_a  (operand_a[5:0]),
        .address_b  (operand_b[5:0]),
        .address_c  (operand_c[5:0]),
        .data_a     (data_a),
        .data_b     (data_b),
        .data_c     (data_c)
    );

    dsp_block u_dsp_block (
        .clk        (clk),
        .reset_in   (reset_in),
        .operand_a  (data_a),
        .operand_b  (data_b),
        .operand_c  (data_c),
        .op_select  (op_select),
        .start      (start),
        .result     (result_o)
    );

endmodule

// ------------------------------------------------------------------
// CDC Synchronizer Module (Double Flop Synchronization)
// ------------------------------------------------------------------
module cdc_synchronizer #(parameter WIDTH = 1) (
    input wire clk_src,  // Source clock
    input wire clk_dst,  // Destination clock
    input wire reset_in, // Reset signal
    input wire [WIDTH-1:0] data_in,  // Data from source domain
    output reg [WIDTH-1:0] data_out  // Synchronized data in destination domain
);
    reg [WIDTH-1:0] data_sync_1, data_sync_2;

    always @(posedge clk_dst or posedge reset_in) begin
        if (reset_in) begin
            data_sync_1 <= {WIDTH{1'b0}};
            data_sync_2 <= {WIDTH{1'b0}};
            data_out    <= {WIDTH{1'b0}};
        end else begin
            data_sync_1 <= data_in;   // First stage
            data_sync_2 <= data_sync_1; // Second stage
            data_out    <= data_sync_2; // Stable output
        end
    end
endmodule

// ------------------------------------------------------------------
// Clock Control Module
// ------------------------------------------------------------------
module clock_control (
    input  wire axi_clk_in,
    input  wire fast_clk_in,
    input  wire clk_ctrl,
    output wire clk
);
    assign clk = clk_ctrl ? fast_clk_in : axi_clk_in;
endmodule

// ------------------------------------------------------------------
// AXI-to-CSR Register Block (With Write Response Handling)
// ------------------------------------------------------------------
module axi_csr_block (
    input  wire        axi_aclk_i,
    input  wire        axi_areset_i,

    // AXI Write Address Channel
    input  wire        axi_awvalid_i,
    output reg         axi_awready_o,
    input  wire [31:0] axi_awaddr_i,

    // AXI Write Data Channel
    input  wire        axi_wvalid_i,
    output reg         axi_wready_o,
    input  wire [31:0] axi_wdata_i,
    input  wire [3:0]  axi_wstrb_i,

    // AXI Write Response Channel (FIXED)
    output reg         axi_bvalid_o,
    input  wire        axi_bready_i,

    // AXI Read Address Channel
    input  wire        axi_arvalid_i,
    output reg         axi_arready_o,
    input  wire [31:0] axi_araddr_i,

    // AXI Read Data Channel
    output reg         axi_rvalid_o,
    input  wire        axi_rready_i,
    output reg  [31:0] axi_rdata_o,

    // CSR Outputs
    output reg  [31:0] operand_a,
    output reg  [31:0] operand_b,
    output reg  [31:0] operand_c,
    output reg  [1:0]  op_select,
    output reg         start,
    output reg         clock_control
);
    reg [31:0] csr_reg [0:4];

    always @(posedge axi_aclk_i or posedge axi_areset_i) begin
        if (axi_areset_i) begin
            operand_a     <= 32'd0;
            operand_b     <= 32'd0;
            operand_c     <= 32'd0;
            op_select     <= 2'd0;
            start         <= 1'b0;
            clock_control <= 1'b0;
            axi_awready_o <= 0;
            axi_wready_o  <= 0;
            axi_bvalid_o  <= 0; // Set response valid
            axi_arready_o <= 0;
            axi_rvalid_o  <= 0;
            axi_rdata_o   <= 32'd0;
            csr_reg[0]    <= 32'd0;
            csr_reg[1]    <= 32'd0;
            csr_reg[2]    <= 32'd0;
            csr_reg[3]    <= 32'd0;
            csr_reg[4]    <= 32'd0;
        end else begin
            // Handle AXI Write
            if (axi_awvalid_i && axi_wvalid_i) begin
                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axis_resize.sv:
module axis_resize (
  input  wire           clk,
  input  wire           resetn,
  input  wire           s_valid,
  output reg            s_ready,
  input  wire [15:0]    s_data,
  output reg            m_valid,
  input  wire           m_ready,
  output reg [7:0]      m_data
);

  // Define a two-bit state type
  typedef enum logic [1:0] {
    IDLE      = 2'b00,
    SEND_UPPER = 2'b01,
    SEND_LOWER = 2'b10
  } state_t;

  state_t state, next_state;
  reg [15:0] data_reg;

  // Next state combinational logic
  always_comb begin
    case (state)
      IDLE: begin
        if (s_valid)
          next_state = SEND_UPPER;
        else
          next_state = IDLE;
      end
      SEND_UPPER: begin
        if (m_ready)
          next_state = SEND_LOWER;
        else
          next_state = SEND_UPPER;
      end
      SEND_LOWER: begin
        if (m_ready)
          next_state = IDLE;
        else
          next_state = SEND_LOWER;
      end
      default: next_state = IDLE;
    endcase
  end

  // Sequential logic: state register and output updates
  always_ff @(posedge clk or negedge resetn) begin
    if (!resetn) begin
      state      <= IDLE;
      s_ready    <= 1'b0;
      m_valid    <= 1'b0;
      m_data     <= 8'd0;
      data_reg   <= 16'd0;
    end else begin
      state <= next_state;
      case (state)
        IDLE: begin
          if (s_valid) begin
            // Capture the 16-bit data and output the upper 8 bits
            data_reg  <= s_data;
            s_ready   <= 1'b0;  // Not ready for a new slave transaction
            m_valid   <= 1'b1;
            m_data    <= data_reg[15:8];
          end else begin
            s_ready   <= 1'b1;  // Ready to accept a new transaction
            m_valid   <= 1'b0;
          end
        end
        SEND_UPPER: begin
          // Hold m_valid high until the master accepts the high-part transaction
          m_valid   <= 1'b1;
          // m_data remains the high 8 bits (data_reg[15:8]) from the previous cycle
        end
        SEND_LOWER: begin
          // Drive the lower 8 bits and wait for m_ready to accept the transaction
          m_valid   <= 1'b1;
          if (m_ready) begin
            s_ready  <= 1'b1;  // Transaction complete; ready for a new slave transfer
            m_valid  <= 1'b0;
          end
          m_data    <= data_reg[7:0];
        end
      endcase
    end
  end

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale (
    input  logic         clk,
    input  logic         resetn,
    input  logic         dfmt_enable,
    input  logic         dfmt_type,
    input  logic         dfmt_se,
    input  logic         s_axis_valid,
    input  logic [23:0]  s_axis_data,
    input  logic         m_axis_ready,
    output logic         s_axis_ready,
    output logic         m_axis_valid,
    output logic [31:0]  m_axis_data
);

    // Internal registers for a single pipeline stage
    reg [23:0] data_reg;
    reg        valid_reg;

    // Pipeline register: capture input data when valid and master is ready.
    // When reset is de-asserted, all registers are cleared.
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            data_reg  <= 24'd0;
            valid_reg <= 1'b0;
        end else begin
            if (valid_reg && m_axis_ready) begin
                valid_reg <= s_axis_valid;
                data_reg  <= s_axis_data;
            end
        end
    end

    // Handshake signals: slave ready is driven by master ready.
    assign s_axis_ready = m_axis_ready;
    assign m_axis_valid = valid_reg;

    // Compute the 8-bit extension based on data format signals.
    // If dfmt_enable is false, the extension is all zeros.
    // If dfmt_enable is true and dfmt_se is true, then the extension bits
    // are all set to either the MSB of s_axis_data (if dfmt_type is 0)
    // or its inverted value (if dfmt_type is 1).
    logic [7:0] ext;
    always_comb begin
        if (!dfmt_enable) begin
            ext = 8'd0;
        end else begin
            if (dfmt_se) begin
                ext = (dfmt_type) ? {8{~data_reg[23]}} : {8{data_reg[23]}};
            end else begin
                ext = 8'd0;
            end
        end
    end

    // Construct m_axis_data by concatenating the extension bits with the 24-bit input data.
    assign m_axis_data = {ext, data_reg};

endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI Read Channel Logic
//-----------------------------------------------------------------
// Internal registers for tracking read transactions
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

// Determine read port based on address (default: 0, peripheral: 1)
always @ *
begin
    if (inport_araddr_i >= PERIPH0_ADDR)
        read_port_r = 1;
    else
        read_port_r = 0;
end

// Update read pending counter on address acceptance and response handshakes
always @ (posedge clk_i)
if (rst_i)
    read_pending_r <= 4'b0;
else begin
    if (inport_arvalid_i && inport_arready_o)
        read_pending_r <= read_pending_r + 1;
    if (outport_rvalid_i && inport_rready_i)
        read_pending_r <= read_pending_r - 1;
end

// Track the last accepted read port and pending count
always @ (posedge clk_i)
if (rst_i)
begin
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    read_pending_q <= read_pending_r;
    if (inport_arvalid_i && inport_arready_o)
        read_port_q <= read_port_r;
end

// Accept read transactions if the pending counter is not full and the port matches
wire read_accept_w = (read_port_q == read_port_r && read_pending_q != 4'hF) ||
                      (read_pending_q == 4'h0);

// AXI Read Address Channel: route to default or peripheral based on address
assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_arready_o = 1'b1; // Always ready for address

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_arready_o = 1'b1; // Always ready for address

// AXI Read Data Channel: multiplex responses from the selected interface
reg inport_rvalid_reg;
reg [DATA_WIDTH-1:0] inport_rdata_reg;
reg [1:0] inport_rresp_reg;

always @ *
begin
    case (read_port_r)
        `ADDR_SEL_W'd0: begin
            inport_rvalid_reg = outport_rvalid_i;
            inport_rdata_reg  = outport_rdata_i;
            inport_rresp_reg  = outport_rresp_i;
        end
        `ADDR_SEL_W'd1: begin
            inport_rvalid_reg = outport_peripheral0_rvalid_i;
            inport_rdata_reg  = outport_peripheral0_rdata_i;
            inport_rresp_reg  = outport_peripheral0_rresp_i;
        end
        default: begin
            inport_rvalid_reg = 1'b0;
            inport_rdata_reg  = {DATA_WIDTH{1'b0}};
            inport_rresp_reg  = 2'b0;
        end
    endcase
end

assign inport_rvalid_o = inport_rvalid_reg;
assign inport_rdata_o  = inport_rdata_reg;
assign inport_rresp_o  = inport_rresp_reg;

assign outport_rready_o = inport_rready_i;
assign outport_peripheral0_rready_o = inport_rready_i;

//-----------------------------------------------------------------
// AXI Write Channel Logic
//-----------------------------------------------------------------
// Internal registers for tracking write transactions
reg awvalid_q;
reg wvalid_q;

// Write port and pending registers for write transactions
reg [`ADDR_SEL_W-1:0] write_port_q;
reg [`ADDR_SEL_W-1:0] write_port_r;
reg [3:0] write_pending_q;
reg [3:0] write_pending_r;

// Determine write port based on address (default: 0, peripheral: 1)
always @ *
begin
    if (inport_awaddr_i >= PERIPH0_ADDR)
        write_port_r = 1;
    else
        write_port_r = 0;
end

// Update write pending counter on address acceptance and response handshakes
always @ (posedge clk_i)
if (rst_i)
    write_pending_r <= 4'b0;
else begin
    if (inport_awvalid_i && inport_awready_o)
        write_pending_r <= write_pending_r + 1;
    if (outport_bvalid_i && inport_bready_i)
        write_pending_r <= write_pending_r - 1;
end

// Track the last accepted write port and pending count
always @ (posedge clk_i)
if (rst_i)
begin
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    write_pending_q <= write_pending_r;
    if (inport_awvalid_i && inport_awready_o)
        write_port_q <= write_port_r;
end

// Accept write transactions if the pending counter is not full and the port matches
wire write_accept_w = (write_port_q == write_port_r && write_pending_q != 4'hF) ||
                       (write_pending_q == 4'h0);

// AXI Write Address Channel: route to default or peripheral based on address
assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_awready_o = 1'b1; // Always ready for address

assign outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_awaddr_o  = inport_awaddr_i;
assign outport_peripheral0_awready_o = 1'b1; // Always ready for address

// AXI Write Data Channel: route data to the appropriate interface
assign outport_wvalid_o = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
assign outport_wdata_o  = inport_wdata_i;
assign outport_wstrb_o  = inport_wstrb_i;
assign outport_wready_o = 1'b1; // Always ready for data

assign outport_peripheral0_wvalid_o = inport_wvalid_i & ~wvalid_q & ((inport_awvalid_i && write_accept_w) || awvalid_q) & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_wdata_o  = inport_wdata_i;
assign outport_peripheral0_wstrb_o  = inport_wstrb_i;
assign outport_peripheral0_wready_o = 1'b1; // Always ready for data

// AXI Write Response Channel: multiplex responses from the selected interface
reg outport_bvalid_r;
reg [1:0] outport_bresp_r;

always @ *
begin
    case (write_port_q)
        `ADDR_SEL_W'd1: begin
            outport_bvalid_r = outport_peripheral0_bvalid_i;
            outport_bresp_r  = outport_peripheral0_bresp_i;
        end
        default: begin
            outport_bvalid_r = outport_bvalid_i;
            outport_bresp_r  = outport_bresp_i;
        end
    endcase
end

assign inport_bvalid_o = outport_bvalid_r;
assign inport_bresp_o  = outport_bresp_r;
assign outport_bready_o = inport_bready_i;

// Backpressure: select ready signals from the appropriate interface
reg inport_awready_r;
reg inport_wready_r;

always @ *
begin
    case (write_port_r)
        `ADDR_SEL_W'd1: begin
            inport_awready_r = outport_peripheral0_awready_i;
            inport_wready_r  = outport_peripheral0_wready_i;
        end
        default: begin
            inport_awready_r = outport_awready_i;
            inport_wready_r  = outport_wready_i;
        end        
    endcase
end

assign inport_awready_o = write_accept_w & ~awvalid_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;

// AXI Write handshake tracking: manage out-of-order AW and W signals
wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || awvalid_q;
wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

always @ (posedge clk_i )
if (rst_i)
    awvalid_q <= 1'b0;
else if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
    awvalid_q <= 1'b1;
else if (wr_data_accepted_w)
    awvalid_q <= 1'b0;

always @ (posedge clk_i )
if (rst_i)
    wvalid_q <= 1'b0;
else if (inport_wvalid_i && inport_wready_o && !wr_cmd_accepted_w)
    wvalid_q <= 1'b1;
else if (wr_cmd_accepted_w)
    wvalid_q <= 1'b0;

endmodule

