reg [3:0]              write_pending_q;
reg [3:0]              write_pending_r;
reg [`ADDR_SEL_W-1:0]  write_port_q;
reg [`ADDR_SEL_W-1:0]  write_port_r;

always @ *
begin    
    if (inport_awvalid_i & ~awvalid_q)
    begin
        write_port_r = `ADDR_SEL_W'b0;
        if ((inport_awaddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR)
            write_port_r = `ADDR_SEL_W'd1;
    end
    else
        write_port_r = write_port_q;
end

wire write_incr_w = (inport_awvalid_i && inport_awready_o);
wire write_decr_w = (inport_bvalid_o  && inport_bready_i);

always @ *
begin
    write_pending_r = write_pending_q;

    if (write_incr_w && !write_decr_w)
        write_pending_r = write_pending_r + 4'd1;
    else if (!write_incr_w && write_decr_w)
        write_pending_r = write_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    write_pending_q <= write_pending_r;

    // Write command accepted
    if (inport_awvalid_i && inport_awready_o)
    begin
        write_port_q <= write_port_r;
    end
end

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
assign outport_wdata_o   = inport_wdata_i;
assign outport_wstrb_o   = inport_wstrb_i;
assign outport_bready_o  = inport_bready_i;

assign outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_awaddr_o  = inport_awaddr_i;
assign outport_peripheral0_wvalid_o  = inport_wvalid_i & ~wvalid_q & ((inport_awvalid_i && write_accept_w) || awvalid_q) & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_wdata_o   = inport_wdata_i;
assign outport_peripheral0_wstrb_o   = inport_wstrb_i;
assign outport_peripheral0_bready_o  = inport_bready_i;

reg        outport_bvalid_r;
reg [1:0]  outport_bresp_r;

always @ *
begin
    case (write_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_bvalid_r = outport_peripheral0_bvalid_i;
        outport_bresp_r  = outport_peripheral0_bresp_i;
    end
    default:
    begin
        outport_bvalid_r = outport_bvalid_i;
        outport_bresp_r  = outport_bresp_i;
    end
    endcase
end

assign inport_bvalid_o  = outport_bvalid_r;
assign inport_bresp_o   = outport_bresp_r;

reg inport_awready_r;
reg inport_wready_r;

always @ *
begin
    case (write_port_r)
    `ADDR_SEL_W'd1:
    begin
        inport_awready_r = outport_peripheral0_awready_i;
        inport_wready_r  = outport_peripheral0_wready_i;
    end
    default:
    begin
        inport_awready_r = outport_awready_i;
        inport_wready_r  = outport_wready_i;
    end        
    endcase
end

assign inport_awready_o = write_accept_w & ~awvalid_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;

//-----------------------------------------------------------------
// Timeout Detection Logic
//-----------------------------------------------------------------
// Registers for tracking active transactions and their timeout counters

// For Read Transactions
reg        read_active;
reg [31:0] read_timeout_counter;

// For Write Transactions
reg        write_active;
reg [31:0] write_timeout_counter;

// Read Transaction Timeout Detection
always @(posedge clk_i) begin
    if (rst_i) begin
        read_active         <= 1'b0;
        read_timeout_counter <= 32'd0;
    end else begin
        // If a new read transaction is started, latch active and reset counter.
        if (!read_active && inport_arvalid_i && inport_arready_o) begin
            read_active         <= 1'b1;
            read_timeout_counter <= 32'd0;
        end
        else if (read_active) begin
            // If read response handshake occurs, transaction complete: clear active and counter.
            if (read_decr_w) begin
                read_active         <= 1'b0;
                read_timeout_counter <= 32'd0;
            end
            // Increment timeout counter
            else if (read_timeout_counter < timeout_threshold_i - 1) begin
                read_timeout_counter <= read_timeout_counter + 1;
            end
            // Timeout reached: assert timeout flag, abort transaction.
            else begin
                timeout_flag_o <= 1'b1;
                read_active    <= 1'b0;
                read_timeout_counter <= 32'd0;
            end
        end
        // Optionally, if a new transaction starts while a timeout is flagged, clear the flag.
        if (inport_arvalid_i && inport_arready_o && timeout_flag_o)
            timeout_flag_o <= 1'b0;
    end
end

// Write Transaction Timeout Detection
always @(posedge clk_i) begin
    if (rst_i) begin
        write_active         <= 1'b0;
        write_timeout_counter <= 32'd0;
    end else begin
        // If a new write transaction is started, latch active and reset counter.
        if (!write_active && inport_awvalid_i && inport_awready_o) begin
            write_active         <= 1'b1;
            write_timeout_counter <= 32'd0;
        end
        else if (write_active) begin
            // If write response handshake occurs, transaction complete: clear active and counter.
            if (write_decr_w) begin
                write_active         <= 1'b0;
                write_timeout_counter <= 32'd0;
            end
            // Increment timeout counter
            else if (write_timeout_counter < timeout_threshold_i - 1) begin
                write_timeout_counter <= write_timeout_counter + 1;
            end
            // Timeout reached: assert timeout flag, abort transaction.
            else begin
                timeout_flag_o <= 1'b1;
                write_active    <= 1'b0;
                write_timeout_counter <= 32'd0;
            end
        end
        // Optionally, if a new transaction starts while a timeout is flagged, clear the flag.
        if (inport_awvalid_i && inport_awready_o && timeout_flag_o)
            timeout_flag_o <= 1'b0;
    end
end

// External timeout clear (if desired) – this input can be used to clear the flag when the system handles the timeout.
always @(posedge clk_i) begin
    if (timeout_clear_i)
        timeout_flag_o <= 1'b0;
end

endmodule

