                                    slv_reg_t <= axi_wdata;
                                    axi_bresp <= 2'b00;
                                end
                                8'h20: begin
                                    slv_reg_v <= axi_wdata;
                                    axi_bresp <= 2'b00;
                                end
                                8'h24: begin
                                    slv_reg_irq_mask <= axi_wdata;
                                    axi_bresp <= 2'b00;
                                end
                                8'h28: begin
                                    slv_reg_irq_thresh <= axi_wdata;
