output.rtl/axis_image_border_gen.sv:
module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,               // Interior image width (X resolution)
    parameter IMG_HEIGHT = 256,              // Interior image height (Y resolution)
    parameter BORDER_COLOR = 16'hFFFF,       // Pixel value for the border
    parameter DATA_MASK    = 16'h0000        // Mask applied to input pixel data
)(
    input  wire            clk,              // AXI clock (100 MHz)
    input  wire            resetn,           // Active-low asynchronous reset

    // AXI Stream input interface
    input  wire [15:0]     s_axis_tdata,     // Input pixel data
    input  wire            s_axis_tvalid,    // Input valid signal
    output wire            s_axis_tready,    // Ready to accept input data
    input  wire            s_axis_tlast,     // Input last signal (not used in this design)
    input  wire            s_axis_tuser,     // Frame start signal

    // AXI Stream output interface
    output wire [15:0]     m_axis_tdata,     // Output pixel data with border applied
    output wire            m_axis_tvalid,    // Output valid signal
    input  wire            m_axis_tready,    // Ready to accept output data
    output wire            m_axis_tlast,     // Output last signal for each row
    output wire            m_axis_tuser      // Output frame start signal
);

    // State encoding for the FSM
    localparam [2:0] ST_IDLE       = 3'b000,
                      ST_ROW_FIRST  = 3'b001,
                      ST_PROCESS_ROW = 3'b010,
                      ST_BORDER_ROW  = 3'b011,
                      ST_ROW_LAST    = 3'b100;

    // Registers for state and pixel/row counters
    reg [2:0] state, next_state;
    reg [15:0] x_count, y_count;

    // Border detection based on current pixel position
    // Note: The total row width is IMG_WIDTH + 2 and total rows is IMG_HEIGHT + 2.
    wire is_top_row     = (y_count == 16'd0);
    wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
    wire is_left_border = (x_count == 16'd0);
    wire is_right_border = (x_count == IMG_WIDTH + 1);
    wire is_border_pixel = is_top_row || is_bottom_row || is_left_border || is_right_border;

    //-------------------------------------------------------------------------
    // Combinational logic to determine the next state
    //-------------------------------------------------------------------------
    always @(*) begin
        case (state)
            ST_IDLE: begin
                if (s_axis_tuser && s_axis_tvalid)
                    next_state = ST_ROW_FIRST;
                else
                    next_state = ST_IDLE;
            end
            ST_ROW_FIRST: begin
                if (x_count == (IMG_WIDTH + 1))
                    next_state = ST_PROCESS_ROW;
                else
                    next_state = ST_ROW_FIRST;
            end
            ST_PROCESS_ROW: begin
                if (x_count == (IMG_WIDTH + 1))
                    next_state = (y_count == IMG_HEIGHT) ? ST_BORDER_ROW : ST_PROCESS_ROW;
                else
                    next_state = ST_PROCESS_ROW;
            end
            ST_BORDER_ROW: begin
                if (x_count == (IMG_WIDTH + 1))
                    next_state = ST_ROW_LAST;
                else
                    next_state = ST_BORDER_ROW;
            end
            ST_ROW_LAST: begin
                next_state = ST_IDLE;
            end
            default: next_state = ST_IDLE;
        endcase
    end

    //-------------------------------------------------------------------------
    // Sequential logic: update state and counters on clock edge
    //-------------------------------------------------------------------------
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            state      <= ST_IDLE;
            x_count    <= 16'd0;
            y_count    <= 16'd0;
        end else begin
            // Update counters based on the current state
            case (state)
                ST_IDLE: begin
                    if (s_axis_tuser && s_axis_tvalid) begin
                        x_count <= 16'd0;
                        y_count <= 16'd0;
                    end
                end
                ST_ROW_FIRST: begin
                    if (x_count == (IMG_WIDTH + 1)) begin
                        x_count <= 16'd0;
                        y_count <= y_count + 1;  // Transition to interior row (row 1)
                    end else begin
                        x_count <= x_count + 1;
                    end
                end
                ST_PROCESS_ROW: begin
                    if (x_count == (IMG_WIDTH + 1)) begin
                        x_count <= 16'd0;
                        y_count <= y_count + 1;
                    end else begin
                        x_count <= x_count + 1;
                    end
                end
                ST_BORDER_ROW: begin
                    if (x_count == (IMG_WIDTH + 1)) begin
                        x_count <= 16'd0;
                        y_count <= y_count + 1;
                    end else begin
                        x_count <= x_count + 1;
                    end
                end
                ST_ROW_LAST: begin
                    x_count <= 16'd0;
                    y_count <= 16'd0;
                end
                default: begin
                    x_count <= 16'd0;
                    y_count <= 16'd0;
                end
            endcase

            // Transition to the next state
            state <= next_state;
        end
    end

    //-------------------------------------------------------------------------
    // AXI Stream Output Assignments
    //-------------------------------------------------------------------------
    // Output pixel data: if the pixel is on the border, output BORDER_COLOR;
    // otherwise, output the masked input pixel data.
    assign m_axis_tdata = is_border_pixel ? BORDER_COLOR : (s_axis_tdata & DATA_MASK);

    // Mark the last pixel of each row (except the final state)
    assign m_axis_tlast = (x_count == (IMG_WIDTH + 1)) && (state != ST_ROW_LAST);

    // Assert tuser at the start of the output frame (i.e. at the first row)
    assign m_axis_tuser = (state == ST_ROW_FIRST);

    // AXI Stream handshake signals
    // The module is ready to accept input when not idle and not in the final state.
    assign s_axis_tready = (state != ST_IDLE) && (state != ST_ROW_LAST);
    // The output valid signal is asserted when the module is actively processing a row.
    assign m_axis_tvalid = (state != ST_IDLE) && (state != ST_ROW_LAST);

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner (
  input  logic         clk,
  input  logic         rst,
  // AXI Stream Input 1
  input  logic [7:0]   s_axis_tdata_1,
  input  logic         s_axis_tvalid_1,
  output logic         s_axis_tready_1,
  input  logic         s_axis_tlast_1,
  // AXI Stream Input 2
  input  logic [7:0]   s_axis_tdata_2,
  input  logic         s_axis_tvalid_2,
  output logic         s_axis_tready_2,
  input  logic         s_axis_tlast_2,
  // AXI Stream Input 3
  input  logic [7:0]   s_axis_tdata_3,
  input  logic         s_axis_tvalid_3,
  output logic         s_axis_tready_3,
  input  logic         s_axis_tlast_3,
  // Merged AXI Stream Output
  output logic [7:0]   m_axis_tdata,
  output logic         m_axis_tvalid,
  input  logic         m_axis_tready,
  output logic         m_axis_tlast,
  output logic [1:0]   m_axis_tuser,
  // Status signal: indicates module is processing data
  output logic         busy
);

  //-------------------------------------------------------------------------
  // FSM State Encoding
  //-------------------------------------------------------------------------
  typedef enum logic [1:0] {
    STATE_IDLE = 2'd0,
    STATE_1    = 2'd1,
    STATE_2    = 2'd2,
    STATE_3    = 2'd3
  } state_t;

  state_t current_state, next_state;

  //-------------------------------------------------------------------------
  // Buffer Registers: hold the current word being transferred.
  //-------------------------------------------------------------------------
  logic [7:0]   buffered_tdata;
  logic         buffered_tlast;
  logic [1:0]   buffered_tuser;  // TAG_ID: 0x1, 0x2, 0x3 for streams 1,2,3 respectively

  //-------------------------------------------------------------------------
  // Combinational Next-State Logic
  //-------------------------------------------------------------------------
  always_comb begin
    next_state = current_state;
    case (current_state)
      STATE_IDLE: begin
        // Arbitration: check inputs in round-robin priority order.
        if (s_axis_tvalid_1)
          next_state = STATE_1;
        else if (s_axis_tvalid_2)
          next_state = STATE_2;
        else if (s_axis_tvalid_3)
          next_state = STATE_3;
        else
          next_state = STATE_IDLE;
      end
      STATE_1: begin
        // Only update state when m_axis_tready is high.
        if (m_axis_tready) begin
          // If the current buffered word indicates the end of a packet,
          // complete the transfer and return to idle.
          if (buffered_tlast)
            next_state = STATE_IDLE;
          else
            next_state = STATE_1;
        end
        else
          next_state = STATE_1;
      end
      STATE_2: begin
        if (m_axis_tready) begin
          if (buffered_tlast)
            next_state = STATE_IDLE;
          else
            next_state = STATE_2;
        end
        else
          next_state = STATE_2;
      end
      STATE_3: begin
        if (m_axis_tready) begin
          if (buffered_tlast)
            next_state = STATE_IDLE;
          else
            next_state = STATE_3;
        end
        else
          next_state = STATE_3;
      end
      default: next_state = STATE_IDLE;
    endcase
  end

  //-------------------------------------------------------------------------
  // Sequential Logic: State Update and Buffer Management
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      current_state   <= STATE_IDLE;
      buffered_tdata  <= 8'd0;
      buffered_tlast  <= 1'b0;
      buffered_tuser  <= 2'd0;
    end
    else begin
      current_state <= next_state;
      // Update the buffer only when the output is ready.
      if (m_axis_tready) begin
        case (current_state)
          STATE_1: begin
            // Capture new data from stream 1 if available.
            if (s_axis_tvalid_1) begin
              buffered_tdata  <= s_axis_tdata_1;
              buffered_tlast  <= s_axis_tlast_1;
              buffered_tuser  <= 2'd1;  // TAG_ID_1 = 0x1
            end
          end
          STATE_2: begin
            if (s_axis_tvalid_2) begin
              buffered_tdata  <= s_axis_tdata_2;
              buffered_tlast  <= s_axis_tlast_2;
              buffered_tuser  <= 2'd2;  // TAG_ID_2 = 0x2
            end
          end
          STATE_3: begin
            if (s_axis_tvalid_3) begin
              buffered_tdata  <= s_axis_tdata_3;
              buffered_tlast  <= s_axis_tlast_3;
              buffered_tuser  <= 2'd3;  // TAG_ID_3 = 0x3
            end
          end
          default: begin
            // No buffering update in STATE_IDLE.
          end
        endcase
      end
    end
  end

  //-------------------------------------------------------------------------
  // Output Assignments and s_axis_tready Generation
  //-------------------------------------------------------------------------
  always_comb begin
    // Drive merged output from the buffered registers.
    m_axis_tdata  = buffered_tdata;
    m_axis_tvalid = (current_state != STATE_IDLE);
    m_axis_tlast  = buffered_tlast;
    m_axis_tuser  = buffered_tuser;

    // Only the active input stream is acknowledged.
    s_axis_tready_1 = (current_state == STATE_1) ? m_axis_tready : 1'b0;
    s_axis_tready_2 = (current_state == STATE_2) ? m_axis_tready : 1'b0;
    s_axis_tready_3 = (current_state == STATE_3) ? m_axis_tready : 1'b0;

