output.rtl/coffee_machine.sv:
module coffee_machine #(
    parameter NBW_DLY    = 'd5,
    parameter NBW_BEANS  = 'd2,
    parameter NS_BEANS   = 'd4,
    parameter NS_OP      = 'd3, // Fixed
    parameter NS_SENSOR  = 'd4  // Fixed
) (
    input  logic                 clk,
    input  logic                 rst_async_n,
    input  logic [NBW_DLY-1:0]   i_grind_delay,
    input  logic [NBW_DLY-1:0]   i_heat_delay,
    input  logic [NBW_DLY-1:0]   i_pour_delay,
    input  logic [NBW_BEANS-1:0] i_bean_sel,
    input  logic [NS_OP-1:0]     i_operation_sel,
    input  logic                 i_start,
    input  logic [NS_SENSOR-1:0] i_sensor,
    output logic [NS_BEANS-1:0]  o_bean_sel,
    output logic                 o_grind_beans,
    output logic                 o_use_powder,
    output logic                 o_heat_water,
    output logic                 o_pour_coffee,
    output logic                 o_error
);

// Fixed delays (bean selection and powder usage)
localparam SEL_CYCLES    = 'd3;
localparam POWDER_CYCLES = 'd2;

typedef enum logic [2:0] {
    IDLE     = 3'b000,
    BEAN_SEL = 3'b001,
    GRIND    = 3'b011,
    POWDER   = 3'b111,
    HEAT     = 3'b110,
    POUR     = 3'b100
} state_t;

// ----------------------------------------
// - Wires/Registers creation
// ----------------------------------------
state_t state_ff, state_nx;
logic [NBW_DLY:0]     counter_ff, counter_nx;
logic [NBW_DLY-1:0]   grind_delay_ff, heat_delay_ff, pour_delay_ff;
logic [NS_OP-1:0]     operation_sel_ff;
logic [NBW_BEANS-1:0] bean_sel_in_ff;
logic                 start_ff;

// Output assignment (error conditions)
always_comb begin : error_logic
    if(state_ff == IDLE) begin
        o_error = (i_sensor[0] | i_sensor[3]) | (&i_operation_sel[2:1]) | (i_operation_sel[1] & i_sensor[1]) | ((i_operation_sel[2] || i_operation_sel[0]) & i_sensor[2]);
    end else begin
        o_error = i_sensor[3];
    end
end

// ----------------------------------------
// - Registers
// ----------------------------------------
always_ff @(posedge clk) begin : data_regs
    start_ff <= i_start & ~(i_sensor[0] | i_sensor[3]) & (|i_operation_sel[2:1]) & ~(i_operation_sel[1] & i_sensor[1]) & ~((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]);

    if(i_start && state_ff == IDLE) begin
        operation_sel_ff <= i_operation_sel;
        grind_delay_ff   <= i_grind_delay;
        heat_delay_ff    <= i_heat_delay;
        pour_delay_ff    <= i_pour_delay;
        bean_sel_in_ff   <= i_bean_sel;
    end

    counter_ff      <= counter_nx;
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        state_ff <= IDLE;
    end else begin
        state_ff <= state_nx;
    end
end

// ----------------------------------------
// - FSM update
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            counter_nx = 0;

            if(start_ff) begin
                if(~(|i_operation_sel[2:1])) begin
                    state_nx = HEAT;
                end else if(i_operation_sel[1]) begin
                    state_nx = BEAN_SEL;
                end else if(i_operation_sel[0]) begin
                    state_nx = POUR;
                end else begin
                    state_nx = POWDER;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        BEAN_SEL: begin
            if(counter_ff >= SEL_CYCLES) begin
                counter_nx = 0;
                state_nx   = GRIND;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = BEAN_SEL;
            end
        end
        GRIND: begin
            if(counter_ff >= grind_delay_ff) begin
                counter_nx = 0;
                if(operation_sel_ff[0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = HEAT;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = GRIND;
            end
        end
        POWDER: begin
            if(counter_ff >= POWDER_CYCLES) begin
                counter_nx = 0;
                state_nx   = POUR;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        HEAT: begin
            if(counter_ff >= heat_delay_ff) begin
                counter_nx = 0;
                if(|operation_sel_ff[1:0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = POUR;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = HEAT;
            end
        end
        POUR: begin
            if(counter_ff >= pour_delay_ff) begin
                counter_nx = 0;
                state_nx   = IDLE;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        default: begin
            counter_nx = 0;
            state_nx   = IDLE;
        end
    endcase
end

// ----------------------------------------
// - Controller outputs
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_use_powder    = 1'b0;
            o_grind_beans   = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        BEAN_SEL: begin
            o_bean_sel                      = 1'b0; // Set all bits to 0
            o_bean_sel[bean_sel_in_ff]      = 1'b1; // Only the position of bean_sel_ff should be 1
            o_grind_beans                   = 1'b0;
            o_use_powder                    = 1'b0;
            o_heat_water                    = 1'b0;
            o_pour_coffee                   = 1'b0;
        end
        GRIND: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b1;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        POWDER: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b1;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        HEAT: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

endmodule : coffee_machine

output.rtl/signed_comparator.sv:
module signed_unsigned_comparator #(parameter WIDTH = 5) (
    input  logic [WIDTH-1:0] i_A,
    input  logic [WIDTH-1:0] i_B,
    input  logic             i_enable,
    input  logic             i_mode,
    output logic             o_greater,
    output logic             o_less,
    output logic             o_equal
);

    // Local wires for signed interpretation in signed mode
    logic signed [WIDTH-1:0] a_signed;
    logic signed [WIDTH-1:0] b_signed;

    assign a_signed = $signed(i_A);
    assign b_signed = $signed(i_B);

    // Purely combinational logic
    always_comb begin
        // Default: outputs inactive
        o_greater = 1'b0;
        o_less    = 1'b0;
        o_equal   = 1'b0;

        if (i_enable) begin
            if (i_mode) begin
                // Signed mode: compare as signed numbers
                if (a_signed > b_signed)
                    o_greater = 1'b1;
                else if (a_signed < b_signed)
                    o_less    = 1'b1;
                else
                    o_equal   = 1'b1;
            end else begin
                // Magnitude mode: compare as unsigned numbers
                if (i_A > i_B)
                    o_greater = 1'b1;
                else if (i_A < i_B)
                    o_less    = 1'b1;
                else
                    o_equal   = 1'b1;
            end
        end
    end

endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier (
    input  logic clk,
    input  logic arst_n,
    input  logic [15:0] a_real,
    input  logic [15:0] a_imag,
    input  logic [15:0] b_real,
    input  logic [15:0] b_imag,
    output logic [31:0] result_real,
    output logic [31:0] result_imag
);

    // Compute the real and imaginary parts of the product in combinational logic.
    logic [31:0] real_temp;
    logic [31:0] imag_temp;

    assign real_temp = (a_real * b_real) - (a_imag * b_imag);
    assign imag_temp = (a_real * b_imag) + (a_imag * b_real);

    // Pipeline stage: register the computed result for one cycle latency.
    always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            result_real <= 32'd0;
            result_imag <= 32'd0;
        end else begin
            result_real <= real_temp;
            result_imag <= imag_temp;
        end
    end

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor (
    input         i_clk,
    input         i_rst_n,
    input         i_enable,
    input         i_clear,
    input         i_ack,
    input         i_fault,
    input  [4:0]  i_vector_1,
    input  [4:0]  i_vector_2,
    input  [4:0]  i_vector_3,
    input  [4:0]  i_vector_4,
    input  [4:0]  i_vector_5,
    input  [4:0]  i_vector_6,
    output reg    o_ready,
    output reg    o_error,
    output reg [1:0] o_fsm_status,
    output reg [7:0] o_vector_1,
    output reg [7:0] o_vector_2,
    output reg [7:0] o_vector_3,
    output reg [7:0] o_vector_4
);

    // Define FSM states: IDLE=00, PROCESS=01, READY=10, FAULT=11
    localparam [1:0] IDLE   = 2'b00,
                     PROCESS = 2'b01,
                     READY   = 2'b10,
                     FAULT   = 2'b11;

    reg [1:0] state;

    // Synchronous state and output update
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state         <= IDLE;
            o_ready       <= 1'b0;
            o_error       <= 1'b0;
            o_vector_1    <= 8'd0;
            o_vector_2    <= 8'd0;
            o_vector_3    <= 8'd0;
            o_vector_4    <= 8'd0;
            o_fsm_status  <= IDLE;
        end
        else begin
            // Fault takes precedence over all other operations
            if (i_fault) begin
                state         <= FAULT;
                o_error       <= 1'b1;
                o_ready       <= 1'b0;
                o_vector_1    <= 8'd0;
                o_vector_2    <= 8'd0;
                o_vector_3    <= 8'd0;
                o_vector_4    <= 8'd0;
                o_fsm_status  <= FAULT;
            end
            else begin
                case (state)
                    IDLE: begin
                        if (i_enable)
                            state <= PROCESS;
                        else
                            state <= IDLE;
                    end

                    PROCESS: begin
                        // Concatenate six 5-bit vectors and append 2'b11 to form a 32-bit bus.
                        // The bus is defined as: { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 }
                        // Then split the bus into four 8-bit outputs:
                        //   o_vector_1 = bus[31:24]
                        //   o_vector_2 = bus[23:16]
                        //   o_vector_3 = bus[15:8]
                        //   o_vector_4 = bus[7:0]
                        o_vector_1 <= { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 }[31:24];
                        o_vector_2 <= { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 }[23:16];
                        o_vector_3 <= { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 }[15:8];
                        o_vector_4 <= { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 }[7:0];
                        state      <= READY;
                        o_ready    <= 1'b0;
                        o_error    <= 1'b0;
                    end

                    READY: begin
                        if (i_ack)
                            state <= IDLE;
                        else
                            state <= READY;
                        // Assert o_ready in READY state to indicate valid outputs
                        o_ready <= (state == READY) ? 1'b1 : 1'b0;
                        o_error <= 1'b0;
                    end

                    FAULT: begin
                        // In FAULT state, if i_clear is asserted and the fault is cleared (i_fault deasserted),
                        // transition back to IDLE.
                        if (i_clear && !i_fault)
                            state <= IDLE;
                        else
                            state <= FAULT;
                        o_error <= (state == FAULT) ? 1'b1 : 1'b0;
                        o_ready <= 1'b0;
                    end
                endcase
                o_fsm_status <= state;
            end
        end
    end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
  parameter DATA_WIDTH = 16,
  parameter COEFF_WIDTH = 16,
  parameter NUM_TAPS   = 8
)(
  input  logic                    clk,
  input  logic                    reset,
  input  logic [DATA_WIDTH*NUM_TAPS-1:0] data_in,
  input  logic                    valid_in,
  input  logic [COEFF_WIDTH*NUM_TAPS-1:0] coeffs,
  output logic [NBW_MULT + $clog2(NUM_TAPS)-1:0] data_out,
  output logic                    valid_out
);

  // Derived parameter: width of intermediate multiplication results.
  localparam int NBW_MULT = DATA_WIDTH + COEFF_WIDTH;
  // Derived parameter: width required for final summation result.
  localparam int OUT_WIDTH = NBW_MULT + $clog2(NUM_TAPS);

  //-------------------------------------------------------------------------
  // Internal Registers: 
  // These registers store the incoming data and coefficients when valid_in
  // is asserted. When valid_in is low, the previous values are retained.
  //-------------------------------------------------------------------------
  reg [DATA_WIDTH-1:0] data_reg [0:NUM_TAPS-1];
  reg [COEFF_WIDTH-1:0] coeff_reg [0:NUM_TAPS-1];

  //-------------------------------------------------------------------------
  // Registered Output Data:
  // The computed convolution result is registered here to introduce one
  // clock cycle of latency.
  //-------------------------------------------------------------------------
  reg [OUT_WIDTH-1:0] data_out_reg;

  //-------------------------------------------------------------------------
  // Combinational Logic: Multiplication and Accumulation
  //
  // The registered input data and coefficients are used to compute the 
  // convolution. Note that the coefficients are applied in reverse order:
  // the first data sample is multiplied by the last coefficient, the second
  // by the second-to-last, and so on.
  //-------------------------------------------------------------------------
  logic [NBW_MULT-1:0] product [0:NUM_TAPS-1];
  logic [OUT_WIDTH-1:0] sum;

  always_comb begin
    sum = '0;
    for (int i = 0; i < NUM_TAPS; i++) begin
      // Reverse the coefficient order: data_reg[i] * coeff_reg[NUM_TAPS-1-i]
      product[i] = data_reg[i] * coeff_reg[NUM_TAPS-1-i];
      sum = sum + product[i];
    end
  end

  //-------------------------------------------------------------------------
  // Sequential Logic: Input Registering and Output Registration
  //
  // On every clock cycle:
  // - If reset is high, clear all internal registers and outputs.
  // - If valid_in is high, update the data_reg and coeff_reg with new values.
  // - Register the valid_in signal to valid_out (one cycle latency).
  // - Register the computed sum into data_out_reg.
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      // Clear all registered data and coefficients.
      for (int i = 0; i < NUM_TAPS; i++) begin
        data_reg[i] <= '0;
        coeff_reg[i] <= '0;
      end
      valid_out   <= 1'b0;
      data_out_reg<= '0;
    end
    else begin
      if (valid_in) begin
        // Update registers with new input data and coefficients.
        for (int i = 0; i < NUM_TAPS; i++) begin
          data_reg[i] <= data_in[(i+1)*DATA_WIDTH-1 -: DATA_WIDTH];
          coeff_reg[i] <= coeffs[(i+1)*COEFF_WIDTH-1 -: COEFF_WIDTH];
        end
      end
      // Register valid_in with one cycle latency.
      valid_out   <= valid_in;
      // Register the convolution result.
      data_out_reg<= sum;
    end
  end

  // Drive the output port with the registered data.
  assign data_out = data_out_reg;

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(
  parameter int N           = 8,         // Total number of input samples
  parameter int DATA_WIDTH   = 16,        // Bit-width of each sample
  parameter int DEC_FACTOR   = 4          // Decimation factor (must divide N)
) (
  input  logic                  clk,
  input  logic                  reset,
  input  logic                  valid_in,
  input  logic [DATA_WIDTH*N-1:0] data_in,
  output logic                  valid_out,
  output logic [DATA_WIDTH*(N/DEC_FACTOR)-1:0] data_out,
  output logic signed [DATA_WIDTH-1:0] peak_value
);

  // Local parameter for the number of decimated samples
  localparam int NUM_DEC = N / DEC_FACTOR;

  // Register to hold the unpacked input samples
  logic signed [DATA_WIDTH-1:0] sample_reg [0:N-1];

  // Registered valid signal
  logic valid_reg;

  // Combinationally computed decimated samples and peak value
  logic signed [DATA_WIDTH-1:0] decimated [0:NUM_DEC-1];
  logic signed [DATA_WIDTH-1:0] peak;

  // Packed bus for the decimated data output
  logic [DATA_WIDTH*NUM_DEC-1:0] decimated_packed;

  // -------------------------------------------------------------------
  // Input Data Registering and Unpacking
  // -------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      // Clear all sample registers on reset
      for (int i = 0; i < N; i++) begin
        sample_reg[i] <= '0;
      end
      valid_reg <= 1'b0;
    end else if (valid_in) begin
      // Unpack the packed input bus into individual samples
      for (int i = 0; i < N; i++) begin
        sample_reg[i] <= data_in[((i+1)*DATA_WIDTH)-1 -: DATA_WIDTH];
      end
      valid_reg <= valid_in;
    end
  end

  // -------------------------------------------------------------------
  // Decimation and Peak Detection (Combinational Logic)
  // -------------------------------------------------------------------
  always_comb begin
    // Decimation: select one sample for every DEC_FACTOR samples.
    // The j-th decimated sample is taken from sample_reg[j*DEC_FACTOR].
    for (int j = 0; j < NUM_DEC; j++) begin
      decimated[j] = sample_reg[j * DEC_FACTOR];
    end

    // Peak Detection: find the maximum value among the decimated samples.
    peak = decimated[0];
    for (int j = 1; j < NUM_DEC; j++) begin
      if (decimated[j] > peak)
        peak = decimated[j];
    end

    // Pack the decimated samples into a single bus.
    // The first decimated sample becomes the most significant portion.
    decimated_packed = '0;
    for (int j = NUM_DEC - 1; j >= 0; j--) begin
      decimated_packed = { decimated[j], decimated_packed };
    end
  end

  // -------------------------------------------------------------------
  // Output Packing and Registration (1-cycle Latency)
  // -------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      valid_out   <= 1'b0;
      data_out    <= '0;
      peak_value  <= '0;
    end else begin
      valid_out   <= valid_reg;
      data_out    <= decimated_packed;
      peak_value  <= peak;
    end
  end

endmodule

