module cont_adder #(
  parameter DATA_WIDTH = 32,
  parameter signed THRESHOLD_VALUE_1 = 50,
  parameter signed THRESHOLD_VALUE_2 = 100,
  parameter signed THRESHOLD_VALUE_3 = 150,
  parameter ACCUM_MODE = 0,
  parameter WEIGHT = 1,
  parameter signed SAT_MAX = (2**(DATA_WIDTH-1))-1,
  parameter signed SAT_MIN = -(2**(DATA_WIDTH-1))
) (
  input  logic                         clk,
  input  logic                         reset,
  input  logic                         accum_clear,
  input  logic                         enable,
  input  logic signed [DATA_WIDTH-1:0] data_in,
  input  logic                         data_valid,
  input  logic [15:0]                  window_size,
  output logic signed [DATA_WIDTH-1:0] sum_out,
  output logic signed [DATA_WIDTH-1:0] avg_out,
  output logic                         threshold_1,
  output logic                         threshold_2,
  output logic                         threshold_3,
  output logic                         sum_ready,
  output logic                         busy
);

  typedef enum logic [1:0] {IDLE, ACCUM, DONE} state_t;
  state_t state;
  logic signed [DATA_WIDTH-1:0] sum_accum;
  logic [15:0] sample_count;
  logic signed [DATA_WIDTH-1:0] weighted_in_reg;
  logic signed [DATA_WIDTH-1:0] new_sum;
  logic signed [DATA_WIDTH-1:0] sat_sum;

  //------------------------------------------------------------------
  // Combined always_ff block for computing the weighted input,
  // new sum, and applying saturation.
  // This reduces the number of sequential blocks and associated wires.
  //------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      weighted_in_reg <= 0;
      new_sum         <= 0;
      sat_sum         <= 0;
    end else if (enable && data_valid) begin
      weighted_in_reg <= (WEIGHT == 1) ? data_in : data_in * WEIGHT;
      new_sum         <= sum_accum + weighted_in_reg;
      sat_sum         <= (new_sum > SAT_MAX) ? SAT_MAX :
                         ((new_sum < SAT_MIN) ? SAT_MIN : new_sum);
    end
  end

  //------------------------------------------------------------------
  // Combined always_ff block for state machine, accumulator, sample
  // count, and output logic. Merging these blocks reduces the overall
  // number of registers and combinational logic, leading to area savings.
  //------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset || accum_clear) begin
      state         <= IDLE;
      sum_accum     <= 0;
      sample_count  <= 0;
      sum_out       <= 0;
      avg_out       <= 0;
      sum_ready     <= 0;
      threshold_1   <= 0;
      threshold_2   <= 0;
      threshold_3   <= 0;
      busy          <= 0;
    end else if (enable && data_valid) begin
      case (state)
        IDLE: begin
          state         <= ACCUM;
          sum_accum     <= sat_sum;
          sample_count  <= 1;
          busy          <= 1;
        end
        ACCUM: begin
          sum_accum     <= sat_sum;
          sample_count  <= sample_count + 1;
          busy          <= 1;
          if ((ACCUM_MODE == 1) && ((sample_count + 1) >= window_size))
            state <= DONE;
          else if ((ACCUM_MODE == 0) &&
                   (((sat_sum >= THRESHOLD_VALUE_1) || (sat_sum <= -THRESHOLD_VALUE_1)) ||
                    ((sat_sum >= THRESHOLD_VALUE_2) || (sat_sum <= -THRESHOLD_VALUE_2)) ||
                    ((sat_sum >= THRESHOLD_VALUE_3) || (sat_sum <= -THRESHOLD_VALUE_3))))
            state <= DONE;
          else
            state <= ACCUM;
        end
        DONE: begin
          // Capture final outputs using the previous cycle's values.
          sum_out       <= sum_accum;
          avg_out       <= (ACCUM_MODE == 1) ? (sum_accum / sample_count) : 0;
          sum_ready     <= 1;
          threshold_1   <= (sum_accum >= THRESHOLD_VALUE_1) || (sum_accum <= -THRESHOLD_VALUE_1);
          threshold_2   <= (sum_accum >= THRESHOLD_VALUE_2) || (sum_accum <= -THRESHOLD_VALUE_2);
          threshold_3   <= (sum_accum >= THRESHOLD_VALUE_3) || (sum_accum <= -THRESHOLD_VALUE_3);
          state         <= IDLE;
          sum_accum     <= 0;
          sample_count  <= 0;
          busy          <= 0;
        end
        default: begin
          state         <= IDLE;
          sum_accum     <= 0;
          sample_count  <= 0;
          sum_out       <= 0;
          avg_out       <= 0;
          sum_ready     <= 0;
          threshold_1   <= 0;
          threshold_2   <= 0;
          threshold_3   <= 0;
          busy          <= 0;
        end
      endcase
    end else begin
      // Hold outputs and state when not processing.
      busy <= (state == ACCUM);
    end
  end

endmodule

output.rtl/convolutional_encoder.sv:
module convolutional_encoder(
    input  logic clk,
    input  logic rst,
    input  logic data_in,
    output logic encoded_bit1,
    output logic encoded_bit2
);

    // 2-bit shift register to hold the previous 2 bits
    logic [1:0] shift_reg;

    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg   <= 2'b00;
            encoded_bit1<= 1'b0;
            encoded_bit2<= 1'b0;
        end else begin
            // The encoder uses the current input bit and the previous 2 bits.
            // The generator polynomial for g1 (111) produces:
            // encoded_bit1 = data_in XOR shift_reg[0] XOR shift_reg[1]
            // The generator polynomial for g2 (101) produces:
            // encoded_bit2 = data_in XOR shift_reg[1]
            encoded_bit1 <= data_in ^ shift_reg[0] ^ shift_reg[1];
            encoded_bit2 <= data_in ^ shift_reg[1];

            // Update the shift register: shift left and insert the new bit at LSB.
            shift_reg <= {shift_reg[0], data_in};
        end
    end

endmodule

module convolutional_encoder (
    input  wire         clk,
    input  wire         rst,
    input  wire         data_in,
    output reg          encoded_bit1,
    output reg          encoded_bit2
);

    // Shift register to hold the two previous bits (constraint length k=3 requires 2 memory bits)
    reg [1:0] shift_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg      <= 2'b00;
            encoded_bit1   <= 1'b0;
            encoded_bit2   <= 1'b0;
        end else begin
            // Compute the encoded bits using the generator polynomials:
            // g1(x) = x^2 + x + 1  --> encoded_bit1 = data_in XOR shift_reg[1] XOR shift_reg[0]
            // g2(x) = x^2 + 1      --> encoded_bit2 = data_in XOR shift_reg[0]
            encoded_bit1  <= data_in ^ shift_reg[1] ^ shift_reg[0];
            encoded_bit2  <= data_in ^ shift_reg[0];

            // Update the shift register:
            // Shift left: the oldest bit (shift_reg[1]) moves to shift_reg[0],
            // and the new input (data_in) becomes the new least significant bit.
            shift_reg <= { shift_reg[0], data_in };
        end
    end

endmodule

output.rtl/crossbar_switch.sv:
module crossbar_switch #(
    parameter DATA_WIDTH = 8,  // Parameterized data width
    localparam NUM_PORTS = 4,
    localparam DATA_WIDTH_IN = (DATA_WIDTH + $clog2(NUM_PORTS))
)(
    input  logic                        clk,        // Clock signal
    input  logic                        reset,      // Reset signal (asynchronous, active low)
    // Input data and destination IDs
    input  logic [DATA_WIDTH_IN-1 :0]  in0, in1, in2, in3,  // Input data (MSBs hold destination ID)
    input  logic                       valid_in0, valid_in1, valid_in2, valid_in3,  // Input data valid signals
    // Output data
    output logic  [DATA_WIDTH-1:0]      out0, out1, out2, out3,  // Output data
    output logic                        valid_out0, valid_out1, valid_out2, valid_out3  // Output valid signals
);
    // Internal Signals: Extract the 2 MSB bits as the destination ID
    logic [$clog2(NUM_PORTS)-1 : 0] dest0, dest1, dest2, dest3;

    // ----------------------------------------
    // - Procedural blocks
    // ----------------------------------------
    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            out0    <= 0;
            out1    <= 0;
            out2    <= 0;
            out3    <= 0;
            valid_out0 <= 1'b0;
            valid_out1 <= 1'b0;
            valid_out2 <= 1'b0;
            valid_out3 <= 1'b0;
        end else begin
            // Default: clear outputs
            out0    <= 0;
            out1    <= 0;
            out2    <= 0;
            out3    <= 0;
            valid_out0 <= 1'b0;
            valid_out1 <= 1'b0;
            valid_out2 <= 1'b0;
            valid_out3 <= 1'b0;

            // Only the highest priority valid input is routed.
            if (valid_in0 == 1) begin
                // For input port 0, route based on destination ID
                case (dest0)
                    2'b00: begin
                        out0    <= in0[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'b01: begin
                        out1    <= in0[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'b10: begin
                        out2    <= in0[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'b11: begin
                        out3    <= in0[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                endcase
            end else if (valid_in1 == 1) begin
                // For input port 1, route based on destination ID
                case (dest1)
                    2'b00: begin
                        out0    <= in1[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'b01: begin
                        out1    <= in1[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'b10: begin
                        out2    <= in1[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'b11: begin
                        out3    <= in1[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                endcase
            end else if (valid_in2 == 1) begin
                // For input port 2, route based on destination ID
                case (dest2)
                    2'b00: begin
                        out0    <= in2[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'b01: begin
                        out1    <= in2[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'b10: begin
                        out2    <= in2[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'b11: begin
                        out3    <= in2[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                endcase
            end else if (valid_in3 == 1) begin
                // For input port 3, route based on destination ID
                case (dest3)
                    2'b00: begin
                        out0    <= in3[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'b01: begin
                        out1    <= in3[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'b10: begin
                        out2    <= in3[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'b11: begin
                        out3    <= in3[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                endcase
            end
        end
    end

    // ----------------------------------------
    // - Combinational Assignments
    // ----------------------------------------
    // Extract the destination ID from the 2 MSB bits of the input data.
    assign dest0 = in0[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];
    assign dest1 = in1[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];
    assign dest2 = in2[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];
    assign dest3 = in3[DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2];

endmodule

output.rtl/data_bus_controller.sv:
module arbitrates between two master interfaces (m0 and m1)
 * and forwards the selected transaction to a single slave interface.
 *
 * Interface details:
 * - Masters (m0 and m1) use a ready-valid handshake.
 *   Their ready outputs (m0_read and m1_read) are driven by the slave's ready (s_read).
 * - The slave uses a ready-valid handshake (s_valid, s_data).
 *
 * Arbitration rules:
 * - If only one master asserts valid, its transaction is forwarded.
 * - If both masters assert valid concurrently:
 *       • When s_read is asserted, the arbitration uses the parameter AFINITY:
 *             AFINITY = 0  -> choose m0_data
 *             AFINITY = 1  -> choose m1_data
 * - First come, first served:
 *       • If masters drive transactions in different cycles, the first captured transaction is forwarded.
 * - One cycle latency:
 *       • The transaction captured is forwarded in the next cycle when s_read is high.
 */

module data_bus_controller #(
  parameter AFINITY = 0
)(
  input         clk,
  input         rst_n,

  output        m0_read,
  input         m0_valid,
  input  [31:0] m0_data,

  output        m1_read,
  input         m1_valid,
  input  [31:0] m1_data,

  input         s_read,
  output        s_valid,
  output [31:0] s_data
);

  // Drive master ready signals directly from slave ready
  assign m0_read = s_read;
  assign m1_read = s_read;

  // Internal register to hold the pending transaction.
  // This simple FIFO (depth = 1) ensures that if a transaction is captured,
  // it is held until the slave is ready, thereby implementing one-cycle latency.
  reg         pending_valid;
  reg  [31:0] pending_data;

  // Combinational logic to generate a new transaction from the masters.
  // Arbitration: if both masters are valid, select based on AFINITY.
  wire new_valid;
  wire [31:0] new_data;
  assign new_valid = m0_valid || m1_valid;
  assign new_data  = (m0_valid & ~m1_valid) ? m0_data :
                     (~m0_valid & m1_valid) ? m1_data :
                     (m0_valid & m1_valid)   ? (AFINITY==0 ? m0_data : m1_data) : 32'd0;

  // Sequential logic: capture a new transaction when possible,
  // and forward the pending transaction when the slave is ready.
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      pending_valid <= 1'b0;
      pending_data  <= 32'd0;
    end else begin
      if (s_read) begin
         // When slave is ready, output the pending transaction and clear it.
         // If no transaction is pending, capture a new one concurrently.
         if (pending_valid) begin
            pending_valid <= 1'b0;
         end else begin
            if (new_valid)
              pending_valid <= 1'b1;
            else
              pending_valid <= 1'b0;
         end
      end else begin
         // When slave is not ready, do not override an existing pending transaction.
         // Capture a new transaction only if none is pending.
         if (!pending_valid && new_valid)
           pending_valid <= 1'b1;
         // Else: hold the pending transaction.
      end
    end
  end

  // Drive the slave interface.
  // If a pending transaction exists, assert s_valid and drive s_data.
  assign s_valid = pending_valid;
  assign s_data  = pending_valid ? pending_data : 32'd0;

endmodule

input.rtl/data_serializer.sv:
module data_serializer #(
  parameter DATA_W   = 8,
  parameter BIT_ORDER= 0,
  parameter PARITY   = 0
)(
  input                  clk,
  input                  reset,
  // Parallel data interface
  input                  p_valid_i,
  input  [DATA_W-1:0]    p_data_i,
  output                 p_ready_o,
  // Serial data interface
  output                 s_valid_o,
  output                 s_data_o,
  input                  s_ready_i,
  // Transmission enable
  input                  tx_en_i
);

  // Local constants
  localparam ST_RX = 1'b0;
  localparam ST_TX = 1'b1;

  // If PARITY != 0 => We use 1 extra bit for parity
  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // If parity is used, it goes in the LSB or SHIFT_W-1?
            // We'll put it in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[8:4] = {p_data_i[4:0],parity_bit};
              shift_reg_d[3:0] = p_data_i[8:5];
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              if (EXTRA_BIT == 1) begin
                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_serializer.sv:
module data_serializer #(
  parameter DATA_W   = 8,
  parameter BIT_ORDER= 0,
  parameter PARITY   = 0
)(
  input                  clk,
  input                  reset,
  // Parallel data interface
  input                  p_valid_i,
  input  [DATA_W-1:0]    p_data_i,
  output                 p_ready_o,
  // Serial data interface
  output                 s_valid_o,
  output                 s_data_o,
  input                  s_ready_i,
  // Transmission enable
  input                  tx_en_i
);

  // Local constants
  localparam ST_RX = 1'b0;
  localparam ST_TX = 1'b1;

  // If PARITY != 0 => We use 1 extra bit for parity
  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first: place LSB of p_data_i at shift_reg_q[0]
            if (EXTRA_BIT == 1)
              // For LSB-first mode, parity bit is appended at the MSB of the shift register
              shift_reg_d = {parity_bit, p_data_i};
            else
              shift_reg_d = p_data_i;
          end
          else begin
            // MSB-first: place MSB of p_data_i at shift_reg_q[SHIFT_W-1]
            if (EXTRA_BIT == 1) begin
              // Correct fix: load the data in natural order and append parity bit at LSB.
              shift_reg_d = {p_data_i[7:0], parity_bit};
            end else begin
              shift_reg_d = p_data_i;
            end
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until all bits are transmitted
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // All bits have been sent; return to receive state
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              // Correct fix: shift left by 1 bit per cycle for MSB-first mode
              shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
              count_d     = count_q + 1;
            end
            else begin
              // LSB-first: shift right by 1 bit per cycle
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // For LSB-first, output the LSB; for MSB-first, output the MSB
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter(
    input  logic         clk,
    input  logic         reset,
    input  logic [31:0]  data_in,
    input  logic         data_valid,
    output logic [127:0] o_data_out,
    output logic         o_data_out_valid
);

    // Internal counter to track number of valid inputs received (0 to 3)
    logic [1:0] count;

    // Buffer to store four 32-bit inputs
    logic [31:0] data_buffer [0:3];

    // Sequential process: operates on the positive edge of clk or asynchronous reset
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // On reset, clear the counter, buffer, and outputs
            count                   <= 2'd0;
            o_data_out              <= 128'd0;
            o_data_out_valid        <= 1'd0;
        end
        else begin
            if (data_valid) begin
                // Store the incoming data into the buffer at the current count index
                data_buffer[count] <= data_in;

                // If four valid inputs have been received, generate the output
                if (count == 2'd3) begin
                    // Concatenate the four 32-bit words into a 128-bit output
                    o_data_out <= { data_buffer[3], data_buffer[2], data_buffer[1], data_buffer[0] };
                    o_data_out_valid <= 1'b1;
                    // Reset counter for the next set of inputs
                    count <= 2'd0;
                end
                else begin
                    // Increment the counter for the next valid input
                    count <= count + 2'd1;
                    o_data_out_valid <= 1'b0;
                end
            end
            else begin
                // If the current input is not valid, flush the state (reset counter)
                count <= 2'd0;
                o_data_out_valid <= 1'b0;
            end
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc (
    input  logic         clk,
    input  logic         rst_n,
    input  logic [39:0]  data_in,
    output logic [39:0]  data_out,
    output logic [1:0]   dbi_cntrl
);

    // Register to hold the previous 40-bit data word
    logic [39:0] prev_data;

    // Split current data into two 20-bit groups
    // Group-1: Most Significant 20 bits
    // Group-0: Least Significant 20 bits
    logic [19:0] curr_group1;
    logic [19:0] curr_group0;

    // Counters for bit differences between current and previous groups
    // (Using $countones which returns an integer value)
    integer diff_count1, diff_count0;

    // Synchronous process: on clock edge or asynchronous reset
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Reset: clear previous data and outputs
            prev_data    <= 40'b0;
            data_out     <= 40'b0;
            dbi_cntrl    <= 2'b00;
        end else begin
            // Split the incoming 40-bit data into two 20-bit groups
            curr_group1 = data_in[39:20];
            curr_group0 = data_in[19:0];

            // Calculate the number of bit differences for each group compared to previous data
            diff_count1 = $countones(curr_group1 ^ prev_data[39:20]);
            diff_count0 = $countones(curr_group0 ^ prev_data[19:0]);

            // Determine control signals:
            // If more than 10 bits differ, set the corresponding control bit high (1)
            dbi_cntrl[1] = (diff_count1 > 10);
            dbi_cntrl[0] = (diff_count0 > 10);

            // Generate output data based on control signals:
            // If control bit is high, invert the corresponding group; otherwise, pass-through unchanged.
            if (dbi_cntrl[1])
                data_out[39:20] = ~curr_group1;
            else
                data_out[39:20] = curr_group1;

            if (dbi_cntrl[0])
                data_out[19:0] = ~curr_group0;
            else
                data_out[19:0] = curr_group0;

            // Update previous data with the current cycle's data_out for next comparison
            prev_data <= data_out;
        end
    end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Control signals for inversion (LSB for group0, MSB for group1)
   // Outputs
   output wire [39:0] data_out   // Data output after DBI decoding
   );

   // Split data_in into two 20-bit groups:
   // Group1: bits [39:20] (most significant)
   // Group0: bits [19:0]  (least significant)

   // On reset, force data_out to 0.
   // On clock edge, decode based on dbi_cntrl:
   // - For group0, if dbi_cntrl[0] is 1, invert data_in[19:0]
   // - For group1, if dbi_cntrl[1] is 1, invert data_in[39:20]

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         data_out <= 40'h00000000;
      end else begin
         data_out <= { (dbi_cntrl[1] ? ~data_in[39:20] : data_in[39:20]),
                       (dbi_cntrl[0] ? ~data_in[19:0]  : data_in[19:0]) };
      end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module cvdp_copilot_decode_firstbit #(
  parameter InWidth_g = 32,
  parameter InReg_g   = 1,
  parameter OutReg_g  = 1,
  parameter PlRegs_g  = 1  // Number of pipeline stages (0 or more)
)(
  input  logic                     Clk,
  input  logic                     Rst,  // asynchronous, active-high reset
  input  logic [InWidth_g-1:0]     In_Data,
  input  logic                     In_Valid,
  output logic [$clog2(InWidth_g)-1:0] Out_FirstBit,
  output logic                     Out_Found,
  output logic                     Out_Valid
);

  //-------------------------------------------------------------------------
  // Local Parameters
  //-------------------------------------------------------------------------
  localparam integer BinBits_c = $clog2(InWidth_g);       // Bits needed to index In_Data
  localparam integer PadWidth  = (1 << BinBits_c);          // Nearest power-of-two width

  //-------------------------------------------------------------------------
  // Internal Signals
  //-------------------------------------------------------------------------
  // Registered input (if enabled)
  logic [InWidth_g-1:0] in_data_reg;
  logic                 in_valid_reg;

  // Padded input vector (always width = PadWidth)
  logic [PadWidth-1:0]  data_padded;

  // Combinational logic outputs: first set bit index, found flag, and valid flag
  logic [$clog2(InWidth_g)-1:0] comb_first_bit;
  logic                         comb_found;
  logic                         comb_valid;

  // Pipeline registers arrays (if any pipeline stages are used)
  // Only used when PlRegs_g > 0.
  logic [$clog2(InWidth_g)-1:0] pipe_first [0:PlRegs_g];
  logic                         pipe_found [0:PlRegs_g];
  logic                         pipe_valid [0:PlRegs_g];

  //-------------------------------------------------------------------------
  // Input Register (if enabled)
  //-------------------------------------------------------------------------
  generate
    if (InReg_g == 1) begin : reg_in
      always_ff @(posedge Clk or posedge Rst) begin
        if (Rst) begin
          in_data_reg  <= '0;
          in_valid_reg <= 1'b0;
        end else begin
          in_data_reg  <= In_Data;
          in_valid_reg <= In_Valid;
        end
      end
    end
    else begin : no_reg_in
      assign in_data_reg  = In_Data;
      assign in_valid_reg = In_Valid;
    end
  endgenerate

  //-------------------------------------------------------------------------
  // Pad the input data to the nearest power-of-two width
  //-------------------------------------------------------------------------
  assign data_padded = { {(PadWidth - InWidth_g){1'b0}}, in_data_reg };

  //-------------------------------------------------------------------------
  // Combinational First-Bit Decoder Logic
  //-------------------------------------------------------------------------
  // This always_comb block scans the lower InWidth_g bits of data_padded 
  // to find the index of the lowest set bit.
  always_comb begin
    // Propagate the input valid signal
    comb_valid = (InReg_g ? in_valid_reg : In_Valid);
    comb_found = 1'b0;
    comb_first_bit = '0;
    // Iterate over bits 0 to InWidth_g-1
    for (int i = 0; i < InWidth_g; i++) begin
      if (data_padded[i]) begin
        comb_found   = 1'b1;
        comb_first_bit = i;
        // Exit the loop once the first set bit is found
        break;
      end
    end
  end

  //-------------------------------------------------------------------------
  // Pipeline Stages and Final Output
  //-------------------------------------------------------------------------
  // If PlRegs_g > 0, the combinational result is passed through pipeline stages.
  // Otherwise, the result is directly forwarded (optionally registered at output).
  generate
    if (PlRegs_g > 0) begin : pipeline_reg_block

      //-------------------------------------------------------------------------
      // Stage 0: Capture the combinational result
      //-------------------------------------------------------------------------
      always_ff @(posedge Clk or posedge Rst) begin
        if (Rst) begin
          pipe_valid[0]  <= 1'b0;
          pipe_first[0]  <= '0;
          pipe_found[0]  <= 1'b0;
        end else begin
          pipe_valid[0]  <= comb_valid;
          pipe_first[0]  <= comb_first_bit;
          pipe_found[0]  <= comb_found;
        end
      end

      //-------------------------------------------------------------------------
      // Pipeline Stages 1 to PlRegs_g: Propagate the result through each stage
      //-------------------------------------------------------------------------
      for (genvar i = 1; i <= PlRegs_g; i = i + 1) begin : pipeline_stages
        always_ff @(posedge Clk or posedge Rst) begin
          if (Rst) begin
            pipe_valid[i]  <= 1'b0;
            pipe_first[i]  <= '0;
            pipe_found[i]  <= 1'b0;
          end else begin
            pipe_valid[i]  <= pipe_valid[i-1];
            pipe_first[i]  <= pipe_first[i-1];
            pipe_found[i]  <= pipe_found[i-1];
          end
        end
      end

      //-------------------------------------------------------------------------
      // Final Output Stage: Register or directly drive the outputs
      //-------------------------------------------------------------------------
      if (OutReg_g == 1) begin : out_reg
        always_ff @(posedge Clk or posedge Rst) begin
          if (Rst) begin
            Out_Valid     <= 1'b0;
            Out_FirstBit  <= '0;
            Out_Found     <= 1'b0;
          end else begin
            Out_Valid     <= pipe_valid[PlRegs_g];
            Out_FirstBit  <= pipe_first[PlRegs_g];
            Out_Found     <= pipe_found[PlRegs_g];
          end
        end
      end
      else begin : no_out_reg
        assign Out_Valid     = pipe_valid[PlRegs_g];
        assign Out_FirstBit  = pipe_first[PlRegs_g];
        assign Out_Found     = pipe_found[PlRegs_g];
      end

    end
    else begin : no_pipeline
      // No pipelining: directly use the combinational result
      if (OutReg_g == 1) begin : out_reg
        always_ff @(posedge Clk or posedge Rst) begin
          if (Rst) begin
            Out_Valid     <= 1'b0;
            Out_FirstBit  <= '0;
            Out_Found     <= 1'b0;
          end else begin
            Out_Valid     <= comb_valid;
            Out_FirstBit  <= comb_first_bit;
            Out_Found     <= comb_found;
          end
        end
      end
      else begin : no_out_reg
        assign Out_Valid     = comb_valid;
        assign Out_FirstBit  = comb_first_bit;
        assign Out_Found     = comb_found;
      end
    end
  endgenerate

endmodule

