module digital_dice_roller(
    input  logic         clk,
    input  logic         reset_n,
    input  logic         button,
    output logic [2:0]   dice_value
);

    // Define FSM states
    typedef enum logic { IDLE, ROLLING } state_t;
    state_t state, next_state;

    // Internal 3-bit counter for dice values (valid range: 1 to 6)
    logic [2:0] counter;

    // FSM sequential process
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            // Asynchronous reset: go to IDLE and clear outputs
            state      <= IDLE;
            counter    <= 3'b000;
            dice_value <= 3'b000;
        end else begin
            case (state)
                IDLE: begin
                    if (button == 1) begin
                        // Transition to ROLLING state and initialize counter to 1
                        state      <= ROLLING;
                        counter    <= 3'b001;
                        dice_value <= 3'b001;
                    end else begin
                        // Remain in IDLE; keep the last dice value unchanged
                        state      <= IDLE;
                    end
                end

                ROLLING: begin
                    if (button == 0) begin
                        // Button released: return to IDLE while retaining the last counter value
                        state      <= IDLE;
                    end else begin
                        // Button remains HIGH: update counter in modulo-6 fashion
                        if (counter == 3'b110) // If counter == 6
                            counter <= 3'b001; // Wrap around to 1
                        else
                            counter <= counter + 1;
                        dice_value <= counter;
                    end
                end
            endcase
        end
    end

endmodule

input.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice value
) (
    input wire clk,
    input wire reset,  // Asynchronous reset signal
    input wire button,
    output reg [BIT_WIDTH-1:0] dice_value
);

  // State encoding
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;
  reg [BIT_WIDTH-1:0] counter;  // Counter to represent dice values

  // State transition and asynchronous reset logic (sequential)
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset to initial values when async_reset is asserted
      current_state <= IDLE;
      counter <= 1;
      dice_value <= 1;
    end else begin
      current_state <= next_state;
    end
  end

  // Next state logic and counter increment (combinational)
  always_comb begin
    next_state = current_state;

    case (current_state)
      IDLE: begin
        if (button) next_state = ROLLING;
      end

      ROLLING: begin
        if (!button) next_state = IDLE;
      end
    endcase
  end

  // Counter logic to simulate rolling dice values from 1 to DICE_MAX
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset counter and dice value when async_reset is asserted
      counter <= 1;
      dice_value <= 1;
    end else if (current_state == ROLLING) begin
      if (counter == DICE_MAX) counter <= 1;  // Reset to 1 after reaching DICE_MAX
      else counter <= counter + 1;
    end else if (current_state == IDLE) begin
      dice_value <= counter;  // Latch the final value
    end
  end
endmodule

