module dot_product (
    input               clk_in,                     // Clock signal
    input               reset_in,                   // Asynchronous Reset signal, Active HIGH
    input               start_in,                   // Start computation signal
    input       [6:0]   dot_length_in,              // Length of the dot product vectors
    input       [7:0]   vector_a_in,                // Input vector A (8-bit)
    input               vector_a_valid_in,          // Valid signal for vector A
    input       [15:0]  vector_b_in,                // Input vector B (16-bit)
    input               vector_b_valid_in,          // Valid signal for vector B
    output reg  [31:0]  dot_product_out,            // Output dot product result (32-bit)
    output reg          dot_product_valid_out       // Valid signal for dot product output
);

    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        COMPUTE = 2'b01,
        OUTPUT  = 2'b10
    } state_t;

    state_t state;

    // Registers for iteration and accumulation
    reg [6:0] counter;
    reg [31:0] acc;
    // Register to implement output latency (one extra cycle)
    reg out_delay;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in) begin
            state             <= IDLE;
            counter           <= 7'd0;
            acc               <= 32'd0;
            dot_product_out   <= 32'd0;
            dot_product_valid_out <= 1'b0;
            out_delay         <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    // Wait for start signal to initiate computation
                    if (start_in) begin
                        state   <= COMPUTE;
                        counter <= 7'd0;
                        acc     <= 32'd0;
                    end
                end
                COMPUTE: begin
                    // Process each element until the counter reaches the dynamic length
                    if (counter < dot_length_in) begin
                        // Only accumulate when both input valid signals are asserted
                        if (vector_a_valid_in && vector_b_valid_in)
                            acc <= acc + (vector_a_in * vector_b_in);
                        counter <= counter + 1;
                    end else begin
                        // Finished computing, move to OUTPUT state
                        state <= OUTPUT;
                        counter <= 7'd0; // Clear counter (not used further)
                    end
                end
                OUTPUT: begin
                    // Implement a two-cycle latency for the output.
                    // In the first cycle of OUTPUT state, set the delay flag.
                    // In the next cycle, assign the accumulated result and deassert the state.
                    if (out_delay == 1'b0) begin
                        out_delay <= 1'b1;
                    end else begin
                        dot_product_out     <= acc;
                        dot_product_valid_out <= 1'b1;
                        state               <= IDLE;
                        out_delay           <= 1'b0;
                    end
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule

input.rtl/dot_product.sv:
module dot_product (
    input               clk_in,                     // Clock signal
    input               reset_in,                   // Asynchronous Reset signal, Active HIGH
    input               start_in,                   // Start computation signal
    input       [6:0]   dot_length_in,              // Length of the dot product vectors
    input       [7:0]   vector_a_in,                // Input vector A (8-bit)
    input               vector_a_valid_in,          // Valid signal for vector A
    input       [15:0]  vector_b_in,                // Input vector B (16-bit)
    input               vector_b_valid_in,          // Valid signal for vector B
    output reg  [31:0]  dot_product_out,            // Output dot product result (32-bit)
    output reg          dot_product_valid_out       // Valid signal for dot product output
);

    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        COMPUTE = 2'b01,
        OUTPUT  = 2'b10
    } state_t;

    state_t state;
    reg [31:0] acc;
    reg [6:0] cnt;
    reg [6:0] dot_length_reg;
    reg vector_a_valid_in_prev;
    reg vector_b_valid_in_prev;

    always @(posedge clk_in or posedge reset_in) begin
        if (reset_in) begin
            state <= IDLE;
            acc <= 0;
            cnt <= 0;
            dot_product_out <= 0;
            dot_product_valid_out <= 0;
            dot_length_reg <= 0;
        end else begin
            case (state)
                IDLE: begin
                    dot_product_valid_out <= 0;
                    dot_length_reg <= dot_length_in;
                    if (start_in) begin
                        state <= COMPUTE;
                        acc <= 0;
                        cnt <= 0;
                    end
                end
                COMPUTE: begin
                    if (vector_a_valid_in && vector_b_valid_in) begin
                        acc <= acc + (vector_a_in * vector_b_in);
                        cnt <= cnt + 1;
                    end
                    if (cnt == dot_length_reg - 1) begin
                        state <= OUTPUT;
                    end else begin
                        state <= COMPUTE;
                    end
                end
                OUTPUT: begin
                    dot_product_out <= acc;
                    dot_product_valid_out <= 1;
                    state <= IDLE;
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/dot_product.sv:
module dot_product (
    input               clk_in,
    input               reset_in,
    input               start_in,
    input       [7:0]   dot_length_in,
    input       [31:0]  vector_a_in,
    input               vector_a_valid_in,
    input       [31:0]  vector_b_in,
    input               vector_b_valid_in,
    input               a_complex_in,
    input               b_complex_in,
    output reg  [31:0]  dot_product_out,
    output reg          dot_product_valid_out,
    output reg          dot_product_error_out
);

    // State definition
    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        COMPUTE = 2'b01,
        OUTPUT  = 2'b10,
        ERROR   = 2'b11
    } state_t;

    state_t state;

    // Registered inputs for robust handling
    reg [31:0] vector_a_in_reg;
    reg [31:0] vector_b_in_reg;
    reg        vector_a_valid_in_reg;
    reg        vector_b_valid_in_reg;
    reg        a_complex_in_reg;
    reg        b_complex_in_reg;
    reg [7:0]  dot_length_reg;

    // Accumulators and counters
    reg [31:0] acc;       // For real-only mode
    reg [31:0] acc_re;    // For real part in complex/mixed mode
    reg [31:0] acc_im;    // For imaginary part in complex/mixed mode
    reg [7:0]  cnt;       // Counter for processed elements
    reg [1:0]  latency_counter; // For 3-cycle output latency

    // Mode detection (using registered inputs)
    wire is_real_mode   = (~a_complex_in_reg) & (~b_complex_in_reg);
    wire is_complex_mode = a_complex_in_reg & b_complex_in_reg;
    wire is_mixed_mode  = a_complex_in_reg ^ b_complex_in_reg; // XOR

    always @(posedge clk_in or posedge reset_in) begin
        if (reset_in) begin
            state <= IDLE;
            vector_a_in_reg        <= 32'h0;
            vector_b_in_reg        <= 32'h0;
            vector_a_valid_in_reg  <= 1'b0;
            vector_b_valid_in_reg  <= 1'b0;
            a_complex_in_reg       <= 1'b0;
            b_complex_in_reg       <= 1'b0;
            dot_length_reg         <= 8'h0;
            acc                    <= 32'h0;
            acc_re                 <= 32'h0;
            acc_im                 <= 32'h0;
            cnt                    <= 8'h0;
            latency_counter        <= 2'b0;
            dot_product_out        <= 32'h0;
            dot_product_valid_out  <= 1'b0;
            dot_product_error_out  <= 1'b0;
        end else begin
            // Register inputs
            vector_a_in_reg        <= vector_a_in;
            vector_b_in_reg        <= vector_b_in;
            vector_a_valid_in_reg  <= vector_a_valid_in;
            vector_b_valid_in_reg  <= vector_b_valid_in;
            a_complex_in_reg       <= a_complex_in;
            b_complex_in_reg       <= b_complex_in;
            dot_length_reg         <= dot_length_in;

            case (state)
                IDLE: begin
                    dot_product_valid_out <= 1'b0;
                    dot_product_error_out <= 1'b0;
                    // Initialize accumulators based on mode
                    if (is_real_mode) begin
                        acc <= 32'h0;
                        cnt <= 8'h0;
                    end else if (is_complex_mode || is_mixed_mode) begin
                        acc_re <= 32'h0;
                        acc_im <= 32'h0;
                        cnt <= 8'h0;
                    end
                    if (start_in) begin
                        state <= COMPUTE;
                    end
                end

                COMPUTE: begin
                    // Error detection: if valid signals drop mid-computation
                    if (~vector_a_valid_in_reg || ~vector_b_valid_in_reg) begin
                        dot_product_error_out <= 1'b1;
                        state <= ERROR;
                    end else begin
                        // Perform computation based on mode
                        if (is_real_mode) begin
                            // For real-only mode, use lower 16 bits of each input
                            if (vector_a_valid_in_reg && vector_b_valid_in_reg) begin
                                acc <= acc + (vector_a_in_reg[15:0] * vector_b_in_reg[15:0]);
                                cnt <= cnt + 1;
                            end
                        end else if (is_complex_mode) begin
                            // For complex-only mode:
                            // A: real = lower 16 bits, imag = upper 16 bits; B similarly
                            acc_re <= acc_re + ((vector_a_in_reg[15:0] * vector_b_in_reg[15:0]) 
                                                - (vector_a_in_reg[31:16] * vector_b_in_reg[31:16]));
                            acc_im <= acc_im + ((vector_a_in_reg[15:0] * vector_b_in_reg[31:16]) 
                                                + (vector_a_in_reg[31:16] * vector_b_in_reg[15:0]));
                            cnt <= cnt + 1;
                        end else if (is_mixed_mode) begin
                            if (a_complex_in_reg && ~b_complex_in_reg) begin
                                // Mixed mode: A is complex, B is real.
                                acc_re <= acc_re + (vector_a_in_reg[15:0] * vector_b_in_reg[15:0]);
                                acc_im <= acc_im + (vector_a_in_reg[31:16] * vector_b_in_reg[15:0]);
                                cnt <= cnt + 1;
                            end else if (~a_complex_in_reg && b_complex_in_reg) begin
                                // Mixed mode: A is real, B is complex.
                                acc_re <= acc_re + (vector_a_in_reg[15:0] * vector_b_in_reg[15:0]);
                                acc_im <= acc_im + (vector_a_in_reg[15:0] * vector_b_in_reg[31:16]);
                                cnt <= cnt + 1;
                            end
                        end

                        // Transition to OUTPUT state when all elements are processed
                        if (cnt == dot_length_reg - 1) begin
                            state <= OUTPUT;
                        end else begin
                            state <= COMPUTE;
                        end
                    end
                end

                OUTPUT: begin
                    // Implement 3-cycle output latency
                    if (latency_counter < 2'd3) begin
                        latency_counter <= latency_counter + 1;
                        dot_product_valid_out <= 1'b0;
                    end else begin
                        // Latch the computed result based on mode
                        if (is_real_mode) begin
                            dot_product_out <= acc;
                        end else if (is_complex_mode || is_mixed_mode) begin
                            // Concatenate {Imaginary[15:0], Real[15:0]}
                            dot_product_out <= {acc_im[15:0], acc_re[15:0]};
                        end
                        dot_product_valid_out <= 1'b1;
                        state <= IDLE;
                    end
                end

                ERROR: begin
                    dot_product_error_out <= 1'b1;
                    dot_product_valid_out <= 1'b0;
                    dot_product_out <= 32'h00000000;
                    // Optionally reset computation after error detection
                    state <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

input.rtl/dot_product.sv:
module dot_product (
    input               clk_in,                     // Clock signal
    input               reset_in,                   // Asynchronous Reset signal, Active HIGH
    input               start_in,                   // Start computation signal
    input       [6:0]   dot_length_in,              // Length of the dot product vectors
    input       [7:0]   vector_a_in,                // Input vector A (8-bit)
    input               vector_a_valid_in,          // Valid signal for vector A
    input       [15:0]  vector_b_in,                // Input vector B (16-bit)
    input               vector_b_valid_in,          // Valid signal for vector B
    output reg  [31:0]  dot_product_out,            // Output dot product result (32-bit)
    output reg          dot_product_valid_out       // Valid signal for dot product output
);

    typedef enum logic [1:0] {
        IDLE    = 2'b00,
        COMPUTE = 2'b01,
        OUTPUT  = 2'b10
    } state_t;

    state_t state;
    reg [31:0] acc;
    reg [6:0] cnt;
    reg [6:0] dot_length_reg;
    reg vector_a_valid_in_prev;
    reg vector_b_valid_in_prev;

    always @(posedge clk_in or posedge reset_in) begin
        if (reset_in) begin
            state <= IDLE;
            acc <= 0;
            cnt <= 0;
            dot_product_out <= 0;
            dot_product_valid_out <= 0;
            dot_length_reg <= 0;
        end else begin
            case (state)
                IDLE: begin
                    dot_product_valid_out <= 0;
                    dot_length_reg <= dot_length_in;
                    if (start_in) begin
                        state <= COMPUTE;
                        acc <= 0;
                        cnt <= 0;
                    end
                end
                COMPUTE: begin
                    if (vector_a_valid_in && vector_b_valid_in) begin
                        acc <= acc + (vector_a_in * vector_b_in);
                        cnt <= cnt + 1;
                    end
                    if (cnt == dot_length_in - 1) begin
                        state <= OUTPUT;
                    end else begin
                        state <= COMPUTE;
                    end
                end
                OUTPUT: begin
                    dot_product_out <= acc;
                    dot_product_valid_out <= 1;
                    state <= IDLE;
                end
                default: state <= IDLE;
            endcase
        end
    end

    always @(posedge clk_in) begin
        if (state == OUTPUT) begin
            dot_product_valid_out <= 1; // Valid signal is HIGH in OUTPUT state
        end else begin
            dot_product_valid_out <= 0; // Valid signal is LOW in all other states
        end
    end

endmodule

