                // Recovery: once overload condition is cleared, resume normal operation
                if (!overload_detected) begin
                    next_state = IDLE;
                    current_floor_next = current_floor_reg;
                end else begin
                    next_state = OVERLOAD_HALT;
                    current_floor_next = current_floor_reg;
