output.rtl/ethernet_parser.v:
module ethernet_parser (
    input  wire         clk,
    input  wire         rst,
    input  wire         vld,
    input  wire         sof,
    input  wire [31:0]  data,
    input  wire         eof,
    output wire         ack,
    output wire [15:0]  field,
    output wire         field_vld
);

  // State encoding: 2-bit state machine
  localparam IDLE          = 2'b00;
  localparam EXTRACTING    = 2'b01;
  localparam DONE          = 2'b10;
  localparam FAIL_FINAL    = 2'b11;

  // Internal registers
  reg [1:0] state;              // Current state of the state machine
  reg [3:0] beat_cnt;           // Beat counter (4-bit)
  reg [15:0] temp_extracted_field; // Temporary storage for the extracted 16-bit field

  // Output assignments
  // ack is always high to indicate that data is always accepted.
  assign ack = 1'b1;
  // In IDLE and EXTRACTING (if extraction not yet performed), field and field_vld are deasserted.
  // In DONE state, field is driven by the captured value and field_vld is asserted.
  assign field    = (state == DONE) ? temp_extracted_field : 16'b0;
  assign field_vld = (state == DONE) ? 1'b1 : 1'b0;

  // Sequential logic: Synchronous process for state machine and registers
  always @(posedge clk) begin
    if (rst) begin
      // Reset: go to IDLE and clear all registers.
      state                   <= IDLE;
      beat_cnt                <= 4'd0;
      temp_extracted_field    <= 16'd0;
    end
    else if (eof) begin
      // End-of-frame: clear field_vld and reset to IDLE.
      state                   <= IDLE;
      beat_cnt                <= 4'd0;
      temp_extracted_field    <= 16'd0;
    end
    else begin
      case (state)
        IDLE: begin
          // Wait for the start-of-frame signal to initiate extraction.
          if (sof && vld) begin
            state             <= EXTRACTING;
            beat_cnt          <= 4'd0;
            temp_extracted_field <= 16'd0;
          end
          else begin
            state <= IDLE;
          end
        end

        EXTRACTING: begin
          // On each valid beat, increment the beat counter.
          if (vld) begin
            beat_cnt <= beat_cnt + 1;
            // Check if we have reached the 2nd beat (beat_cnt == 1).
            if (beat_cnt == 4'd1) begin
              // Capture the 2 most significant bytes from data.
              temp_extracted_field <= data[31:16];
              state <= DONE;
            end
            else begin
              state <= EXTRACTING;
            end
          end
          else begin
            state <= EXTRACTING;
          end
        end

        DONE: begin
          // In DONE state, output the captured field.
          // Remain in DONE until eof is asserted.
          state <= DONE;
        end

        FAIL_FINAL: begin
          // On eof, clear field_vld and return to IDLE.
          state <= IDLE;
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

output.rtl/apb_controller.sv:
module apb_controller (
  input  logic         clk,
  input  logic         reset_n,
  input  logic         select_a_i,
  input  logic         select_b_i,
  input  logic         select_c_i,
  input  logic [31:0]  addr_a_i,
  input  logic [31:0]  data_a_i,
  input  logic [31:0]  addr_b_i,
  input  logic [31:0]  data_b_i,
  input  logic [31:0]  addr_c_i,
  input  logic [31:0]  data_c_i,
  input  logic         apb_pready_i,
  output reg  logic     apb_psel_o,
  output reg  logic     apb_penable_o,
  output reg  logic     apb_pwrite_o,
  output reg  logic [31:0] apb_paddr_o,
  output reg  logic [31:0] apb_pwdata_o
);

  // State encoding: IDLE, SETUP, ACCESS
  typedef enum logic [1:0] {
    IDLE  = 2'd0,
    SETUP = 2'd1,
    ACCESS = 2'd2
  } state_t;

  state_t state, next_state;

  // Internal registers to hold the captured address and data for the transaction
  reg [31:0] addr_reg;
  reg [31:0] data_reg;

  // 4-bit timeout counter for the ACCESS phase
  reg [3:0] timeout_counter;

  // Flag to indicate an event was captured in IDLE
  reg event_pending;

  // Synchronous state register update and signal assignment
  always_ff @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      state            <= IDLE;
      timeout_counter  <= 4'd0;
      apb_psel_o       <= 1'b0;
      apb_penable_o    <= 1'b0;
      apb_pwrite_o     <= 1'b0;
      apb_paddr_o      <= 32'd0;
      apb_pwdata_o     <= 32'd0;
      event_pending    <= 1'b0;
      addr_reg         <= 32'd0;
      data_reg         <= 32'd0;
    end
    else begin
      case (state)
        IDLE: begin
          // Capture the event: only the highest priority event is processed.
          if (select_a_i) begin
            addr_reg    <= addr_a_i;
            data_reg    <= data_a_i;
            event_pending <= 1'b1;
          end
          else if (select_b_i) begin
            addr_reg    <= addr_b_i;
            data_reg    <= data_b_i;
            event_pending <= 1'b1;
          end
          else if (select_c_i) begin
            addr_reg    <= addr_c_i;
            data_reg    <= data_c_i;
            event_pending <= 1'b1;
          end
          else begin
            event_pending <= 1'b0;
          end

          // Deassert all APB signals in IDLE
          apb_psel_o    <= 1'b0;
          apb_penable_o <= 1'b0;
          apb_pwrite_o  <= 1'b0;
          apb_paddr_o   <= 32'd0;
          apb_pwdata_o  <= 32'd0;

          // Transition to SETUP if an event was captured; otherwise remain in IDLE.
          if (event_pending)
            state <= SETUP;
          else
            state <= IDLE;
        end

        SETUP: begin
          // Assert APB select and write signals, load address and data.
          apb_psel_o    <= 1'b1;
          apb_pwrite_o  <= 1'b1;
          apb_paddr_o   <= addr_reg;
          apb_pwdata_o  <= data_reg;
          // Keep apb_penable_o deasserted during SETUP.
          apb_penable_o <= 1'b0;
          // Reset timeout counter for the new transaction.
          timeout_counter <= 4'd0;
          // Move to ACCESS state in the next cycle.
          state <= ACCESS;
        end

        ACCESS: begin
          // Assert apb_penable_o to indicate the transaction is in progress.
          apb_psel_o    <= 1'b1;
          apb_pwrite_o  <= 1'b1;
          apb_paddr_o   <= addr_reg;
          apb_pwdata_o  <= data_reg;
          apb_penable_o <= 1'b1;

          // Check if the peripheral is ready.
          if (apb_pready_i) begin
            // Transaction complete; return to IDLE next cycle.
            state <= IDLE;
          end
          else begin
            // Increment the timeout counter each cycle.
            if (timeout_counter == 4'd15) begin
              // Timeout reached: abort the transaction and return to IDLE.
              state <= IDLE;
            end
            else begin
              timeout_counter <= timeout_counter + 1;
              state <= ACCESS;
            end
          end
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

output.rtl/factorial.sv:
module computes the factorial of a 5-bit input number.
// Ports:
//   clk       : Clock input.
//   arst_n    : Asynchronous active low reset.
//   num_in    : 5-bit input number (0 to 31) whose factorial is to be computed.
//   start     : Start signal to initiate computation (only accepted in IDLE).
//   busy      : Indicates that the design is busy computing.
//   fact      : 64-bit output holding the computed factorial.
//   done      : Asserted for one cycle in DONE state to indicate computation complete.

module factorial(
    input  logic         clk,
    input  logic         arst_n,
    input  logic [4:0]   num_in,
    input  logic         start,
    output logic         busy,
    output logic [63:0]  fact,
    output logic         done
);

    // FSM state definitions
    typedef enum logic [1:0] {
        IDLE = 2'b00,
        BUSY = 2'b01,
        DONE = 2'b10
    } state_t;

    state_t state, next_state;

    // Registers for factorial computation
    logic [63:0] product;  // holds the running product
    logic [4:0]  counter;  // counts the number of multiplications performed

    // Sequential block: update state and computation registers on clock edge or asynchronous reset
    always_ff @(posedge clk or negedge arst_n) begin
        if (!arst_n) begin
            state      <= IDLE;
            product    <= 64'd1;
            counter    <= 5'd0;
        end else begin
            state <= next_state;
            case (next_state)
                IDLE: begin
                    // Prepare for a new computation: reset product and counter
                    product <= 64'd1;
                    counter <= 5'd0;
                end
                BUSY: begin
                    // Multiply product by (counter + 1) each cycle.
                    // When counter == num_in, the loop ends.
                    product <= product * (counter + 1);
                    counter <= counter + 1;
                end
                DONE: begin
                    // Hold the computed result.
                    product <= product;
                    counter <= counter;
                end
                default: begin
                    product <= product;
                    counter <= counter;
                end
            endcase
        end
    end

    // Combinational block: determine next state and output signals
    always_comb begin
        // Default assignments
        next_state = state;
        busy       = 1'b0;
        done       = 1'b0;
        fact       = product;

        case (state)
            IDLE: begin
                // Accept new input only if start is asserted.
                if (start)
                    next_state = BUSY;
                else
                    next_state = IDLE;
            end

            BUSY: begin
                // Continue multiplying until counter reaches num_in.
                if (counter < num_in)
                    next_state = BUSY;
                else
                    next_state = DONE;
            end

            DONE: begin
                // Stay in DONE for one cycle then return to IDLE.
                next_state = IDLE;
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

endmodule

