      end else if (i_ce) begin
        left_idx <= write_idx;
        right_idx <= write_idx - (HALFTAPS[LGNMEM-1:0]) + 1;
      end else if (clk_en || !last_data_warn) begin
        left_idx <= left_idx - 2;
        right_idx <= right_idx + 2;
      end
    end

    initial tap_idx = 0;
    always @(posedge i_clk) begin
      if (i_reset)
         tap_idx <= 0;
      else if (clk_en)
         tap_idx <= 0;
      else if (!last_tap_warn)
         tap_idx <= tap_idx + 1;
    end

    initial clk_en = 1'b0;
    always @(posedge i_clk) begin
      clk_en <= (i_ce && !i_reset);
    end

    initial begin
        sample_left  = 0;
        sample_right = 0;
    end

    always @(posedge i_clk) begin
      sample_left  <= dmem1_messy[left_idx];
      sample_right <= dmem2_messy[right_idx];
    end

    // --- Data Enable Update ---
    initial data_en = 1'b0;
    always @(posedge i_clk)
       data_en <= (clk_en && !i_reset);

    // --- Coefficient Read and Data Sum Computation ---
    reg [TW-1:0] current_coef;
    initial current_coef = 0;
    always @(posedge i_clk)
       current_coef <= coef_mem_messy[tap_idx[LGNCOEF-1:0]];

    initial sum_data = 0;
    always @(posedge i_clk) begin
      if (i_reset)
         sum_data <= 0;
      else if (OPT_HILBERT)
         sum_data <= sample_left - sample_right;
      else
         sum_data <= sample_left + sample_right;
    end

    // --- Summation Enable ---
    initial sum_en = 1'b0;
    always @(posedge i_clk)
       sum_en <= (data_en && !i_reset);

    // --- Multiply Operation ---
    initial mult_result = 0;
    always @(posedge i_clk)
       mult_result <= current_coef * sum_data;

    wire [OW-1:0] mid_prod;
    generate
      if (OPT_HILBERT) begin : NO_MIDPOINT
         assign mid_prod = 0;
      end else begin : GEN_MIDPOINT
         reg [OW-1:0] mid_prod_reg;
         initial mid_prod_reg = 0;
         always @(posedge i_clk) begin
            if (i_reset)
               mid_prod_reg <= 0;
            else if (clk_en)
               mid_prod_reg <= { {(OW-IW-TW+1){mid_sample_messy[IW-1]}}, 
                                  mid_sample_messy, {(TW-1){1'b0}} }
                              - { {(OW-IW){mid_sample_messy[IW-1]}}, 
                                  mid_sample_messy };
         end
         assign mid_prod = mid_prod_reg;
      end
    endgenerate

    // --- Accumulation ---
    initial acc_result = 0;
    always @(posedge i_clk) begin
      if (i_reset)
         acc_result <= 0;
      else if (sum_en)
         acc_result <= mid_prod;
      else if (messy_flag[3])
         acc_result <= acc_result + { {(OW-(IW+TW)){mult_result[IW+TW-1]}}, mult_result };
    end

    // --- Output Assignments ---
    initial o_result = 0;
    always @(posedge i_clk)
       if (sum_en)
          o_result <= acc_result;

    // --- Output Clock Enable Update ---
    initial o_ce = 1'b0;
    always @(posedge i_clk)
       o_ce <= (sum_en && !i_reset);

endmodule

output.rtl/hamming_code_tx_for_4bit.sv:
module hamming_code_tx_for_4bit (
    input  logic [3:0] data_in,
    output logic [7:0] data_out
);

    // data_out[0] is a redundant bit fixed to 0.
    assign data_out[0] = 1'b0;

    // Calculate parity bits using XOR for even parity.
    // data_out[1]: Parity for positions (data_in[0], data_in[1], data_in[3])
    assign data_out[1] = data_in[0] ^ data_in[1] ^ data_in[3];

    // data_out[2]: Parity for positions (data_in[0], data_in[2], data_in[3])
    assign data_out[2] = data_in[0] ^ data_in[2] ^ data_in[3];

    // data_out[3]: Data bit (data_in[0])
    assign data_out[3] = data_in[0];

    // data_out[4]: Parity for positions (data_in[1], data_in[2], data_in[3])
    assign data_out[4] = data_in[1] ^ data_in[2] ^ data_in[3];

    // data_out[5]: Data bit (data_in[1])
    assign data_out[5] = data_in[1];

    // data_out[6]: Data bit (data_in[2])
    assign data_out[6] = data_in[2];

    // data_out[7]: Data bit (data_in[3])
    assign data_out[7] = data_in[3];

endmodule

output.rtl/hamming_code_receiver.sv:
module hamming_code_receiver (
    input  wire [7:0] data_in,
    output wire [3:0] data_out
);

  // Calculate syndrome bits for even parity error detection
  // c3: XOR of bits at positions with LSB = 1: data_in[1], data_in[3], data_in[5], data_in[7]
  wire c3 = data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];

  // c2: XOR of bits at positions with second LSB = 1: data_in[2], data_in[3], data_in[6], data_in[7]
  wire c2 = data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];

  // c1: XOR of bits at positions with MSB = 1: data_in[4], data_in[5], data_in[6], data_in[7]
  wire c1 = data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  // Combine syndrome bits: {c1, c2, c3}
  wire [2:0] syndrome = {c1, c2, c3};

  // Correct the error if detected.
  // If syndrome is nonzero, the bit at that position (1-indexed) in data_in is flipped.
  // Note: syndrome == 3'b000 indicates an error in the redundant bit (data_in[0]),
  //       so no correction is applied to the 7-bit Hamming code.
  wire [7:0] corrected_data;
  assign corrected_data = data_in ^ ((syndrome != 3'b000) ? (8'h01 << syndrome) : 8'h00);

  // Extract the 4 data bits from the corrected data.
  // According to the specification, data bits are located at:
  //   data_in[3] -> data bit 1
  //   data_in[5] -> data bit 2
  //   data_in[6] -> data bit 3
  //   data_in[7] -> data bit 4
  assign data_out = {corrected_data[7], corrected_data[6], corrected_data[5], corrected_data[3]};

endmodule

