module interrupt_controller 
#(
    parameter NUM_INTERRUPTS = 4, 
    parameter ADDR_WIDTH = 8
)
(
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,
    output logic [$clog2(NUM_INTERRUPTS)-1:0] interrupt_idx,
    input  logic [NUM_INTERRUPTS-1:0] priority_map_value [NUM_INTERRUPTS-1:0],
    input  logic                      priority_map_update,
    input  logic [ADDR_WIDTH-1:0]     vector_table_value [NUM_INTERRUPTS-1:0],
    input  logic                      vector_table_update,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_mask_value,
    input  logic                      interrupt_mask_update
);

    // Internal registers for dynamic updates and state
    reg [NUM_INTERRUPTS-1:0] priority_map_reg [0:NUM_INTERRUPTS-1];
    reg [ADDR_WIDTH-1:0]     vector_table_reg [0:NUM_INTERRUPTS-1];
    reg [NUM_INTERRUPTS-1:0] interrupt_mask_reg;
    reg [NUM_INTERRUPTS-1:0] pending_interrupts;
    reg [$clog2(NUM_INTERRUPTS)-1:0] current_interrupt_idx;
    reg cpu_interrupt_reg;

    // Next interrupt to be serviced (combinational selection)
    reg [$clog2(NUM_INTERRUPTS)-1:0] next_interrupt;

    // Combinational block: Select the highest priority pending interrupt that is not masked.
    // Lower numeric value in priority_map_reg indicates higher priority.
    always_comb begin
        next_interrupt = 0; // Default: no interrupt selected.
        for (int i = 0; i < NUM_INTERRUPTS; i++) begin
            if (pending_interrupts[i] && ~interrupt_mask_reg[i]) begin
                // If no current candidate or found a lower priority value, select this interrupt.
                if (next_interrupt == 0 || priority_map_reg[i] < priority_map_reg[next_interrupt])
                    next_interrupt = i;
            end
        end
    end

    // Sequential logic: Update internal state, registers, and select the interrupt to service.
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Reset all registers to default values.
            pending_interrupts       <= '0;
            current_interrupt_idx    <= 0;
            cpu_interrupt_reg        <= 0;
            // Initialize priority map: sequential priorities (lower number = higher priority)
            for (int i = 0; i < NUM_INTERRUPTS; i++) begin
                priority_map_reg[i] <= i;
            end
            // Initialize vector table: assign vectors as multiples of 4.
            for (int i = 0; i < NUM_INTERRUPTS; i++) begin
                vector_table_reg[i] <= i * 4;
            end
            // Default interrupt mask: 0 (no interrupts masked).
            interrupt_mask_reg <= '0;
        end
        else begin
            // Dynamic update of registers if update signals are asserted.
            if (priority_map_update) begin
                for (int i = 0; i < NUM_INTERRUPTS; i++) begin
                    priority_map_reg[i] <= priority_map_value[i];
                end
            end
            if (vector_table_update) begin
                for (int i = 0; i < NUM_INTERRUPTS; i++) begin
                    vector_table_reg[i] <= vector_table_value[i];
                end
            end
            if (interrupt_mask_update) begin
                interrupt_mask_reg <= interrupt_mask_value;
            end

            // Update pending interrupts: OR in new requests.
            pending_interrupts <= pending_interrupts | interrupt_requests;

            // If the CPU acknowledges servicing the current interrupt, clear it.
            if (cpu_ack && (current_interrupt_idx != 0)) begin
                pending_interrupts <= pending_interrupts & ~(1 << current_interrupt_idx);
                current_interrupt_idx <= 0;
            end
            // If no interrupt is currently being serviced, select the next pending interrupt.
            else if (current_interrupt_idx == 0) begin
                current_interrupt_idx <= next_interrupt;
            end

            // Assert cpu_interrupt if an interrupt is being serviced.
            cpu_interrupt_reg <= (current_interrupt_idx != 0);
        end
    end

    // Output assignments.
    assign cpu_interrupt      = cpu_interrupt_reg;
    assign interrupt_service  = (current_interrupt_idx != 0) ? (1 << current_interrupt_idx) : '0;
    assign interrupt_vector   = (current_interrupt_idx != 0) ? vector_table_reg[current_interrupt_idx] : '0;
    assign interrupt_idx      = current_interrupt_idx;

endmodule

output.rtl/pic_starvation_prevention.sv:
module interrupt_controller (
    input  wire         clk,
    input  wire         rst_n,
    input  wire         reset_interrupts,
    input  wire [9:0]   interrupt_requests,
    input  wire         interrupt_ack,
    input  wire         interrupt_trig,
    input  wire [9:0]   interrupt_mask,
    input  wire [3:0]   priority_override,
    input  wire [3:0]   override_interrupt_id,
    input  wire         priority_override_en,
    output reg  [3:0]   interrupt_id,
    output reg          interrupt_valid,
    output reg [9:0]    interrupt_status,
    output reg [9:0]    missed_interrupts,
    output reg          starvation_detected
);

    // Define starvation threshold (cycles)
    parameter STARVATION_THRESHOLD = 5;

    // State encoding
    localparam [2:0] 
        IDLE           = 3'b000,
        PRIORITY_CALC  = 3'b001,
        SERVICE_PREP   = 3'b010,
        SERVICING      = 3'b011,
        COMPLETION     = 3'b100,
        ERROR          = 3'b111;

    // State and internal registers
    reg [2:0] current_state, next_state;
    reg [9:0] pending_interrupts;
    // Use 5-bit counters to accommodate STARVATION_THRESHOLD
    reg [4:0] wait_counters [0:9];
    reg [4:0] effective_priority [0:9];
    reg [9:0] active_mask;
    reg [3:0] service_timer;
    reg timeout_error;
    reg [3:0] next_interrupt_id;
    reg [4:0] max_priority;

    // Main state machine and logic
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            // Asynchronous reset: clear all registers
            current_state          <= IDLE;
            pending_interrupts     <= 10'b0;
            wait_counters          <= '{default: 5'd0};
            effective_priority     <= '{default: 5'd0};
            interrupt_status       <= 10'b0;
            missed_interrupts      <= 10'b0;
            starvation_detected    <= 1'b0;
            service_timer          <= 4'd0;
            timeout_error          <= 1'b0;
            interrupt_id           <= 4'd0;
            interrupt_valid        <= 1'b0;
        end else if (reset_interrupts) begin
            // Synchronous reset of interrupt-related registers
            pending_interrupts     <= 10'b0;
            wait_counters          <= '{default: 5'd0};
            effective_priority     <= '{default: 5'd0};
            interrupt_status       <= 10'b0;
            missed_interrupts      <= 10'b0;
            starvation_detected    <= 1'b0;
            service_timer          <= 4'd0;
            timeout_error          <= 1'b0;
            interrupt_id           <= 4'd0;
            interrupt_valid        <= 1'b0;
        end else begin
            // Update active mask from input
            active_mask <= interrupt_mask;

            // Update pending_interrupts and wait_counters based on new requests and mask
            for (int i = 0; i < 10; i = i + 1) begin
                if (interrupt_requests[i] && !interrupt_mask[i]) begin
                    pending_interrupts[i] <= 1'b1;
                    wait_counters[i]      <= wait_counters[i] + 1;
                end else begin
                    // If not requested, ensure wait counter is reset
                    wait_counters[i] <= 5'd0;
                end
            end

            // Update effective priority for each pending interrupt.
            // Base priority is assumed to be the interrupt index.
            // Priority override is applied if enabled for the specific interrupt.
            for (int i = 0; i < 10; i = i + 1) begin
                if (pending_interrupts[i]) begin
                    if (priority_override_en && (override_interrupt_id == i))
                        effective_priority[i] <= priority_override;
                    else
                        effective_priority[i] <= i + wait_counters[i];
                end else begin
                    effective_priority[i] <= 5'd0;
                end
            end

            // State Machine Transitions
            case (current_state)
                IDLE: begin
                    // If any interrupt is pending, move to priority calculation
                    if (|pending_interrupts)
                        current_state <= PRIORITY_CALC;
                    else
                        current_state <= IDLE;
                end

                PRIORITY_CALC: begin
                    // Determine the highest priority interrupt
                    max_priority   <= 5'd0;
                    next_interrupt_id <= 4'd0;
                    for (int i = 0; i < 10; i = i + 1) begin
                        if (pending_interrupts[i]) begin
                            if (effective_priority[i] > max_priority) begin
                                max_priority         <= effective_priority[i];
                                next_interrupt_id    <= i;
                            end
                        end
                    end

                    // Check for starvation: if any wait counter exceeds threshold, assert starvation_detected
                    for (int i = 0; i < 10; i = i + 1) begin
                        if (wait_counters[i] >= STARVATION_THRESHOLD)
                            starvation_detected <= 1'b1;
                    end

                    // Transition to service preparation
                    current_state <= SERVICE_PREP;
                end

                SERVICE_PREP: begin
                    // Prepare to service the selected interrupt
                    interrupt_id    <= next_interrupt_id;
                    interrupt_valid <= 1'b1;
                    // Set the corresponding bit in interrupt_status
                    interrupt_status[next_interrupt_id] <= 1'b1;
                    // Transition to servicing state
                    current_state <= SERVICING;
                end

                SERVICING: begin
                    // Wait for the system to acknowledge the interrupt
                    if (interrupt_ack) begin
                        service_timer <= 4'd0;
                        current_state <= COMPLETION;
                    end else begin
                        service_timer <= service_timer + 1;
                        // Timeout detection: if service_timer exceeds a threshold, go to ERROR state
                        if (service_timer >= 4'd8) begin
                            timeout_error <= 1'b1;
                            current_state <= ERROR;
                        end
                    end
                end

                COMPLETION: begin
                    // Clear the serviced interrupt from pending list and reset its counters
                    pending_interrupts[next_interrupt_id] <= 1'b0;
                    wait_counters[next_interrupt_id]      <= 5'd0;
                    effective_priority[next_interrupt_id] <= 5'd0;
                    // Clear the serviced bit in interrupt_status
                    interrupt_status[next_interrupt_id] <= 1'b0;
                    // Deassert interrupt_valid
                    interrupt_valid <= 1'b0;
                    // Return to idle state
                    current_state <= IDLE;
                end

                ERROR: begin
                    // Handle error: clear all pending interrupts and related registers
                    pending_interrupts     <= 10'b0;
                    wait_counters          <= '{default: 5'd0};
                    effective_priority     <= '{default: 5'd0};
                    timeout_error          <= 1'b0;
                    current_state          <= IDLE;
                end

                default: current_state <= IDLE;
            endcase
        end
    end

endmodule

