                        cycle_counter <= cycle_counter + 1;
                     end
                  end else begin
                     cycle_counter <= 0; // Error condition.
                  end
               end
            end
            finish: begin
               // No counter updates in finish state.
            end
            default: cycle_counter <= 0;
         endcase
      end
   end

   //-------------------------------------------------------------------------
   // Output Register Logic: 1-cycle latency for decoded frame.
   //-------------------------------------------------------------------------
