        end else if (start && !active) begin
            active <= 1;
            stage <= 0;
            done <= 0;
            Sum <= 0;
        end else if (active) begin
            if (stage == 4) begin
                Sum <= sum_comb;    
                done <= 1;
                active <= 0;
            end else begin
                stage <= stage + 1;
            end
        end else if (!start) begin
            done <= 0;
        end
    end

    always_comb begin
        G1 = 0; G2 = 0; G3 = 0;
        P1 = 0; P2 = 0; P3 = 0;
        carry = 0;
