module lfsr_8bit(input clock,reset,input [7:0] lfsr_seed, output reg [7:0] lfsr_out);
	logic q1,q2,q3;
	//Primitive polynomial considered for 8-bit Linear Feedback Shift Register (LFSR) with Galois configuration is x^8+x^6+x^5+x+1 

	//Internal XORing based on primitive polynomial
	assign q1 = lfsr_out[6] ^ lfsr_out[0];
	assign q2 = lfsr_out[5] ^ lfsr_out[0];
	assign q3 = lfsr_out[1] ^ lfsr_out[0];

	always_ff @(posedge clock or negedge reset)
	begin
		if (!reset)
			lfsr_out <= lfsr_seed;//If reset is at logic LOW, the initial seed will be loaded into LFSR's 8-bit output
		else
			lfsr_out <= {lfsr_out[0],lfsr_out[7],q1,q2,lfsr_out[4],lfsr_out[3],lfsr_out[2],q3};//Shift register based on the primitive polynomial
	end
endmodule

output.rtl/lfsr_8bit.sv:
module lfsr_8bit(input clock, input reset, input [7:0] lfsr_seed, output reg [7:0] lfsr_out);
    // Fibonacci configuration LFSR based on primitive polynomial: x^8 + x^6 + x^5 + x + 1
    // Tap positions: lfsr_out[6], lfsr_out[5], lfsr_out[1], and lfsr_out[0]
    // On every positive clock edge (when reset is high), the feedback bit is computed and shifted into the MSB.
    always_ff @(posedge clock or negedge reset) begin
        if (!reset)
            lfsr_out <= lfsr_seed;  // Load seed when asynchronous reset is active (logic LOW)
        else begin
            // Compute feedback bit as XOR of tapped bits
            bit [0] feedback = lfsr_out[6] ^ lfsr_out[5] ^ lfsr_out[1] ^ lfsr_out[0];
            // Shift right: new MSB is the feedback, and the rest shift right by one bit
            lfsr_out <= {feedback, lfsr_out[7:1]};
        end
    end
endmodule

output.rtl/load_store_unit.sv:
module load_store_unit (
  input  wire         clk,
  input  wire         rst_n,
  // Data-Cache Interface
  output reg          dmem_req_o,
  input  wire         dmem_gnt_i,
  output reg [31:0]   dmem_req_addr_o,
  output reg          dmem_req_we_o,
  output reg [3:0]    dmem_req_be_o,
  output reg [31:0]   dmem_req_wdata_o,
  input  wire         dmem_rvalid_i,
  input  wire [31:0]  dmem_rsp_rdata_i,
  // Execution Stage Interface
  input  wire         ex_if_req_i,
  input  wire         ex_if_we_i,
  input  wire [1:0]   ex_if_type_i,
  input  wire [31:0]  ex_if_wdata_i,
  input  wire [31:0]  ex_if_addr_base_i,
  input  wire [31:0]  ex_if_addr_offset_i,
  output reg          ex_if_ready_o,
  // Writeback Interface
  output reg [31:0]   wb_if_rdata_o,
  output reg          wb_if_rvalid_o
);

  // State encoding
  localparam IDLE      = 2'b00,
             SENT      = 2'b01,
             WAIT_LOAD = 2'b10;

  // Internal registers to hold latched request information
  reg [1:0] state;
  reg [31:0] eff_addr_reg;       // Latched effective address
  reg [1:0]  type_reg;           // Latched data type
  reg        is_store_reg;       // Latched store flag (1 = store, 0 = load)
  reg [31:0] req_wdata_reg;      // Latched write data (for store)
  reg [3:0]  be_mask_reg;        // Computed byte enable mask
  reg [31:0] rdata_reg;          // Latched read data (for load)

  // Compute effective address (combinationally)
  wire [31:0] eff_addr;
  assign eff_addr = ex_if_addr_base_i + ex_if_addr_offset_i;

  // Alignment check based on data type and effective address.
  // For byte access (ex_if_type_i == 2'b00): always valid.
  // For halfword access (ex_if_type_i == 2'b01): valid if LSBs are 00 or 10.
  // For word access (ex_if_type_i == 2'b10): valid only if LSBs are 00.
  wire valid_align;
  assign valid_align = (ex_if_type_i == 2'b00) ||
                       ((ex_if_type_i == 2'b01) && ((eff_addr[1:0] == 2'b00) || (eff_addr[1:0] == 2'b10))) ||
                       ((ex_if_type_i == 2'b10) && (eff_addr[1:0] == 2'b00));

  // Main state machine
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      state              <= IDLE;
      ex_if_ready_o      <= 1'b1;
      dmem_req_o         <= 1'b0;
      dmem_req_addr_o    <= 32'b0;
      dmem_req_we_o      <= 1'b0;
      dmem_req_be_o      <= 4'b0;
      dmem_req_wdata_o   <= 32'b0;
      wb_if_rvalid_o     <= 1'b0;
      wb_if_rdata_o      <= 32'b0;
    end
    else begin
      case (state)
        IDLE: begin
          // In IDLE, LSU is ready for a new request.
          ex_if_ready_o      <= 1'b1;
          dmem_req_o         <= 1'b0;
          dmem_req_addr_o    <= 32'b0;
          dmem_req_we_o      <= 1'b0;
          dmem_req_be_o      <= 4'b0;
          dmem_req_wdata_o   <= 32'b0;
          wb_if_rvalid_o     <= 1'b0;
          wb_if_rdata_o      <= 32'b0;

          // Accept new request only if EX stage is requesting and alignment is valid.
          if (ex_if_req_i && ex_if_ready_o && valid_align) begin
            // Latch the effective address and transaction details.
            eff_addr_reg    <= eff_addr;
            type_reg        <= ex_if_type_i;
            is_store_reg    <= ex_if_we_i;
            req_wdata_reg   <= ex_if_wdata_i;

            // Compute the byte enable mask based on the type and effective address.
            case (type_reg)
              2'b00: begin
                // Byte access: enable only the byte at offset eff_addr[1:0]
                be_mask_reg <= 4'b0001 << eff_addr_reg[1:0];
              end
              2'b01: begin
                // Halfword access: enable two consecutive bytes.
                if (eff_addr_reg[1:0] == 2'b00)
                  be_mask_reg <= 4'b0011;  // Lower two bytes
                else if (eff_addr_reg[1:0] == 2'b10)
                  be_mask_reg <= 4'b1100;  // Upper two bytes
                else
                  be_mask_reg <= 4'b0000;  // Misaligned (should not occur due to valid_align)
              end
              2'b10: begin
                // Word access: enable all 4 bytes.
                if (eff_addr_reg[1:0] == 2'b00)
                  be_mask_reg <= 4'b1111;
                else
                  be_mask_reg <= 4'b0000;  // Misaligned access
              end
              default: be_mask_reg <= 4'b0000;
            endcase

            state <= SENT;
          end
        end

        SENT: begin
          // Drive the data-cache interface signals.
          ex_if_ready_o      <= 1'b0;
          dmem_req_o         <= 1'b1;
          dmem_req_addr_o    <= eff_addr_reg;
          dmem_req_we_o      <= is_store_reg;
          dmem_req_be_o      <= be_mask_reg;
          dmem_req_wdata_o   <= req_wdata_reg;
          wb_if_rvalid_o     <= 1'b0;
          wb_if_rdata_o      <= 32'b0;

          // For store transactions, wait for dmem_gnt_i.
          if (is_store_reg) begin
            if (dmem_gnt_i)
              state <= IDLE;
          end
          // For load transactions, wait for dmem_rvalid_i.
          else begin
            if (dmem_rvalid_i) begin
              rdata_reg <= dmem_rsp_rdata_i;
              state <= WAIT_LOAD;
            end
          end
        end

        WAIT_LOAD: begin
          // Provide the read data to the writeback stage.
          ex_if_ready_o      <= 1'b0;
          dmem_req_o         <= 1'b0;
          dmem_req_addr_o    <= 32'b0;
          dmem_req_we_o      <= 1'b0;
          dmem_req_be_o      <= 4'b0;
          dmem_req_wdata_o   <= 32'b0;
          wb_if_rvalid_o     <= 1'b1;
          wb_if_rdata_o      <= rdata_reg;
          state <= IDLE;
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

input.rtl/load_store_unit.sv:
module load_store_unit (
    input  logic                 clk,
    input  logic                 rst_n,

    // EX stage interface
    input  logic                 ex_if_req_i,           // LSU request
    input  logic                 ex_if_we_i,            // Write enable: 0 (load), 1 (store)
    input  logic     [ 1:0]      ex_if_type_i,          // Data type: 0x2 (word), 0x1 (halfword), 0x0 (byte)
    input  logic     [31:0]      ex_if_wdata_i,         // Data to write to memory
    input  logic     [31:0]      ex_if_addr_base_i,     // Base address
    input  logic     [31:0]      ex_if_addr_offset_i,   // Offset address
    output logic                 ex_if_ready_o    ,

    // Writeback stage interface
    output logic     [31:0]      wb_if_rdata_o,         // Requested data
    output logic                 wb_if_rvalid_o,        // Requested data valid

    // Data memory (DMEM) interface
    output logic                 dmem_req_o,
    input  logic                 dmem_gnt_i,
    output logic     [31:0]      dmem_req_addr_o,
    output logic                 dmem_req_we_o,
    output logic     [ 3:0]      dmem_req_be_o,
    output logic     [31:0]      dmem_req_wdata_o,
    input  logic     [31:0]      dmem_rsp_rdata_i,
    input  logic                 dmem_rvalid_i
    );

  // Internal signals
  logic ex_req_fire;
  logic dmem_req_we_q;
  logic [31:0] data_addr_int;
  logic misaligned_addr;
  logic [3:0] dmem_be, dmem_req_be_q;

  logic busy_q;  // Sticky busy bit: Set with EX req and cleared with DMEM response
  logic dmem_req_q ;




  logic [31:0] dmem_req_wdata_q;
  logic [31:0] dmem_req_addr_q;

  logic [31:0] wb_if_rdata_q;
  logic wb_if_rvalid_q;

  // Address calculation
  assign data_addr_int = ex_if_addr_base_i + ex_if_addr_offset_i;

  // EX request fire condition
  assign ex_req_fire = ex_if_req_i && !busy_q && !misaligned_addr;
  assign ex_if_ready_o = !busy_q;

  ///////////////////////////////// Byte Enable Generation ////////////////////////////////
  always_comb begin
    misaligned_addr = 1'b0;
    dmem_be = 4'b0000;
    case (ex_if_type_i)  // 0x2 (word), 0x1 (halfword), 0x0 (byte)
      2'b00: begin  // Writing a byte
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0001;
            2'b01:   dmem_be = 4'b0010;
            2'b10:   dmem_be = 4'b0100;
            2'b11:   dmem_be = 4'b1000;
            default: dmem_be = 4'b0000;
          endcase
      end

      2'b01: begin  // Writing a half-word
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0011;
            2'b10:   dmem_be = 4'b1100;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end

      2'b10: begin  // Writing a word
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b1111;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end
      default: begin
          dmem_be = 4'b0000;
          misaligned_addr = 1'b1;
      end 
    endcase
  end


  ///////////////////////////////// dmem_req ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      dmem_req_q <= 1'b0;
      dmem_req_addr_q <= '0;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end else if (ex_req_fire) begin
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= ex_if_we_i;
      dmem_req_be_q <= dmem_be ;
      dmem_req_wdata_q <= ex_if_wdata_i ;
    end else if (dmem_req_q && dmem_gnt_i) begin
      dmem_req_q <= 1'b0;  // request granted
      dmem_req_addr_q <= '0 ;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end
  end


  ///////////////////////////////// DMEM Request Interface ////////////////////////////////
  always_comb begin : dmem_req
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  ///////////////////////////////// Read Response Handling ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      wb_if_rdata_q   <= 32'b0;
      wb_if_rvalid_q  <= 1'b0;
    end else if (dmem_rvalid_i) begin
      wb_if_rdata_q   <= dmem_rsp_rdata_i;
      wb_if_rvalid_q  <= 1'b1;
    end else begin
      wb_if_rvalid_q  <= 1'b0;
    end
  end

  assign wb_if_rdata_o =  wb_if_rdata_q;
  assign wb_if_rvalid_o = wb_if_rvalid_q;

  ///////////////////////////////// Busy Logic ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      busy_q <= 1'b0;
    end else if (ex_req_fire) begin
      busy_q <= 1'b1;
    end else if (dmem_req_we_q && dmem_gnt_i) begin
      busy_q <= 1'b0;  // Write request granted
    end else if (!dmem_req_we_q && dmem_rvalid_i) begin
      busy_q <= 1'b0;  // Read request response received
    end
  end

endmodule

