output.rtl/moving_average.v:
module moving_average (
    input         clk,
    input         reset,
    input  [11:0] data_in,
    output reg [11:0] data_out
);

  // Circular buffer to hold the last 8 samples
  reg [11:0] buffer [0:7];
  // 3-bit pointer to index into the 8-element buffer
  reg [2:0] pointer;
  // 16-bit register to accumulate the sum of the samples in the buffer
  reg [15:0] sum;
  // 4-bit counter for the number of samples stored (max 8)
  reg [3:0] count;
  // Temporary register to hold the old value being replaced
  reg [11:0] old_val;

  always @(posedge clk) begin
    if (reset) begin
      // On reset: clear the pointer, counter, sum, and output.
      pointer <= 0;
      count   <= 0;
      sum     <= 0;
      data_out<= 0;
      // Clear the circular buffer
      integer i;
      for (i = 0; i < 8; i = i + 1)
        buffer[i] <= 0;
    end else begin
      // Read the value currently at the buffer location pointed to by 'pointer'
      old_val = buffer[pointer];
      // Store the new incoming sample into the buffer at the current pointer
      buffer[pointer] <= data_in;
      // Update the running sum: add the new sample and subtract the old sample
      sum <= sum + data_in - old_val;
      // If the buffer is not yet full, increment the sample count
      if (count < 8)
        count <= count + 1;
      // Update the pointer in a circular fashion (0 to 7)
      pointer <= (pointer + 1) % 8;
      // Compute the moving average:
      // For the first (count < 8) samples, average the sum of the available samples.
      // Once 8 samples are stored, always average over 8 samples.
      if (count < 8)
        data_out <= sum / count;
      else
        data_out <= sum / 8;
    end
  end

endmodule

input.rtl/moving_average.v:
module moving_average(
    input wire clk,
    input wire reset,
    input  wire [11 : 0] data_in,
    output wire [11 : 0] data_out
);

reg [11 : 0] memory [7 : 0];
reg [14 : 0] sum;
reg [2  : 0] write_address;
wire [2 : 0] next_address;
reg [11 : 0] read_data;

assign next_address=write_address + 1'b1;
assign data_out=sum[14 : 3];

    // write current input to memory
    integer i;
    always @(posedge clk ) begin
        if (reset == 1'b1) begin
            for (i = 0 ;i < 8 ; i = i + 1 ) begin
                memory[i]<='h0;
            end
        end else begin
            memory[write_address]<=data_in;
        end
    end

    // read the oldest element written to memory
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            read_data<='h0;
        end else begin
            read_data<=memory[next_address];
        end
    end

    // increase the write address to move onto the next data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            write_address<='h0;
        end else begin
            write_address<=write_address + 1'b1;
        end
    end

    // calculate sum by adding the latest data to the sum and substracting the oldest data
    always @(posedge clk ) begin
        if(reset == 1'b1)begin
            sum<='h0;
        end else begin
            sum<=sum+data_in-read_data;
        end
    end

endmodule

output.rtl/moving_average.v:
module moving_average(
    input wire clk,
    input wire reset,
    input wire enable,            // New enable signal: 1-bit
    input  wire [11:0] data_in,
    output wire [11:0] data_out
);

    // Internal memory for the last 8 samples
    reg [11:0] memory [7:0];
    // Running sum of the 8 samples (15 bits to accommodate overflow)
    reg [14:0] sum;
    // Write address pointer for the circular buffer
    reg [2:0] write_address;
    // Next address for reading the oldest sample
    wire [2:0] next_address;
    // Register to hold the oldest sample value
    reg [11:0] read_data;

    // Calculate the next address by simply incrementing the write pointer
    assign next_address = write_address + 1'b1;
    // The moving average is computed by shifting the running sum right by 3 bits
    assign data_out = sum[14:3];

    // Write current input to memory only when reset is asserted or when enable is high
    always @(posedge clk) begin
        if (reset) begin
            integer i;
            for (i = 0; i < 8; i = i + 1) begin
                memory[i] <= 12'h0;
            end
        end else if (enable) begin
            memory[write_address] <= data_in;
        end
    end

    // Read the oldest element from memory only when reset is asserted or when enable is high
    always @(posedge clk) begin
        if (reset) begin
            read_data <= 12'h0;
        end else if (enable) begin
            read_data <= memory[next_address];
        end
    end

    // Increment the write address only when reset is asserted or when enable is high
    always @(posedge clk) begin
        if (reset) begin
            write_address <= 3'h0;
        end else if (enable) begin
            write_address <= write_address + 1'b1;
        end
    end

    // Update the running sum only when reset is asserted or when enable is high
    always @(posedge clk) begin
        if (reset) begin
            sum <= 15'h0;
        end else if (enable) begin
            sum <= sum + data_in - read_data;
        end
    end

endmodule

output.rtl/mux_synch.sv:
module mux_synch (
    input  [7:0] data_in,    // asynchronous data input
    input        req,        // indicates that valid data is available at data_in
    input        dst_clk,    // destination clock domain
    input        src_clk,    // source clock domain (not used in this design)
    input        nrst,       // asynchronous active-low reset
    output reg [7:0] data_out // synchronized version of data_in in the destination clock domain
);

    // Synchronize the req signal using a 2-flop synchronizer (nff module)
    wire sync_req;
    nff req_sync (
        .d_in  (req),
        .dst_clk(dst_clk),
        .rst   (nrst),
        .syncd (sync_req)
    );

    // Pipeline registers for data synchronization.
    // The input data is sampled when sync_req is high; otherwise, 0 is passed.
    // A three-stage pipeline is used to meet the requirement that data remains stable for at least three destination clock cycles.
    reg [7:0] data_sync0, data_sync1, data_sync2;

    always @(posedge dst_clk or negedge nrst) begin
        if (!nrst) begin
            data_sync0 <= 8'b0;
            data_sync1 <= 8'b0;
            data_sync2 <= 8'b0;
        end else begin
            // Sample data_in when sync_req is high; else pass 0.
            data_sync0 <= (sync_req) ? data_in : 8'b0;
            data_sync1 <= data_sync0;
            data_sync2 <= data_sync1;
        end
    end

    // Drive the final output from the last stage of the pipeline.
    always @(posedge dst_clk or negedge nrst) begin
        if (!nrst)
            data_out <= 8'b0;
        else
            data_out <= data_sync2;
    end

endmodule

module nff (
    input  d_in,    // asynchronous input signal to be synchronized
    input  dst_clk, // destination clock domain
    input  rst,     // asynchronous active-low reset
    output reg syncd // synchronized output (2-clock-cycle delayed version of d_in)
);

    // Two-stage flip-flop synchronizer to minimize metastability.
    reg d_in_ff;

    always @(posedge dst_clk or negedge rst) begin
        if (!rst) begin
            d_in_ff  <= 1'b0;
            syncd    <= 1'b0;
        end else begin
            d_in_ff  <= d_in;
            syncd    <= d_in_ff;
        end
    end

endmodule

module mux_synch (

    input  [7:0] data_in,    // asynchronous data input
    input        req,        // indicating that data is available at the data_in input
    input        dst_clk,    // destination clock
    input        src_clk,    // source clock
    input        nrst,       // asynchronous reset 
    output reg [7:0] data_out, // synchronized version of data_in to the destination clock domain
    output        ack_out     // acknowledgment signal transmitted back to the source domain
);

    wire         syncd_req;
    wire         anded_req;
    wire         syncd_ack;
    reg          syncd_req_1;
    reg          ack;         // one-cycle pulse generated in destination domain
    reg          ack_stretched; // pulse stretcher: holds the ack pulse for an extra cycle

    // Synchronize the req signal from source to destination domain
    nff req_synch_0 (
        .d_in     (req),
        .dst_clk  (dst_clk),
        .rst      (nrst),
        .syncd    (syncd_req)
    );

    // One clock cycle delay of the synchronized req signal
    always_ff @(posedge dst_clk) begin
        syncd_req_1 <= syncd_req;
    end

    // Generate a pulse (posedge) when the req signal transitions
    assign anded_req = (!syncd_req_1 && syncd_req);

    // Latch data_in to data_out on the rising edge of the pulse
    always_ff @(posedge dst_clk or negedge nrst) begin
        if (!nrst)
            data_out <= 8'b0;
        else if (anded_req == 1'b1)
            data_out <= data_in;
        else
            data_out <= data_out;
    end

    // Generate a one-cycle ack pulse in the destination domain
    always_ff @(posedge dst_clk or negedge nrst) begin
        if (!nrst)
            ack <= 1'b0;
        else if (anded_req == 1'b1)
            ack <= 1'b1;
        else
            ack <= 1'b0;
    end

    // Pulse stretcher: Extend the ack pulse for one extra destination clock cycle.
    // This ensures that when the ack pulse crosses to the source domain,
    // it overlaps at least one rising edge of src_clk.
    always_ff @(posedge dst_clk or negedge nrst) begin
        if (!nrst)
            ack_stretched <= 1'b0;
        else if (anded_req == 1'b1)
            ack_stretched <= 1'b1;
        else if (ack_stretched)
            ack_stretched <= 1'b1; // hold for an extra cycle
        else
            ack_stretched <= 1'b0;
    end

    // Synchronize the stretched ack pulse from destination domain to source domain
    nff enable_synch_1 (
        .d_in     (ack_stretched),
        .dst_clk  (src_clk),
        .rst      (nrst),
        .syncd    (syncd_ack)
    );

    assign ack_out = syncd_ack;

endmodule

module nff (
    input  d_in,       // input data that needs to be synchronized to the dst_clk domain.
    input  dst_clk,    // destination domain clock.
    input  rst,        // asynchronous active-low reset
    output reg syncd   // synced output, which is a 2-clock-cycle delayed version of d_in.
);
    reg dmeta;

    always @(posedge dst_clk or negedge rst)  
    begin
        if (!rst) begin
            syncd   <= 1'b0;
            dmeta   <= 1'b0;
        end else begin
            dmeta   <= d_in;
            syncd   <= dmeta;
        end
    end

endmodule

