module ping_pong_buffer (
    input logic clk,
    input logic rst_n,
    input logic write_enable,
    input logic read_enable,
    input logic [7:0] data_in,
    output logic [7:0] data_out,
    output logic buffer_full,
    output logic buffer_empty,
    output reg buffer_select
);

    localparam DEPTH = 256;
    localparam ADDR_WIDTH = 8;

    // Pointers for the two buffers
    logic [ADDR_WIDTH-1:0] wr_ptr0, rd_ptr0;
    logic [ADDR_WIDTH-1:0] wr_ptr1, rd_ptr1;

    // Outputs from the dual port memories
    logic [7:0] data_out0, data_out1;

    // Full and empty flags for each buffer
    assign full0 = ((wr_ptr0 + 1) % DEPTH == rd_ptr0);
    assign empty0 = (wr_ptr0 == rd_ptr0);
    assign full1 = ((wr_ptr1 + 1) % DEPTH == rd_ptr1);
    assign empty1 = (wr_ptr1 == rd_ptr1);

    // Dual port memories instantiation
    dual_port_memory memory0 (
        .clk(clk),
        .we((buffer_select == 1) ? write_enable : 1'b0),
        .write_addr((buffer_select == 1) ? wr_ptr0 : 8'd0),
        .din((buffer_select == 1) ? data_in : 8'd0),
        .read_addr(rd_ptr0),
        .dout(data_out0)
    );

    dual_port_memory memory1 (
        .clk(clk),
        .we((buffer_select == 0) ? write_enable : 1'b0),
        .write_addr((buffer_select == 0) ? wr_ptr1 : 8'd0),
        .din((buffer_select == 0) ? data_in : 8'd0),
        .read_addr(rd_ptr1),
        .dout(data_out1)
    );

    // Output assignment
    assign data_out = (buffer_select == 0) ? data_out0 : data_out1;
    assign buffer_full = (buffer_select == 0) ? full1 : full0;
    assign buffer_empty = (buffer_select == 0) ? empty0 : empty1;

    // Sequential logic for pointer management and buffer switching
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr0 <= 0;
            rd_ptr0 <= 0;
            wr_ptr1 <= 0;
            rd_ptr1 <= 0;
            buffer_select <= 0;
        end else begin
            // Write operation: update write pointer for the active write memory
            if (write_enable) begin
                if (buffer_select == 0) begin
                    // In mode 0, memory1 is active for writing
                    if (!full1) begin
                        wr_ptr1 <= (wr_ptr1 + 1) % DEPTH;
                    end
                end else begin
                    // In mode 1, memory0 is active for writing
                    if (!full0) begin
                        wr_ptr0 <= (wr_ptr0 + 1) % DEPTH;
                    end
                end
            end

            // Read operation: update read pointer for the active read memory
            if (read_enable) begin
                if (buffer_select == 0) begin
                    // In mode 0, memory0 is active for reading
                    if (!empty0) begin
                        rd_ptr0 <= (rd_ptr0 + 1) % DEPTH;
                    end
                end else begin
                    // In mode 1, memory1 is active for reading
                    if (!empty1) begin
                        rd_ptr1 <= (rd_ptr1 + 1) % DEPTH;
                    end
                end
            end

            // Buffer switching logic:
            // Toggle buffer_select if the active write buffer becomes full
            if ((buffer_select == 0 && full1) || (buffer_select == 1 && full0)) begin
                buffer_select <= ~buffer_select;
            end
            // Also, toggle if the active read buffer is empty and a read was requested
            if ((buffer_select == 0 && empty0 && read_enable) || (buffer_select == 1 && empty1 && read_enable)) begin
                buffer_select <= ~buffer_select;
            end
        end
    end

endmodule

output.rtl/pipeline_mac.sv:
module pipeline_mac #(
    parameter DWIDTH = 16,  // Bit width for multiplicand and multiplier
    parameter N      = 4    // Number of data points to accumulate over
) (
    clk,
    rstn,
    multiplicand,
    multiplier,
    valid_i,
    result,
    valid_out
);

  // ----------------------------------------
  // - Local parameter definition
  // ----------------------------------------
  // Calculate accumulator width to avoid overflow:
  // Maximum multiplication result is 2*DWIDTH bits and accumulating N products requires an extra
  // ceil(log2(N)) bits. Hence, DWIDTH_ACCUMULATOR = 2*DWIDTH + $clog2(N).
  localparam DWIDTH_ACCUMULATOR = 2*DWIDTH + $clog2(N);

  // ----------------------------------------
  // - Interface Definitions
  // ----------------------------------------
  input  logic clk;                                // Clock signal
  input  logic rstn;                               // Active low reset signal
  input  logic [DWIDTH-1:0] multiplicand;          // Input multiplicand
  input  logic [DWIDTH-1:0] multiplier;            // Input multiplier
  input  logic valid_i;                            // Input valid signal
  output logic [DWIDTH_ACCUMULATOR-1:0] result;   // Accumulated result output
  output logic valid_out;                         // Output valid signal, indicates when result is ready

  // ----------------------------------------
  // - Internal signals
  // ----------------------------------------
  logic [DWIDTH_ACCUMULATOR-1:0] mult_result_reg;    // Register to store intermediate multiplication result
  logic [DWIDTH_ACCUMULATOR-1:0] accumulation_reg;   // Register to store accumulated result
  logic [$clog2(N):0] counter;                       // Counter to track the number of accumulations
  logic [$clog2(N):0] counter_reg;                   // Register to hold the value of the counter
  logic count_rst, accumulator_rst;                  // Reset signals for counter and accumulator
  logic valid_out_s0, valid_out_s1, valid_out_s2;      // Intermediate signals for valid output staging
  logic valid_i_s1;                                  // Intermediate signal for input valid (not used further)

  // ----------------------------------------
  // - Procedural blocks
  // ----------------------------------------

  // Stage 1 of the pipeline: Perform multiplication
  always @(posedge clk or negedge rstn) begin
     if (!rstn)
         mult_result_reg <= '0;
     else if (valid_i)
         mult_result_reg <= multiplicand * multiplier;
     else
         mult_result_reg <= mult_result_reg;
  end

  // Stage 2 of the pipeline: Accumulation logic
  always @(posedge clk or negedge rstn) begin
     if (!rstn)
         accumulation_reg <= '0;
     else if (accumulator_rst)
         accumulation_reg <= '0;
     else if (valid_i)
         accumulation_reg <= accumulation_reg + mult_result_reg;
     else
         accumulation_reg <= accumulation_reg;
  end

  // N-bit counter to track the number of accumulations
  always @(posedge clk or negedge rstn) begin
     if (!rstn)
         counter_reg <= '0;
     else if (count_rst)
         counter_reg <= '1;
     else if (valid_i)
         counter_reg <= counter_reg + '1;
     else
         counter_reg <= counter_reg;
  end

  // Register valid output for 2-stage pipeline
  always @(posedge clk or negedge rstn) begin
     if (!rstn) begin
         valid_out_s1 <= '0;
         valid_out_s2 <= '0;
     end else begin
         valid_out_s1 <= valid_out_s0;
         valid_out_s2 <= valid_out_s1;
     end
  end

  // ----------------------------------------
  // - Combinational Assignments
  // ----------------------------------------
  assign counter = count_rst ? '1 : (valid_i ? (counter_reg + '1) : counter_reg);
  assign valid_out_s0 = (counter_reg == N-1);    // Assert when N accumulations are done
  assign count_rst      = valid_out_s1;            // Reset counter after N accumulations
  assign accumulator_rst = valid_out_s1;            // Reset accumulator after N accumulations
  assign result         = accumulation_reg;        // Output final accumulated result
  assign valid_out      = valid_out_s1 & ~valid_out_s2; // Valid output asserted for one cycle

endmodule

output.rtl/piso_8bit.sv:
module piso_8bit (
    input  logic clk,    // 1-bit clock input
    input  logic rst,    // asynchronous active LOW reset
    output logic serial_out  // 1-bit serial output
);

  // Internal 8-bit register used for pattern generation
  reg [7:0] tmp;
  // Counter to track which bit of tmp is being shifted out (0 to 7)
  reg [2:0] bit_counter;

  // On every positive edge of clk or when rst is asserted (active LOW),
  // update the internal state.
  always_ff @(posedge clk or negedge rst) begin
    if (!rst) begin
      // Initialize tmp to 0000_0001 and reset the bit counter.
      tmp       <= 8'b0000_0001;
      bit_counter <= 3'b000;
      // serial_out is combinational, so no need to drive it here.
    end else begin
      // Check if we have shifted out all 8 bits.
      if (bit_counter == 3'd7) begin
        // After 8 cycles, increment tmp.
        // If tmp is 8'hFF, wrap around to 0000_0000.
        if (tmp == 8'hFF)
          tmp <= 8'b0000_0000;
        else
          tmp <= tmp + 1;
        // Reset the bit counter for the next 8-bit pattern.
        bit_counter <= 3'b000;
      end else begin
        // Increment the bit counter to shift the next bit.
        bit_counter <= bit_counter + 1;
      end
    end
  end

  // Generate the serial output by selecting the appropriate bit from tmp.
  // Since the pattern is shifted out in MSB-first order:
  // When bit_counter == 0, serial_out = tmp[7] (MSB);
  // When bit_counter == 7, serial_out = tmp[0] (LSB).
  // This matches the requirement that for 0000_0001, the first output is 0 and the eighth is 1.
  assign serial_out = tmp[7 - bit_counter];

endmodule

output.rtl/pkt_detector.sv:
module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

    // Packet symbols and packet length
    localparam [7:0] START_SYMBOL = 8'hFB;
    localparam [7:0] END_SYMBOL   = 8'hFD;
    localparam       PKT_BYTES    = 20;

    // State machine definition
    typedef enum logic [1:0] {
        S_IDLE     = 2'b00,
        S_ACTIVE   = 2'b01,
        S_WAIT_END = 2'b10,
        S_ERROR    = 2'b11
    } state_t;

    state_t curr_state, nxt_state;

    // Internal registers
    logic [7:0]    byte_cnt;
    logic [159:0]  pkt_reg;

    // State register: synchronous update on posedge clk, asynchronous reset
    always_ff @(posedge clk or negedge reset) begin
        if (!reset)
            curr_state <= S_IDLE;
        else
            curr_state <= nxt_state;
    end

    // Next state logic
    always_comb begin
        case (curr_state)
            S_IDLE: 
                nxt_state = ((data_in == START_SYMBOL) && (data_k_flag == 1'b1)) ? S_ACTIVE : S_IDLE;
            S_ACTIVE: 
                nxt_state = (byte_cnt == PKT_BYTES) ? S_WAIT_END : S_ACTIVE;
            S_WAIT_END: 
                nxt_state = (pkt_reg[159:152] == END_SYMBOL) ? S_IDLE : S_ERROR;
            S_ERROR: 
                nxt_state = ((data_in == START_SYMBOL) && (data_k_flag == 1'b1)) ? S_ACTIVE : S_ERROR;
            default: nxt_state = S_IDLE;
        endcase
    end

    // Register update logic: accumulators, counters, output flags, etc.
    always_ff @(posedge clk or negedge reset) begin
        if (!reset) begin
            byte_cnt         <= 8'd0;
            pkt_reg          <= 160'd0;
            pkt_count        <= {PKT_CNT_WIDTH{1'b0}};
            pkt_data         <= 160'd0;
            mem_read_detected       <= 1'b0;
            mem_write_detected      <= 1'b0;
            io_read_detected        <= 1'b0;
            io_write_detected       <= 1'b0;
            cfg_read0_detected      <= 1'b0;
            cfg_write0_detected     <= 1'b0;
            cfg_read1_detected      <= 1'b0;
            cfg_write1_detected     <= 1'b0;
            completion_detected     <= 1'b0;
            completion_data_detected<= 1'b0;
            error_detected          <= 1'b0;
        end
        else begin
            // Default assignments: clear flags and error signal each cycle
            mem_read_detected       <= 1'b0;
            mem_write_detected      <= 1'b0;
            io_read_detected        <= 1'b0;
            io_write_detected       <= 1'b0;
            cfg_read0_detected      <= 1'b0;
            cfg_write0_detected     <= 1'b0;
            cfg_read1_detected      <= 1'b0;
            cfg_write1_detected     <= 1'b0;
            completion_detected     <= 1'b0;
            completion_data_detected<= 1'b0;
            error_detected          <= 1'b0;
            // Default: hold pkt_data and pkt_count until updated in S_WAIT_END
            pkt_data         <= pkt_reg;
            pkt_count        <= pkt_count;

            case (curr_state)
                S_IDLE: begin
                    // On detecting START_SYMBOL in IDLE, reset accumulators
                    if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1)) begin
                        byte_cnt <= 8'd0;
                        pkt_reg  <= 160'd0;
                    end
                end
                S_ACTIVE: begin
                    // Accumulate packet data: shift in new byte at LSB
                    if (data_k_flag) begin
                        pkt_reg <= {pkt_reg[151:0], data_in};
                        if (byte_cnt < PKT_BYTES - 1)
                            byte_cnt <= byte_cnt + 1;
                    end
                end
                S_WAIT_END: begin
                    // Validate the packet by checking the END_SYMBOL
                    if (pkt_reg[159:152] == END_SYMBOL) begin
                        // Valid packet: update output packet data and packet counter
                        pkt_data   <= pkt_reg;
                        pkt_count  <= pkt_count + 1;
                        // Decode the packet header (second byte) to set detection flags
                        case (pkt_reg[31:24])
                            8'h01: mem_read_detected       <= 1'b1;
                            8'h02: mem_write_detected      <= 1'b1;
                            8'h03: io_read_detected        <= 1'b1;
                            8'h04: io_write_detected       <= 1'b1;
                            8'h05: cfg_read0_detected      <= 1'b1;
                            8'h06: cfg_write0_detected     <= 1'b1;
                            8'h07: cfg_read1_detected      <= 1'b1;
                            8'h08: cfg_write1_detected     <= 1'b1;
                            8'h09: completion_detected     <= 1'b1;
                            8'h0A: completion_data_detected<= 1'b1;
                            default: error_detected          <= 1'b1;
                        endcase
                    end
                    else begin
                        // Invalid packet sequence: flag error
                        error_detected <= 1'b1;
                    end
                end
                S_ERROR: begin
                    // In error state, clear the accumulators for recovery
                    pkt_reg <= 160'd0;
                    byte_cnt<= 8'd0;
                end
                default: ;
            endcase
        end
    end

endmodule

output.rtl/cvdp_prbs_gen.sv:
module cvdp_prbs_gen #(
  parameter int CHECK_MODE = 0,    // 0 = Generator Mode, 1 = Checker Mode
  parameter int POLY_LENGTH = 31,  // Length of the LFSR (number of stages)
  parameter int POLY_TAP   = 3,    // Tap position (assumed 1-indexed; tap at POLY_LENGTH is the MSB)
  parameter int WIDTH      = 16    // Width of data_in and data_out buses
) (
  input  logic         clk,
  input  logic         rst,
  input  logic [WIDTH-1:0] data_in,
  output logic [WIDTH-1:0] data_out
);

  //-------------------------------------------------------------------------
  // Parameter Checks (compile-time assertions)
  //-------------------------------------------------------------------------
  // Ensure that the polynomial length is at least as large as the tap position,
  // that the tap is positive, and that WIDTH is positive.
  static_assert(POLY_LENGTH >= POLY_TAP, "Error: POLY_LENGTH must be >= POLY_TAP");
  static_assert(POLY_TAP > 0, "Error: POLY_TAP must be a positive integer");
  static_assert(WIDTH > 0, "Error: WIDTH must be a positive integer");

  //-------------------------------------------------------------------------
  // Internal Registers and Wires
  //-------------------------------------------------------------------------
  // LFSR register: using POLY_LENGTH bits. Index [POLY_LENGTH-1] is the MSB.
  logic [POLY_LENGTH-1:0] lfsr_reg;

  // Expected PRBS pattern slice: most significant WIDTH bits of the LFSR.
  // In Generator Mode, this is the output pattern.
  // In Checker Mode, this is used for comparison.
  logic [WIDTH-1:0] expected_prbs;

  // Feedback bit computed as the XOR of the MSB (position POLY_LENGTH)
  // and the tap bit (position POLY_TAP). (Assumes 1-indexed positions.)
  logic feedback_bit;

  //-------------------------------------------------------------------------
  // Sequential Logic: LFSR Update and Output Generation
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      // On reset, initialize the LFSR to all ones and force data_out to all ones.
      lfsr_reg <= {POLY_LENGTH{1'b1}};
      data_out  <= {WIDTH{1'b1}};
    end else begin
      if (CHECK_MODE == 0) begin
        //-------------------------------------------------------------------------
        // Generator Mode (CHECK_MODE = 0)
        //-------------------------------------------------------------------------
        // Compute the feedback bit as the XOR of:
        //   - The MSB (bit at position POLY_LENGTH, i.e. index POLY_LENGTH-1)
        //   - The tap bit (bit at position POLY_TAP, i.e. index POLY_TAP-1)
        feedback_bit = lfsr_reg[POLY_LENGTH-1] ^ lfsr_reg[POLY_TAP-1];

        // Update the LFSR: shift right by one and insert the feedback bit at the MSB.
        // This produces the next state of the PRBS.
        lfsr_reg <= {feedback_bit, lfsr_reg[POLY_LENGTH-1:1]};

        // In Generator Mode, output the most significant WIDTH bits of the LFSR.
        data_out <= lfsr_reg[POLY_LENGTH-1:POLY_LENGTH-WIDTH];
      end else begin
        //-------------------------------------------------------------------------
        // Checker Mode (CHECK_MODE = 1)
        //-------------------------------------------------------------------------
        // Even in Checker Mode, we update the LFSR in the same way to generate
        // the expected PRBS pattern.
        feedback_bit = lfsr_reg[POLY_LENGTH-1] ^ lfsr_reg[POLY_TAP-1];
        lfsr_reg <= {feedback_bit, lfsr_reg[POLY_LENGTH-1:1]};

        // Extract the expected PRBS pattern from the LFSR.
        expected_prbs = lfsr_reg[POLY_LENGTH-1:POLY_LENGTH-WIDTH];

        // Compare the incoming data with the expected PRBS pattern.
        // The XOR of data_in and expected_prbs yields a nonzero value for any bit
        // discrepancy. Thus, data_out will be nonzero if there is an error.
        data_out <= data_in ^ expected_prbs;
      end
    end
  end

endmodule

input.rtl/prim_max_find.sv:
module prim_max_find #(
  parameter int NumSrc = 8,
  parameter int Width = 8,
  // Derived parameters
  localparam int SrcWidth = $clog2(NumSrc),
  localparam int NumLevels = $clog2(NumSrc) - 1,
  localparam int NumNodes = 2**(NumLevels+1)
) (
  input                         clk_i,
  input                         rst_ni,
  input [Width*NumSrc-1:0]      values_i,    // Flattened Input values
  input [NumSrc-1:0]            valid_i,     // Input valid bits
  output wire [Width-1:0]       max_value_o, // Maximum value
  output wire [SrcWidth-1:0]    max_idx_o,   // Index of the maximum value
  output wire                   max_valid_o  // Whether any of the inputs is valid
);

  reg [NumNodes-1:0]                vld_tree [0:NumLevels];
  reg [SrcWidth-1:0]                 idx_tree [0:NumLevels][NumNodes-1:0];
  reg [Width-1:0]                    max_tree [0:NumLevels][NumNodes-1:0];

  generate
    for (genvar level = 0; level <= NumLevels; level++) begin : gen_tree
      localparam int Base0 = (2**level);
      localparam int Base1 = (2**(level+1));

      for (genvar offset = 0; offset < 2**level; offset++) begin : gen_level
        localparam int Pa = Base0 + offset;
        localparam int C0 = Base1 + 2*offset;
        localparam int C1 = Base1 + 2*offset + 1;

        if (level == NumLevels) begin : gen_leafs
          if (offset < NumSrc) begin : gen_assign
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end else begin
                vld_tree[level][Pa] <= valid_i[offset];
                idx_tree[level][Pa] <= offset;
                max_tree[level][Pa] <= values_i[(offset+1)*Width : offset*Width];
              end
            end
          end else begin : gen_tie_off
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end
            end
          end
        end

        else begin : gen_nodes
          reg sel; 
          always @(posedge clk_i or negedge rst_ni) begin
            if (!rst_ni) begin
              vld_tree[level][Pa] <= 1'b0;
              idx_tree[level][Pa] <= '0;
              max_tree[level][Pa] <= '0;
            end else begin
              sel = (~vld_tree[level+1][C0] & vld_tree[level+1][C1]) |
                    (vld_tree[level+1][C0] & vld_tree[level+1][C1] & (max_tree[level+1][C1] > max_tree[level+1][C0]));

              vld_tree[level][Pa] <= (sel) ? vld_tree[level+1][C1] : vld_tree[level+1][C0];
              idx_tree[level][Pa] <= (sel) ? idx_tree[level+1][C1] : idx_tree[level+1][C0];
              max_tree[level][Pa] <= (sel) ? max_tree[level+1][C1] : max_tree[level+1][C0];
            end
          end
        end
      end : gen_level
    end : gen_tree
  endgenerate

  assign max_valid_o = vld_tree[0][0];
  assign max_idx_o   = idx_tree[0][0];
  assign max_value_o = max_tree[0][0];

endmodule

output.rtl/prim_max_find.sv:
module prim_max_find #(
  parameter int NumSrc = 8,
  parameter int Width  = 8,
  // Compute source index width
  localparam int SrcWidth = $clog2(NumSrc),
  // Number of levels: leaves are at level NumLevels.
  // For a complete binary tree with NumSrc leaves, we need:
  //   NumLevels = log2(NumSrc)   and total nodes = 2**(NumLevels+1) - 1.
  localparam int NumLevels = $clog2(NumSrc),
  localparam int NumNodes  = (2**(NumLevels+1) - 1)
) (
  input                         clk_i,
  input                         rst_ni,
  input [Width*NumSrc-1:0]      values_i,    // Flattened input values
  input [NumSrc-1:0]            valid_i,     // Validity bits for each input
  output reg [Width-1:0]        max_value_o, // Maximum value among valid inputs
  output reg [SrcWidth-1:0]     max_idx_o,   // Index of the maximum value
  output reg                    max_valid_o  // Flag indicating if any input is valid
);

  // Internal registers for the binary tree:
  // Each node holds a validity flag, the index of the valid input, and the maximum value.
  reg                           vld [0:NumNodes-1];
  reg [SrcWidth-1:0]            idx [0:NumNodes-1];
  reg [Width-1:0]               max_val [0:NumNodes-1];

  //-------------------------------------------------------------------------
  // Generate Leaves: These correspond to the actual inputs.
  // Leaves are located at level = NumLevels.
  // For a complete binary tree, the starting index for level L is (2**L - 1).
  //-------------------------------------------------------------------------
  generate
    for (genvar offset = 0; offset < 2**NumLevels; offset++) begin : gen_leaf
      localparam int leaf_index = (2**NumLevels - 1) + offset;
      always @(posedge clk_i or negedge rst_ni) begin
        if (!rst_ni) begin
          vld[leaf_index]   <= 1'b0;
          idx[leaf_index]   <= '0;
          max_val[leaf_index] <= '0;
        end else begin
          if (offset < NumSrc) begin
            vld[leaf_index]   <= valid_i[offset];
            idx[leaf_index]   <= offset;
            max_val[leaf_index] <= values_i[(offset+1)*Width-1 -: Width];
          end else begin
            // Tie-off unused leaves
            vld[leaf_index]   <= 1'b0;
            idx[leaf_index]   <= '0;
            max_val[leaf_index] <= '0;
          end
        end
      end
    end
  endgenerate

  //-------------------------------------------------------------------------
  // Generate Internal Nodes: Combine the results from child nodes.
  // For each internal node at level L (0 <= L < NumLevels), the parent node is
  // located at index = (2**L - 1) + offset, with 2**L nodes at that level.
  // Its children are at indices:
  //   left_child  = (2**(L+1) - 1) + (2*offset)
  //   right_child = (2**(L+1) - 1) + (2*offset) + 1
  //-------------------------------------------------------------------------
  generate
    for (genvar level = 0; level < NumLevels; level++) begin : gen_internal
      for (genvar offset = 0; offset < 2**level; offset++) begin : gen_node
