always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
      end
   end
   else begin
      if(start_intra) begin
         for(int i = 0; i < SUB_BLOCKS; i++) begin
            out_data_intra_block_reg[i] <= out_data_intra_block[i];
         end
      end
   end
