output.rtl/sdram_controller.sv:
module sdram_controller (
    input  logic         clk,
    input  logic         reset,
    input  logic [23:0]  addr,
    input  logic [15:0]  data_in,
    output logic [15:0]  data_out,
    input  logic         read,
    input  logic         write,
    input  logic [15:0]  sdram_dq,
    output logic [15:0]  dq_out,
    output logic         sdram_clk,
    output logic         sdram_cke,
    output logic         sdram_cs,
    output logic         sdram_ras,
    output logic         sdram_cas,
    output logic         sdram_we,
    output logic [22:0]  sdram_addr,
    output logic [1:0]   sdram_ba
);

    // Define state encoding
    typedef enum logic [2:0] {
        INIT     = 3'd0,
        IDLE     = 3'd1,
        ACTIVATE = 3'd2,
        READ     = 3'd3,
        WRITE    = 3'd4,
        REFRESH  = 3'd5
    } state_t;

    state_t state, next_state;
    logic [3:0] init_counter; // 4-bit counter for 10-cycle init sequence
    logic [9:0] idle_counter; // 10-bit counter for 1024-cycle auto-refresh

    //-------------------------------------------------------------------------
    // Sequential logic: state machine and counter updates
    //-------------------------------------------------------------------------
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            state      <= INIT;
            init_counter <= 0;
            idle_counter <= 0;
        end else begin
            case (state)
                INIT: begin
                    if (init_counter < 10)
                        init_counter <= init_counter + 1;
                    else begin
                        state      <= IDLE;
                        idle_counter <= 0;
                    end
                end
                IDLE: begin
                    if (read || write) begin
                        // A read or write request is received; move to ACTIVATE
                        state      <= ACTIVATE;
                        idle_counter <= 0;
                    end else if (idle_counter >= 1023) begin
                        // Auto-refresh trigger after 1024 cycles of inactivity
                        state      <= REFRESH;
                        idle_counter <= 0;
                    end else begin
                        idle_counter <= idle_counter + 1;
                    end
                end
                ACTIVATE: begin
                    // Next state is determined by the input command
                    if (read)
                        state <= READ;
                    else if (write)
                        state <= WRITE;
                    else
                        state <= IDLE;
                end
                READ: begin
                    state <= IDLE;
                end
                WRITE: begin
                    state <= IDLE;
                end
                REFRESH: begin
                    state <= IDLE;
                end
                default: state <= IDLE;
            endcase
        end
    end

    //-------------------------------------------------------------------------
    // Combinational logic: drive SDRAM control signals based on state
    //-------------------------------------------------------------------------
    always_comb begin
        // Default assignments for inactive state
        sdram_cs  = 1'b1;
        sdram_ras = 1'b1;
        sdram_cas = 1'b1;
        sdram_we  = 1'b1;
        sdram_cke = 1'b1;
        // Drive address signals: assume lower 22 bits for row/column and upper 2 bits for bank
        sdram_addr = addr[22:0];
        sdram_ba   = addr[24:23];
        data_out   = 16'b0;
        dq_out     = 16'b0;
        sdram_clk  = clk;  // SDRAM clock driven by system clock

        case (state)
            INIT: begin
                // During initialization, SDRAM clock enable is held low.
                sdram_cke = 1'b0;
                // Address signals can be driven by the provided address.
                sdram_addr = addr[22:0];
                sdram_ba   = addr[24:23];
            end
            IDLE: begin
                // Idle state: no active command; address signals are continuously driven.
                sdram_addr = addr[22:0];
                sdram_ba   = addr[24:23];
            end
            ACTIVATE: begin
                // Activation command: drive address signals for row activation.
                sdram_addr = addr[22:0];
                sdram_ba   = addr[24:23];
            end
            READ: begin
                // Read command: assert CKE high, RAS low, CAS high, and WE low.
                sdram_ras = 1'b0;
                sdram_we  = 1'b0;
                // Capture data from SDRAM data bus into data_out.
                data_out  = sdram_dq;
            end
            WRITE: begin
                // Write command: assert CKE high, RAS low, CAS high, and WE high.
                sdram_ras = 1'b0;
                sdram_we  = 1'b1;
                // Drive data bus with the write data.
                dq_out    = data_in;
            end
            REFRESH: begin
                // Refresh command: assert CS high, RAS high, CAS high, WE low.
                sdram_ras = 1'b1;
                sdram_cas = 1'b1;
                sdram_we  = 1'b0;
                // For refresh, typically bank 0 and address 0 are used.
                sdram_addr = 23'd0;
                sdram_ba   = 2'd0;
            end
        endcase
    end

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,          // Clock signal
    input i_rst_b,        // Active-low asynchronous reset
    input [3:0] i_operand_a, // 4-bit input operand A
    input [3:0] i_operand_b, // 4-bit input operand B
    input [2:0] i_opcode,    // 3-bit operation code
    input [7:0] i_key_in,    // 8-bit security key input
    output reg [7:0] o_result // 8-bit operation result
);

    // Internal configurable security key (default: 0xAA)
    parameter p_key = 8'hAA;

    always @(posedge i_clk or negedge i_rst_b) begin
        if (!i_rst_b) begin
            o_result <= 8'b0;
        end else begin
            if (i_key_in == p_key) begin
                case(i_opcode)
                    3'b000: o_result <= i_operand_a + i_operand_b;
                    3'b001: o_result <= i_operand_a - i_operand_b;
                    3'b010: o_result <= i_operand_a * i_operand_b;
                    3'b011: o_result <= {4'b0, i_operand_a & i_operand_b};
                    3'b100: o_result <= {4'b0, i_operand_a | i_operand_b};
                    3'b101: o_result <= {4'b0, ~i_operand_a};
                    3'b110: o_result <= {4'b0, i_operand_a ^ i_operand_b};
                    3'b111: o_result <= {4'b0, ~(i_operand_a ^ i_operand_b)};
                    default: o_result <= 8'b0;
                endcase
            end else begin
                o_result <= 8'b0;
            end
        end
    end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface (
    input  wire [p_addr_width-1:0] i_addr,
    input  wire [p_data_width-1:0] i_data_in,
    input  wire [7:0]              i_key_in,
    input  wire                    i_read_write_enable,  // 1 = read, 0 = write
    input  wire                    i_capture_pulse,
    input  wire                    i_reset_bar,          // Asynchronous active-low reset
    output reg  [p_data_width-1:0] o_data_out,
    output reg                     o_error
);

  // Parameter definitions
  parameter p_configurable_key = 8'hAA;
  parameter p_data_width       = 8;
  parameter p_addr_width       = 8;

  // Internal memory array declaration
  // Memory depth is 2^p_addr_width words, each p_data_width bits wide.
  reg [p_data_width-1:0] mem [0:2**p_addr_width-1];

  // Loop index for memory clearing
  integer i;

  // Synchronous operations gated by i_capture_pulse with asynchronous reset
  always @(posedge i_capture_pulse or negedge i_reset_bar) begin
    if (!i_reset_bar) begin
      // Asynchronous reset: clear all internal registers and memory
      o_error         <= 1'b1;
      o_data_out      <= {p_data_width{1'b0}};
      for (i = 0; i < 2**p_addr_width; i = i + 1) begin
        mem[i] <= {p_data_width{1'b0}};
      end
    end
    else begin
      // Check if the provided key matches the internal configurable key
      if (i_key_in == p_configurable_key) begin
        if (!i_read_write_enable) begin
          // Write operation (authorized)
          mem[i_addr] <= i_data_in;
          o_data_out  <= {p_data_width{1'b0}}; // Default output for write is 0
          o_error     <= 1'b0;
        end
        else begin
          // Read operation (authorized)
          o_data_out <= mem[i_addr];
          o_error    <= 1'b0;
        end
      end
      else begin
        // Unauthorized access: flag error and default outputs to 0
        o_error    <= 1'b1;
        o_data_out <= {p_data_width{1'b0}};
      end
    end
  end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
    parameter p_address_width = 8,
    parameter p_data_width    = 8,
    parameter p_unlock_code_0 = 8'hAB,
    parameter p_unlock_code_1 = 8'hCD
)(
    input  wire [p_address_width-1:0] i_addr,
    input  wire [p_data_width-1:0]    i_data_in,
    input  wire                       i_read_write_enable, // 0 = write, 1 = read
    input  wire                       i_capture_pulse,     // clock for register bank
    input  wire                       i_rst_n,             // asynchronous active low reset
    output reg  [p_data_width-1:0]    o_data_out
);

    // State encoding for the unlocking mechanism:
    // 00: LOCKED
    // 01: WAIT_FOR_SECOND_CODE (unlock code 0 written correctly)
    // 10: UNLOCKED
    localparam STATE_LOCKED    = 2'b00;
    localparam STATE_WAIT_1    = 2'b01;
    localparam STATE_UNLOCKED  = 2'b10;

    reg [1:0] unlock_state;

    // Register bank memory: one register per address in the addressable space.
    reg [p_data_width-1:0] registers [0: (1 << p_address_width)-1];

    // Write operation: triggered on the rising edge of i_capture_pulse.
    // i_read_write_enable = 0 indicates a write operation.
    always @(posedge i_capture_pulse or negedge i_rst_n) begin
        if (!i_rst_n) begin
            unlock_state <= STATE_LOCKED;
        end else if (!i_read_write_enable) begin  // Write operation
            case(i_addr)
                0: begin
                    // Writing to address 0: must match the unlock code 0.
                    if (i_data_in == p_unlock_code_0)
                        unlock_state <= STATE_WAIT_1;
                    else
                        unlock_state <= STATE_LOCKED;
                    registers[0] <= i_data_in;
                end
                1: begin
                    // Writing to address 1: allowed only if previous unlock code was written correctly.
                    if (unlock_state == STATE_WAIT_1 && i_data_in == p_unlock_code_1)
                        unlock_state <= STATE_UNLOCKED;
                    else
                        unlock_state <= STATE_LOCKED;
                    registers[1] <= i_data_in;
                end
                default: begin
                    // For addresses 2 and above: writing is permitted only when unlocked.
                    if (unlock_state == STATE_UNLOCKED)
                        registers[i_addr] <= i_data_in;
                    // Otherwise, do nothing (write is prevented).
                end
            endcase
        end
    end

    // Read operation: triggered on the rising edge of i_capture_pulse.
    // i_read_write_enable = 1 indicates a read operation.
    always @(posedge i_capture_pulse or negedge i_rst_n) begin
        if (!i_rst_n)
            o_data_out <= {p_data_width{1'b0}};
        else if (i_read_write_enable) begin  // Read operation
            // Addresses 0 and 1 are write-only; always output 0.
            if ((i_addr == 0) || (i_addr == 1))
                o_data_out <= {p_data_width{1'b0}};
            // For addresses 2 and above, output stored data only if unlocked.
            else if (unlock_state == STATE_UNLOCKED)
                o_data_out <= registers[i_addr];
            else
                o_data_out <= {p_data_width{1'b0}};
        end else begin
            // During write operations, o_data_out defaults to 0.
            o_data_out <= {p_data_width{1'b0}};
        end
    end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // State definitions for the FSM
    localparam STATE_IDLE      = 2'd0;
    localparam STATE_CONFIGURE = 2'd1;
    localparam STATE_COUNTING  = 2'd2;
    localparam STATE_DONE      = 2'd3;

    // Constant for 1000 clock cycles (14-bit wide to cover up to 16000 cycles)
    localparam COUNT_THRESHOLD = 14'd1000;

    // Internal registers
    reg [1:0] state;                  // FSM state register
    reg [3:0] pattern_reg;            // Shift register for detecting the 1101 start sequence
    reg [1:0] config_bit_count;       // Counter for the 4 configuration bits
    reg [3:0] delay;                  // Delay value configured (most significant bit first)
    reg [13:0] cycle_count;           // Cycle counter for the counting phase
    reg [3:0] decrement_count;        // Counter to track how many 1000-cycle segments have elapsed
    reg [13:0] total_cycles;          // Total cycles for the counting phase = (delay + 1) * 1000

    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state            <= STATE_IDLE;
            pattern_reg      <= 4'd0;
            config_bit_count <= 2'd0;
            delay            <= 4'd0;
            cycle_count      <= 14'd0;
            decrement_count  <= 4'd0;
            total_cycles     <= 14'd0;
            o_processing     <= 1'b0;
            o_time_left      <= 4'd0;
            o_completed      <= 1'b0;
        end else begin
            case (state)
                STATE_IDLE: begin
                    // Shift in the serial data for start sequence detection
                    pattern_reg <= {pattern_reg[2:0], i_data_in};
                    if (pattern_reg == 4'b1101) begin
                        state <= STATE_CONFIGURE;
                        // Optionally clear pattern_reg here if desired
                    end
                    o_processing <= 1'b0;
                    o_completed  <= 1'b0;
                    o_time_left  <= 4'd0;  // Don't-care in idle state
                end

                STATE_CONFIGURE: begin
                    // Shift in the next 4 bits to configure the delay (MSB first)
                    if (config_bit_count < 2'd3) begin
                        delay          <= {delay[2:0], i_data_in};
                        config_bit_count <= config_bit_count + 1;
                    end else begin
                        // Last configuration bit received; calculate total counting cycles
                        total_cycles   <= (delay + 1) * COUNT_THRESHOLD;
                        cycle_count    <= 14'd0;
                        decrement_count<= 4'd0;
                        state          <= STATE_COUNTING;
                        config_bit_count <= 2'd0;  // Reset configuration bit counter
                    end
                    o_processing <= 1'b0;
                    o_completed  <= 1'b0;
                    o_time_left  <= 4'd0;
                end

                STATE_COUNTING: begin
                    // Increment the cycle counter each clock cycle
                    cycle_count <= cycle_count + 1;
                    // Every 1000 cycles, increment the decrement counter
                    if (cycle_count == COUNT_THRESHOLD - 1)
                        decrement_count <= decrement_count + 1;
                    // Transition to DONE state when the total cycle count is reached
                    if (cycle_count == total_cycles - 1)
                        state <= STATE_DONE;

                    o_processing <= 1'b1;
                    // o_time_left decrements every 1000 cycles:
                    // For the first 1000 cycles, o_time_left = delay;
                    // Then it decrements by 1 every subsequent 1000 cycles, clamped to 0.
                    if (delay > decrement_count)
                        o_time_left <= delay - decrement_count;
                    else
                        o_time_left <= 4'd0;
                    o_completed  <= 1'b0;
                end

                STATE_DONE: begin
                    o_completed  <= 1'b1;
                    o_processing <= 1'b0;
                    // Wait for the acknowledgment signal to reset the module
                    if (i_ack) begin
                        state            <= STATE_IDLE;
                        cycle_count      <= 14'd0;
                        decrement_count  <= 4'd0;
                        delay            <= 4'd0;
                        total_cycles     <= 14'd0;
                        config_bit_count <= 2'd0;
                        pattern_reg      <= 4'd0;
                    end
                end

                default: state <= STATE_IDLE;
            endcase
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequencial #(
    parameter BINARY_WIDTH = 5,
    parameter OUTPUT_WIDTH = 32
)(
    input  wire                      i_clk,
    input  wire                      i_rstb,
    input  wire [BINARY_WIDTH-1:0]   i_binary_in,
    output reg  [OUTPUT_WIDTH-1:0]   o_one_hot_out
);

  // Parameter check: Ensure OUTPUT_WIDTH is large enough to represent all values up to 2^BINARY_WIDTH - 1.
  generate
    if (OUTPUT_WIDTH < (1 << BINARY_WIDTH)) begin : param_check
      $error("Parameter ERROR: OUTPUT_WIDTH (%0d) must be >= 2^(BINARY_WIDTH) (%0d) for BINARY_WIDTH=%0d.",
             OUTPUT_WIDTH, (1 << BINARY_WIDTH), BINARY_WIDTH);
    end
  endgenerate

  // Sequential process: Sample the binary input on the rising edge of the clock and update the one-hot output.
  always @(posedge i_clk or negedge i_rstb) begin : one_hot_proc
    integer j;
    reg [OUTPUT_WIDTH-1:0] one_hot;

    if (!i_rstb) begin
      o_one_hot_out <= {OUTPUT_WIDTH{1'b0}};
    end else begin
      // Initialize the one-hot temporary register to all zeros.
      one_hot = {OUTPUT_WIDTH{1'b0}};
      // Loop through all bits of the output vector.
      for (j = 0; j < OUTPUT_WIDTH; j = j + 1) begin
         // Set the bit corresponding to the sampled binary input.
         if (j == i_binary_in)
            one_hot[j] = 1'b1;
         else
            one_hot[j] = 1'b0;
      end
      o_one_hot_out <= one_hot;
    end
  end

endmodule

