module sipo_top#(
    parameter DATA_WIDTH = 16,
    parameter SHIFT_DIRECTION = 1,
    parameter CODE_WIDTH = DATA_WIDTH + $clog2(DATA_WIDTH + 1),
    parameter CRC_WIDTH = DATA_WIDTH / 2,
    parameter POLY = 8'b10101010
)(
    input clk,
    input reset_n,
    input serial_in,
    input shift_en,
    input [CODE_WIDTH-1:0] received,
    input [CRC_WIDTH-1:0] received_crc,
    output done,
    output [DATA_WIDTH-1:0] data_out,
    output [CODE_WIDTH-1:0] encoded,
    output error_detected,
    output error_corrected,
    output [CRC_WIDTH-1:0] crc_out,
    output crc_error
);

    // Wires connecting sub-modules
    wire [DATA_WIDTH-1:0] parallel_out;
    wire [DATA_WIDTH-1:0] sipo_out_ecc_in;

    // Instantiate serial_in_parallel_out_8bit
    serial_in_parallel_out_8bit  #(.WIDTH(DATA_WIDTH), .SHIFT_DIRECTION(SHIFT_DIRECTION)) uut_sipo (
        .clk           (clk),
        .reset_n       (reset_n),
        .sin           (serial_in),
        .shift_en      (shift_en),
        .done          (done),
        .parallel_out  (parallel_out)
    );

    // Instantiate onebit_ecc for Hamming encoding and single-bit error correction
    onebit_ecc #(.DATA_WIDTH(DATA_WIDTH), .CODE_WIDTH(CODE_WIDTH)) uut_onebit_ecc1 (
        .data_in       (parallel_out),
        .encoded       (encoded),
        .received      (received),
        .data_out      (data_out),
        .error_detected(error_detected),
        .error_corrected(error_corrected)
    );

    // Instantiate crc_generator to compute CRC from the SIPO output data
    crc_generator #(.DATA_WIDTH(DATA_WIDTH), .CRC_WIDTH(CRC_WIDTH), .POLY(POLY)) uut_crc (
        .clk          (clk),
        .rst          (reset_n),
        .data_in      (parallel_out),
        .crc_out      (crc_out)
    );

    // Compare generated CRC with received CRC and assert error if mismatch
    assign crc_error = (crc_out != received_crc);

endmodule

// ------------------------------------------------------------------
// Module: serial_in_parallel_out_8bit
// Description: Converts serial input into parallel output using a configurable shift direction.
// ------------------------------------------------------------------
module serial_in_parallel_out_8bit  #(
    parameter WIDTH = 64,
    parameter SHIFT_DIRECTION = 1
)(
    input clk,
    input reset_n,
    input sin,
    input shift_en,
    output reg done,
    output reg [WIDTH-1:0] parallel_out
);

    localparam COUNT_WIDTH = $clog2(WIDTH);
    reg [COUNT_WIDTH:0] shift_count;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin                                   
            parallel_out     <= {WIDTH{1'b0}};                
            done             <= 1'b0;                         
            shift_count      <= {COUNT_WIDTH{1'b0}};          
        end else begin
            if (shift_en) begin
                if (SHIFT_DIRECTION) begin
                    parallel_out    <= {parallel_out[WIDTH-2:0], sin}; 
                end else begin
                    parallel_out    <= {sin, parallel_out[WIDTH-1:1]}; 
                end
                shift_count   <= shift_count + 1;                      
            end

            if (shift_count == (WIDTH - 1)) begin
                done         <= 1'b1;                                 
                shift_count  <= {COUNT_WIDTH{1'b0}};                  
            end else begin
                done         <= 1'b0;                                  
            end
        end
    end 
endmodule

// ------------------------------------------------------------------
// Module: onebit_ecc
// Description: Generates Hamming code from input data and performs single-bit error detection and correction.
// ------------------------------------------------------------------
module onebit_ecc #(
    parameter DATA_WIDTH = 4,
    parameter CODE_WIDTH = DATA_WIDTH + $clog2(DATA_WIDTH + 1)
)(
    input [DATA_WIDTH-1:0] data_in,
    output reg [CODE_WIDTH-1:0] encoded,
    input [CODE_WIDTH-1:0] received,
    output reg [DATA_WIDTH-1:0] data_out,
    output reg error_detected,
    output reg error_corrected
);

    localparam PARITY_BITS = CODE_WIDTH - DATA_WIDTH;
    reg [PARITY_BITS-1:0] syndrome;
    reg [CODE_WIDTH-1:0] corrected_data;
    integer idx_i, idx_j, idx_k;
    integer idx_m, idx_n;
    integer idx_p, idx_q;

    // Generate encoded data by interleaving data and parity bits
    always @(*) begin
        encoded = 0;
        idx_k = 0;
        for (idx_i = 0; idx_i < CODE_WIDTH; idx_i = idx_i + 1) begin
            if ((idx_i + 1) & (idx_i)) begin
                encoded[idx_i] = data_in[idx_k];
                idx_k = idx_k + 1;
            end
        end

        // Calculate parity bits
        for (idx_i = 0; idx_i < PARITY_BITS; idx_i = idx_i + 1) begin
            encoded[(1 << idx_i) - 1] = 0; 
            for (idx_j = 0; idx_j < CODE_WIDTH; idx_j = idx_j + 1) begin
                if (((idx_j + 1) & (1 << idx_i)) && ((idx_j + 1) != (1 << idx_i))) begin
                    encoded[(1 << idx_i) - 1] = encoded[(1 << idx_i) - 1] ^ encoded[idx_j];
                end
            end
        end
    end

    // Compute syndrome for error detection
    always @(*) begin
        syndrome = 0; 
        for (idx_m = 0; idx_m < PARITY_BITS; idx_m = idx_m + 1) begin
            for (idx_n = 0; idx_n < CODE_WIDTH; idx_n = idx_n + 1) begin
                if ((idx_n + 1) & (1 << idx_m)) begin
                    syndrome[idx_m] = syndrome[idx_m] ^ received[idx_n];
                end
            end
        end
    end

    // Assert error_detected if any syndrome bit is high
    always @(*) begin
        error_detected = |syndrome; 
    end

    // Correct single-bit error if detected
    always @(*) begin
        corrected_data = received;
        if (error_detected) begin
            corrected_data[syndrome - 1] = ~corrected_data[syndrome - 1]; 
        end
    end

    // Extract original data from corrected data
    always @(*) begin
        idx_q = 0;
        for (idx_p = 0; idx_p < CODE_WIDTH; idx_p = idx_p + 1) begin
            if ((idx_p + 1) & (idx_p)) begin
                data_out[idx_q] = corrected_data[idx_p];
                idx_q = idx_q + 1;
            end
        end
    end

    // Pass through the error_detected flag as error_corrected
    always @(*) begin
        error_corrected = error_detected; 
    end

endmodule

// ------------------------------------------------------------------
// Module: crc_generator
// Description: Computes the CRC for the input data using a given polynomial.
// Inputs:
//   - data_in: DATA_WIDTH-bit data (MSB first)
//   - clk: Clock signal (50:50 duty cycle)
//   - rst: Active low synchronous reset (when asserted, crc_out is zero)
// Outputs:
//   - crc_out: CRC result (CRC_WIDTH bits)
// ------------------------------------------------------------------
module crc_generator #(
    parameter DATA_WIDTH = 16,
    parameter CRC_WIDTH = DATA_WIDTH / 2,
    parameter POLY = 8'b10101010
)(
    input clk,
    input rst, // Active low reset: when rst is low, crc_out is reset to 0
    input [DATA_WIDTH-1:0] data_in,
    output reg [CRC_WIDTH-1:0] crc_out
);
    integer i;
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            crc_out <= 0;
        end else begin
            // Local register to hold the shifting CRC value
            reg [CRC_WIDTH-1:0] crc_reg;
            crc_reg = 0;
            // Process each bit of data_in (MSB first)
            for (i = 0; i < DATA_WIDTH; i = i + 1) begin
                // If MSB of crc_reg XOR current data bit is 1, apply XOR with POLY
                if (crc_reg[CRC_WIDTH-1] ^ data_in[i])
                    crc_reg = (crc_reg << 1) ^ POLY;
                else
                    crc_reg = crc_reg << 1;
            end
            crc_out <= crc_reg;
        end
    end
endmodule

output.rtl/SetBitStreamCalculator.v:
module SetBitStreamCalculator #(
    parameter p_max_set_bit_count_width = 8
)(
    input  wire i_clk,
    input  wire i_rst_n,         // asynchronous active-low reset
    input  wire i_bit_in,        // single-bit input stream
    input  wire i_ready,         // when high, enables counting; transition from low to high resets count
    output reg  [p_max_set_bit_count_width-1:0] o_set_bit_count
);

    // Maximum count value based on parameter width
    localparam integer MAX_COUNT = (1 << p_max_set_bit_count_width) - 1;

    // Register to detect transition from low to high on i_ready
    reg ready_prev;
    // Flag to indicate that the first bit after i_ready transition should be ignored
    reg first_cycle;

    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            o_set_bit_count <= 0;
            ready_prev      <= 0;
            first_cycle     <= 0;
        end else begin
            // Update previous ready value
            ready_prev <= i_ready;

            // Detect transition from low to high: reset count and set first_cycle flag
            if (i_ready && !ready_prev) begin
                o_set_bit_count <= 0;
                first_cycle     <= 1;
            end 
            // When i_ready is high, process the bit stream
            else if (i_ready) begin
                if (first_cycle) begin
                    // First bit after transition: ignore it and clear the flag
                    first_cycle <= 0;
                end 
                else begin
                    // Count normally: increment count if i_bit_in is 1 and not saturated
                    if (i_bit_in) begin
                        if (o_set_bit_count == MAX_COUNT)
                            o_set_bit_count <= MAX_COUNT; // saturate
                        else
                            o_set_bit_count <= o_set_bit_count + 1;
                    end
                end
            end
            // When i_ready is low, count holds (no update)
        end
    end

endmodule


// File: verif/SetBitStreamCalculator_tb.v
`timescale 1ns/1ps
module SetBitStreamCalculator_tb;

  // Clock parameters
  parameter CLK_PERIOD = 20;  // 50 MHz clock

  reg clk;
  reg rst_n;
  reg bit_in;
  reg ready;

  // Wires for the instance with default parameter (p_max_set_bit_count_width = 8)
  wire [7:0] set_bit_count_8;
  // Wires for the instance with parameter 4 (for saturation test)
  wire [3:0] set_bit_count_4;

  // Instantiate module with default parameter (8-bit count)
  SetBitStreamCalculator #(
      .p_max_set_bit_count_width(8)
  ) dut_8 (
      .i_clk(clk),
      .i_rst_n(rst_n),
      .i_bit_in(bit_in),
      .i_ready(ready),
      .o_set_bit_count(set_bit_count_8)
  );

  // Instantiate module with parameter 4 (maximum count = 15)
  SetBitStreamCalculator #(
      .p_max_set_bit_count_width(4)
  ) dut_4 (
      .i_clk(clk),
      .i_rst_n(rst_n),
      .i_bit_in(bit_in),
      .i_ready(ready),
      .o_set_bit_count(set_bit_count_4)
  );

  // Clock generation
  initial begin
      clk = 0;
      forever #(CLK_PERIOD/2) clk = ~clk;
  end

  // Testbench stimulus
  initial begin
      // Initialize signals
      rst_n = 0;
      ready = 0;
      bit_in = 0;
      # (CLK_PERIOD*2);
      rst_n = 1;  // Deassert asynchronous reset

      //--------------------------------------------------------------------------
      // Scenario 1: Counting set bits with p_max_set_bit_count_width = 8
      // Sequence: i_ready asserted; bit sequence: 1, 0, 1, 1.
      // The first bit after i_ready goes high is ignored.
      // Expected count: 3 (only the two 1's after the first bit are counted).
      //--------------------------------------------------------------------------

      $display("Scenario 1: Counting set bits with p_max_set_bit_count_width = 8");
      ready = 1;  // Assert i_ready to start counting
      # (CLK_PERIOD);
      bit_in = 1; // First bit (ignored)
      # (CLK_PERIOD);
      bit_in = 0;
      # (CLK_PERIOD);
      bit_in = 1;
      # (CLK_PERIOD);
      bit_in = 1;
      # (CLK_PERIOD*2);
      if (set_bit_count_8 == 3)
          $display("Scenario 1 Passed: o_set_bit_count_8 = %d", set_bit_count_8);
      else
          $display("Scenario 1 Failed: o_set_bit_count_8 = %d (expected 3)", set_bit_count_8);

      //--------------------------------------------------------------------------
      // Scenario 2: Reset Behavior
      // While counting, assert asynchronous reset (i_rst_n low) to reset the count.
      //--------------------------------------------------------------------------

      ready = 0;  // Deassert i_ready to hold the current count
      # (CLK_PERIOD*2);
      ready = 1;  // Assert i_ready again to resume counting
      $display("Scenario 2: Reset Behavior");
      bit_in = 1;
      # (CLK_PERIOD);
      rst_n = 0;  // Assert asynchronous reset (active low)
      # (CLK_PERIOD);
      rst_n = 1;  // Deassert reset
      # (CLK_PERIOD);
      if (set_bit_count_8 == 0)
          $display("Scenario 2 Passed: o_set_bit_count_8 reset to 0");
      else
          $display("Scenario 2 Failed: o_set_bit_count_8 = %d (expected 0)", set_bit_count_8);

      //--------------------------------------------------------------------------
      // Scenario 3: Saturation Test with p_max_set_bit_count_width = 4
      // Apply 16 consecutive 1's. The first bit is ignored, so 15 ones should be counted.
      // With saturation, the maximum count is 15.
      //--------------------------------------------------------------------------

      $display("Scenario 3: Saturation test with p_max_set_bit_count_width = 4");
      ready = 1;  // Assert i_ready to start counting in dut_4
      # (CLK_PERIOD);
      // Apply 16 consecutive 1's
      repeat (16) begin
          bit_in = 1;
          # (CLK_PERIOD);
      end
      # (CLK_PERIOD*2);
      if (set_bit_count_4 == 15)
          $display("Scenario 3 Passed: o_set_bit_count_4 = %d", set_bit_count_4);
      else
          $display("Scenario 3 Failed: o_set_bit_count_4 = %d (expected 15)", set_bit_count_4);

      $display("Testbench finished.");
      # (CLK_PERIOD*10);
      $finish;
  end

endmodule

