module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

    // State encoding
    localparam IDLE   = 2'b00;
    localparam LOAD   = 2'b01;
    localparam COMPUTE= 2'b10;
    localparam OUTPUT = 2'b11;

    // Internal registers
    reg [1:0] state;
    reg [DATA_WIDTH-1:0] operand_a_reg;
    reg [DATA_WIDTH-1:0] operand_b_reg;
    reg [DATA_WIDTH-1:0] result_reg;

    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state            <= IDLE;
            operand_a_reg    <= {DATA_WIDTH{1'b0}};
            operand_b_reg    <= {DATA_WIDTH{1'b0}};
            result_reg       <= {DATA_WIDTH{1'b0}};
            o_resultant_sum  <= {DATA_WIDTH{1'b0}};
            o_overflow       <= 1'b0;
            o_ready          <= 1'b0;
            o_status         <= IDLE;
        end else begin
            if (i_clear) begin
                // Clear outputs and reset state
                state            <= IDLE;
                operand_a_reg    <= {DATA_WIDTH{1'b0}};
                operand_b_reg    <= {DATA_WIDTH{1'b0}};
                result_reg       <= {DATA_WIDTH{1'b0}};
                o_resultant_sum  <= {DATA_WIDTH{1'b0}};
                o_overflow       <= 1'b0;
                o_ready          <= 1'b0;
                o_status         <= IDLE;
            end else begin
                case (state)
                    IDLE: begin
                        // Wait for start signal and enable
                        if (i_enable && i_start)
                            state <= LOAD;
                        else
                            state <= IDLE;
                        o_status <= IDLE;
                        o_ready  <= 1'b0;
                    end
                    LOAD: begin
                        // Capture operands
                        state            <= COMPUTE;
                        operand_a_reg    <= i_operand_a;
                        operand_b_reg    <= i_operand_b;
                        o_status         <= LOAD;
                        o_ready          <= 1'b0;
                    end
                    COMPUTE: begin
                        // Perform addition or subtraction based on mode
                        state            <= OUTPUT;
                        result_reg       <= (i_mode ? operand_a_reg - operand_b_reg : operand_a_reg + operand_b_reg);
                        o_status         <= COMPUTE;
                        o_ready          <= 1'b0;
                    end
                    OUTPUT: begin
                        // Update outputs and check for overflow
                        state            <= IDLE;
                        o_resultant_sum  <= result_reg;
                        o_overflow       <= ((~operand_a_reg[DATA_WIDTH-1] & ~operand_b_reg[DATA_WIDTH-1] & result_reg[DATA_WIDTH-1]) |
                                            ( operand_a_reg[DATA_WIDTH-1] & operand_b_reg[DATA_WIDTH-1] & ~result_reg[DATA_WIDTH-1]));
                        o_ready          <= 1'b1;
                        o_status         <= OUTPUT;
                    end
                    default: state <= IDLE;
                endcase
            end
        end
    end

endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,       // System clock
    input  wire         i_rst_b,     // Active-low async reset
    input  wire [15:0]  i_data_in,   // 16-bit data to transmit
    input  wire         i_enable,    // Enable block
    input  wire         i_fault,     // Fault indicator
    input  wire         i_clear,     // Forces FSM to clear/idle

    output reg          o_spi_cs_b,  // SPI chip select (active-low)
    output reg          o_spi_clk,   // SPI clock
    output reg          o_spi_data,  // Serialized SPI data out
    output reg [4:0]    o_bits_left, // Bits remaining to transmit (default: 16)
    output reg          o_done,      // One-cycle pulse when done or error
    output reg [1:0]    o_fsm_state  // FSM state: 00=Idle, 01=Transmit, 10=Clock Toggle, 11=Error
);

  // State encoding
  localparam IDLE   = 2'b00;
  localparam TX     = 2'b01;
  localparam CLKTOG = 2'b10;
  localparam ERROR  = 2'b11;

  // Internal registers
  reg [1:0] state;
  reg [15:0] shift_reg;  // Shift register holding data to be transmitted
  reg [4:0] bits_left;   // Number of bits remaining
  reg toggle_clk;        // Internal clock toggle signal

  // Asynchronous reset and control signals have highest priority.
  // i_fault: Transition to ERROR state.
  // i_clear: Immediately go to IDLE.
  always @(posedge i_clk or negedge i_rst_b) begin
    if (!i_rst_b) begin
      state         <= IDLE;
      o_spi_cs_b    <= 1'b1;
      o_spi_clk     <= 1'b0;
      o_spi_data    <= 1'b0;
      bits_left     <= 5'd16;
      o_done        <= 1'b0;
      o_fsm_state   <= 2'b00;
      shift_reg     <= 16'd0;
      toggle_clk    <= 1'b0;
    end
    else begin
      // Check for fault or clear conditions first.
      if (i_fault) begin
        state         <= ERROR;
        o_spi_cs_b    <= 1'b1;
        o_spi_clk     <= 1'b0;
        o_spi_data    <= 1'b0;
        bits_left     <= 5'd16;
        o_done        <= 1'b0;
        o_fsm_state   <= 2'b11;
        shift_reg     <= 16'd0;
        toggle_clk    <= 1'b0;
      end
      else if (i_clear) begin
        state         <= IDLE;
        o_spi_cs_b    <= 1'b1;
        o_spi_clk     <= 1'b0;
        o_spi_data    <= 1'b0;
        bits_left     <= 5'd16;
        o_done        <= 1'b0;
        o_fsm_state   <= 2'b00;
        shift_reg     <= 16'd0;
        toggle_clk    <= 1'b0;
      end
      else begin
        case (state)
          IDLE: begin
            // In Idle: Wait for i_enable to start transmission.
            if (i_enable) begin
              state         <= TX;
              shift_reg     <= i_data_in;  // Load data into shift register
              bits_left     <= 5'd16;       // Reset bit counter to 16
              o_spi_cs_b    <= 1'b0;        // Assert chip select (active low)
              o_spi_clk     <= 1'b0;        // Start with clock low
              o_spi_data    <= shift_reg[15]; // Output MSB
              o_done        <= 1'b0;
              o_fsm_state   <= 2'b01;       // TX state
              toggle_clk    <= 1'b0;
            end
            else begin
              state         <= IDLE;
              o_spi_cs_b    <= 1'b1;        // Deassert CS when idle
              o_spi_clk     <= 1'b0;
              o_spi_data    <= 1'b0;
              bits_left     <= bits_left;   // Remain unchanged
              o_done        <= 1'b0;
              o_fsm_state   <= 2'b00;
              toggle_clk    <= 1'b0;
            end
          end

          TX: begin
            // In Transmit: Simply transition to Clock Toggle.
            state         <= CLKTOG;
            o_spi_cs_b    <= 1'b0;
            o_spi_clk     <= 1'b0;
            o_spi_data    <= shift_reg[15];
            o_done        <= 1'b0;
            o_fsm_state   <= 2'b01;
            toggle_clk    <= 1'b0;
          end

          CLKTOG: begin
            // Toggle the SPI clock.
            toggle_clk    <= ~toggle_clk;
            o_spi_clk     <= toggle_clk;
            // Shift the data left by one bit.
            shift_reg     <= shift_reg << 1;
            // Decrement the bit counter.
            bits_left     <= bits_left - 1;
            // Check if all bits have been transmitted.
            if ((bits_left - 1) == 5'd0) begin
              state         <= IDLE;
              o_done        <= 1'b1;  // Assert done pulse for one cycle
              o_fsm_state   <= 2'b00;
              o_spi_cs_b    <= 1'b1;  // Deassert chip select
              o_spi_clk     <= 1'b0;
              o_spi_data    <= 1'b0;
            end
            else begin
              state         <= TX;
              o_done        <= 1'b0;
              o_fsm_state   <= 2'b01;
              o_spi_cs_b    <= 1'b0;
              o_spi_clk     <= 1'b0;
              o_spi_data    <= shift_reg[15];
            end
          end

          ERROR: begin
            // In Error state: Hold outputs at safe defaults.
            state         <= ERROR;
            o_spi_cs_b    <= 1'b1;
            o_spi_clk     <= 1'b0;
            o_spi_data    <= 1'b0;
            bits_left     <= 5'd16;
            o_done        <= 1'b0;
            o_fsm_state   <= 2'b11;
            shift_reg     <= 16'd0;
            toggle_clk    <= 1'b0;
          end

          default: begin
            state         <= IDLE;
            o_spi_cs_b    <= 1'b1;
            o_spi_clk     <= 1'b0;
            o_spi_data    <= 1'b0;
            bits_left     <= 5'd16;
            o_done        <= 1'b0;
            o_fsm_state   <= 2'b00;
            shift_reg     <= 16'd0;
            toggle_clk    <= 1'b0;
          end
        endcase
      end
    end
  end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8,
    parameter p_max_numbers = 16
)(
    input wire i_clk,
    input wire i_rst_n,
    input wire i_ready,
    input wire [p_bit_width-1:0] i_number,
    output reg [p_bit_width-1:0] o_unique_number
);

    // Register to accumulate the XOR of all numbers seen so far.
    reg [p_bit_width-1:0] xor_reg;

    // Synchronous process with asynchronous active-low reset.
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            xor_reg <= {p_bit_width{1'b0}};
            o_unique_number <= {p_bit_width{1'b0}};
        end else begin
            if (i_ready) begin
                // XOR the incoming number with the current accumulator.
                xor_reg <= xor_reg ^ i_number;
            end
            // Continuously update the output with the current XOR result.
            o_unique_number <= xor_reg;
        end
    end

endmodule

