module soundgenerator #(
	parameter CLOCK_HZ = 10_000_000
)(
	input wire clk,                                         // input clock signal with frequency 10 MHz
	input wire nrst,                                        // active low asynchronous reset.

	input wire start,                                       // indicate the start of the operation.
	input wire finish,                                      // indicate the end of operation.
	input wire [15:0] sond_dur_ms_i,                        // duration (in milliseconds) for which the sound should be generated
	input wire [15:0] half_period_us_i,                     // half period of the soundwave in microseconds

	output wire soundwave_o,                                // generated soundwave output (square wave)
	output wire busy,                                       // indicates the system is actively generating sound
	output wire done                                        // indicates that the sound generation operation is complete
);

	// Internal strobe signals from timing generators
	wire ms_strobe;  // 1ms strobe pulse
	wire us_strobe;  // 1us strobe pulse

	// Instantiate the millisecond strobe generator (TickMilli)
	strob_gen #(
		.CLOCK_HZ(CLOCK_HZ),
		.PERIOD_US(1000)  // 1 ms = 1000 µs
	) ms_strob_gen_inst (
		.clk(clk),
		.nrst(nrst),
		.enable(busy),  // enable strobe generation only when busy
		.strobe_o(ms_strobe)
	);

	// Instantiate the microsecond strobe generator (TickMicro)
	strob_gen #(
		.CLOCK_HZ(CLOCK_HZ),
		.PERIOD_US(1)   // 1 µs
	) us_strob_gen_inst (
		.clk(clk),
		.nrst(nrst),
		.enable(busy),  // enable strobe generation only when busy
		.strobe_o(us_strobe)
	);

	// Internal registers for timing and signal generation
	reg [15:0] duration_counter;   // counts remaining milliseconds
	reg [15:0] halfperiod_counter; // counts microseconds for the half period
	reg soundwave_reg;             // internal soundwave signal register
	reg busy_reg;                  // internal busy flag
	reg done_reg;                  // one-cycle done signal

	// Drive outputs: soundwave output is active only when busy; busy and done pass through
	assign soundwave_o = busy_reg ? soundwave_reg : 1'b0;
	assign busy         = busy_reg;
	assign done         = done_reg;

	// Main state and counter logic
	always @(posedge clk or negedge nrst) begin
		if (!nrst) begin
			// Reset all internal states
			duration_counter   <= 16'd0;
			halfperiod_counter <= 16'd0;
			soundwave_reg      <= 1'b0;
			busy_reg           <= 1'b0;
			done_reg           <= 1'b0;
		end else begin
			// When start is asserted and system is idle, load counters and start generation.
			if (start && !busy_reg) begin
				duration_counter   <= sond_dur_ms_i;
				halfperiod_counter <= half_period_us_i;
				soundwave_reg      <= 1'b0;
				busy_reg           <= 1'b1;
			end

			// If finish is asserted, immediately stop generation.
			if (finish) begin
				busy_reg      <= 1'b0;
				done_reg      <= 1'b1;
				duration_counter   <= 16'd0;
				halfperiod_counter <= 16'd0;
				soundwave_reg      <= 1'b0;
			end else if (busy_reg) begin
				// On every 1ms strobe pulse, decrement the duration counter.
				if (ms_strobe) begin
					if (duration_counter == 16'd1)
						duration_counter <= 16'd0;
					else
						duration_counter <= duration_counter - 16'd1;
				end

				// On every 1us strobe pulse, decrement the half-period counter.
				// When it reaches zero, toggle the soundwave signal and reload the counter.
				if (us_strobe) begin
					halfperiod_counter <= halfperiod_counter - 16'd1;
					if (halfperiod_counter == 16'd0) begin
						soundwave_reg      <= ~soundwave_reg;
						halfperiod_counter <= half_period_us_i;
					end
				end

				// If the duration counter has expired, stop generation and assert done.
				if (duration_counter == 16'd0) begin
					busy_reg <= 1'b0;
					done_reg <= 1'b1;
				end
			end
			// When not busy, no action is taken.
		end
	end

endmodule

module strob_gen #(
	parameter CLOCK_HZ = 10_000_000,
	parameter PERIOD_US = 100
)(
	input wire clk,
	input wire nrst,
	input wire enable,
	output reg strobe_o
);

	// Calculate delay in clock cycles based on clock frequency and desired period.
	localparam integer DELAY = (CLOCK_HZ / 1_000_000) * PERIOD_US;

	reg [31:0] counter;

	always @(posedge clk or negedge nrst) begin
		if (!nrst) begin
			counter   <= DELAY;
			strobe_o  <= 1'b0;
		end else begin
			// When enable is low, reset counter and suppress strobe output.
			if (!enable) begin
				counter   <= DELAY;
				strobe_o  <= 1'b0;
			end else begin
				if (counter == 1) begin
					strobe_o <= 1'b1;
					counter  <= DELAY;
				end else begin
					strobe_o <= 1'b0;
					counter  <= counter - 1;
				end
			end
		end
	end

endmodule

output.rtl/sprite_fsm.sv:
module sprite_controller_fsm#(
   parameter MEM_ADDR_WIDTH = 16,
   parameter PIXEL_WIDTH    = 24,
   parameter SPRITE_WIDTH   = 16,
   parameter SPRITE_HEIGHT  = 16,
   parameter WAIT_WIDTH     = 4,
   parameter N_ROM          = 256
)(
   input  logic clk,
   input  logic rst_n,
   input  logic [WAIT_WIDTH-1:0] i_wait,
   output logic rw,                             
   output logic [MEM_ADDR_WIDTH-1:0] write_addr,
   output logic [PIXEL_WIDTH-1:0] write_data,   
   output logic [SPRITE_WIDTH-1:0] x_pos,       
   output logic [SPRITE_HEIGHT-1:0] y_pos,      
   input  logic [PIXEL_WIDTH-1:0] pixel_out,    
   output logic done                            
);

   // FSM state declaration
   typedef enum logic [2:0] {
       IDLE,
       INIT_WRITE,
       WRITE,
       INIT_READ,
       READ,
       WAIT,
       DONE
   } state_t;

   state_t current_state, next_state;

   // Counters and wait counter
   logic [MEM_ADDR_WIDTH-1:0] addr_counter; 
   logic [PIXEL_WIDTH-1:0]    data_counter;    
   logic [WAIT_WIDTH-1:0]     wait_counter;     

   // Next state logic
   always_comb begin
      next_state = current_state;
      case(current_state)
         IDLE:         next_state = INIT_WRITE;
         INIT_WRITE:   next_state = WRITE;
         WRITE:        if (addr_counter == (N_ROM - 1))
                         next_state = INIT_READ;
                      else
                         next_state = WRITE;
         INIT_READ:    next_state = READ;
         READ:         if (addr_counter == (N_ROM - 1))
                         next_state = WAIT;
                      else
                         next_state = READ;
         WAIT:         if (wait_counter == i_wait)
                         next_state = DONE;
                      else
                         next_state = WAIT;
         DONE:         next_state = IDLE;
         default:      next_state = IDLE;
      endcase
   end

   // Sequential logic: state register and counter updates
   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         current_state <= IDLE;
         addr_counter  <= '0;
         data_counter  <= '0;
         wait_counter  <= '0;
         done          <= 1'b0;
      end else begin
         current_state <= next_state;
         case(current_state)
            IDLE: begin
               addr_counter <= '0;
               data_counter <= '0;
               wait_counter <= '0;
               done         <= 1'b0;
            end
            INIT_WRITE: begin
               addr_counter <= '0;
               // write_data will be driven by combinational logic below.
            end
            WRITE: begin
               if (addr_counter == (N_ROM - 1))
                  addr_counter <= addr_counter; // hold at last address
               else begin
                  addr_counter <= addr_counter + 1;
                  data_counter <= data_counter + 1;
               end
            end
            INIT_READ: begin
               addr_counter <= '0;
            end
            READ: begin
               if (addr_counter == (N_ROM - 1))
                  addr_counter <= addr_counter; // hold at last address
               else
                  addr_counter <= addr_counter + 1;
            end
            WAIT: begin
               wait_counter <= wait_counter + 1;
            end
            DONE: begin
               // 'done' remains asserted for one cycle.
            end
         endcase
      end
   end

   // Output logic: drive rw, write_addr, write_data, x_pos, y_pos, and done
   always_comb begin
      // Default assignments
      rw          = 1'b0;
      write_addr  = addr_counter;
      write_data  = data_counter;
      // Calculate x_pos and y_pos using bit slicing.
      // x_pos = addr_counter % SPRITE_WIDTH; for SPRITE_WIDTH=16, use lower 4 bits.
      x_pos       = addr_counter[3:0];
      // y_pos = addr_counter / SPRITE_WIDTH; for SPRITE_HEIGHT=16, use next 4 bits.
      y_pos       = addr_counter[7:4];
      done        = 1'b0;

      case(current_state)
         INIT_WRITE: begin
            write_data = 24'hFF0000;
            rw         = 1'b1;
         end
         WRITE: begin
            rw = 1'b1;
         end
         READ: begin
            rw = 1'b0;
         end
         WAIT: begin
            // No additional assignments needed.
         end
         DONE: begin
            done = 1'b1;
         end
      endcase
   end

endmodule

