module square_root_seq #(parameter WIDTH = 16) (
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [WIDTH-1:0] num,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);

    // State encoding: IDLE and COMPUTE
    localparam IDLE   = 2'b00;
    localparam COMPUTE = 2'b01;

    reg [1:0] state;
    reg [WIDTH-1:0] remainder;
    reg [WIDTH-1:0] odd;
    reg [WIDTH/2-1:0] root;

    // Sequential state machine with asynchronous reset
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            state         <= IDLE;
            remainder     <= '0;
            odd           <= '0;
            root          <= '0;
            final_root    <= '0;
            done          <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        // Initialize for a new computation
                        remainder   <= num;
                        odd         <= 1;
                        root        <= 0;
                        final_root  <= 0;
                        done        <= 0;
                        state       <= COMPUTE;
                    end else begin
                        // Remain in IDLE; clear done to ensure it is asserted only for one cycle
                        done <= 0;
                    end
                end
                COMPUTE: begin
                    if (rst) begin
                        state         <= IDLE;
                        remainder     <= '0;
                        odd           <= '0;
                        root          <= '0;
                        final_root    <= '0;
                        done          <= 1'b0;
                    end else begin
                        if (remainder >= odd) begin
                            // Subtract current odd from remainder, update odd and root
                            remainder <= remainder - odd;
                            odd       <= odd + 2;
                            root      <= root + 1;
                        end else begin
                            // Remainder is smaller than the current odd number: computation complete
                            final_root <= root;
                            done       <= 1;
                            state      <= IDLE;
                        end
                    end
                end
                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (
  input  wire [31:0] fetch_rdata_i,
  input  wire [31:0] fetch_pc_i,
  input  wire        fetch_valid_i,
  output reg  [0:0]  predict_branch_taken_o,
  output reg  [31:0] predict_branch_pc_o
);

  // Local parameters for opcodes
  localparam OPCODE_BRANCH = 7'h63;  // Uncompressed branch (BXXX) and compressed branch (C.BEQZ/C.BNEZ)
  localparam OPCODE_JAL    = 7'h6F;  // Uncompressed jump (JAL) and compressed jump (C.J/C.JAL)
  localparam OPCODE_JALR   = 7'h67;  // Uncompressed jump register (JALR)

  // Alias for the fetched instruction
  wire [31:0] instr = fetch_rdata_i;
  // Extract opcode from bits [6:0]
  wire [6:0] opcode = instr[6:0];

  // Immediate extraction for uncompressed branch instruction (BXXX)
  // Immediate format: { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 }
  wire [31:0] imm_b = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  // Immediate extraction for uncompressed jump (JAL) instruction
  // Immediate format: { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 }
  wire [31:0] imm_j = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };

  // Immediate extraction for uncompressed jump register (JALR) instruction
  // Immediate format: { {20{instr[31]}}, instr[31:20] }
  wire [31:0] imm_jalr = { {20{instr[31]}}, instr[31:20] };

  // Note:
  // For JALR, the target address is defined as:
  //    pc + {{20{instr[31]}}, instr[31:20]} + rs1
  // However, since the register file value for rs1 is not available in this module,
  // we approximate the target address as:
  //    pc + {{20{instr[31]}}, instr[31:20]}
  // This approximation is acceptable for a static branch predictor in the IF stage.

  // Combinational logic for branch prediction
  always_comb begin
    if (!fetch_valid_i) begin
      // If the fetched instruction is not valid, do not predict a branch.
      predict_branch_taken_o = 1'b0;
      predict_branch_pc_o   = 32'd0;
    end else begin
      case (opcode)
        OPCODE_BRANCH: begin
          // Uncompressed branch (BXXX) or compressed branch (C.BEQZ/C.BNEZ)
          // Prediction: branch is taken if the sign bit of the immediate is '1'
          if (imm_b[31])
            predict_branch_taken_o = 1'b1;
          else
            predict_branch_taken_o = 1'b0;
          // Target address = pc + sign-extended immediate
          predict_branch_pc_o = fetch_pc_i + imm_b;
        end
        OPCODE_JAL: begin
          // Uncompressed jump (JAL) or compressed jump (C.J/C.JAL)
          // Jumps are always predicted as taken.
          predict_branch_taken_o = 1'b1;
          predict_branch_pc_o = fetch_pc_i + imm_j;
        end
        OPCODE_JALR: begin
          // Uncompressed jump register (JALR) instruction
          // Always predict taken.
          predict_branch_taken_o = 1'b1;
          // As noted above, rs1 value is not available; using only the immediate.
          predict_branch_pc_o = fetch_pc_i + imm_jalr;
        end
        default: begin
          // For all other instructions (not supported), predict not taken.
          predict_branch_taken_o = 1'b0;
          predict_branch_pc_o   = 32'd0;
        end
      endcase
    end
  end

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

