            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
)(
    input  logic clock,
    input  logic reset,
    input  logic write_en,
    input  logic read_en,
    input  logic [DATA_WIDTH-1:0] data_in,
    output logic empty,
    output logic full,
    output logic [DATA_WIDTH-1:0] data_out
);

    // Calculate the depth of the LIFO (number of storage locations)
    localparam DEPTH = 1 << ADDR_WIDTH;

    // Memory array for storing LIFO data
    reg [DATA_WIDTH-1:0] mem [0:DEPTH-1];

    // Pointer to the top of the LIFO.
    // When top == 0, the LIFO is empty.
    // When top == DEPTH, the LIFO is full.
    logic [ADDR_WIDTH:0] top;

    // Combinational outputs for empty and full flags
    assign empty = (top == 0);
    assign full  = (top == DEPTH);

    // Synchronous process for LIFO operations
    always_ff @(posedge clock) begin
        if (reset) begin
            // Synchronous reset: clear pointer, memory, and output
            top <= 0;
            integer i;
            for (i = 0; i < DEPTH; i = i + 1) begin
                mem[i] <= '0;
            end
            data_out <= '0;
        end else begin
            // Write operation: push data into the LIFO if not full
            if (write_en && !full) begin
                mem[top] <= data_in;
                top <= top + 1;
            end

            // Read operation: pop data from the LIFO if not empty
            if (read_en && !empty) begin
                data_out <= mem[top - 1];
                top <= top - 1;
            end
        end
    end

endmodule

output.rtl/sync_serial_communication_top.sv:
modules:
    • tx_block: Transmits parallel data (8, 16, 32, or 64 bits) by serializing it.
    • rx_block: Receives serialized data and reconstructs the parallel data.
    • sync_serial_communication_top: Top-level module that instantiates tx_block and rx_block.

  The design operates synchronously on clk with an asynchronous active-LOW reset (reset_n).
  The transmitter (tx_block) converts the selected portion of data_in into a serial bit stream.
  The receiver (rx_block) samples the serial data using serial_clk (provided by tx_block)
  and reconstructs the data into data_out according to the sel input.

  Valid sel values:
    3'b000 : No data transmission/reception.
    3'b001 : 8-bit transmission (data_in[7:0]).
    3'b010 : 16-bit transmission (data_in[15:0]).
    3'b011 : 32-bit transmission (data_in[31:0]).
    3'b100 : 64-bit transmission (data_in).

  The rx_block outputs data_out with the received bits placed in the lower bits:
    - For 8 bits: data_out = {56'h0, received[7:0]}
    - For 16 bits: data_out = {48'h0, received[15:0]}
    - For 32 bits: data_out = {32'h0, received[31:0]}
    - For 64 bits: data_out = received[63:0]

  The done signal in rx_block is asserted for one clock cycle when reception is complete.
*/

module tx_block (
    input  logic         clk,
    input  logic         reset_n,
    input  logic [63:0]  data_in,
    input  logic [2:0]   sel,
    output logic         serial_out,
    output logic         done,
    output logic         serial_clk
);
    // Define state machine types
    typedef enum logic {IDLE, TRANSMIT} state_t;
    state_t state, next_state;

    // Registers for shifting data
    logic [63:0] shift_reg;
    logic [5:0]  bit_cnt;   // Counter for bit index (0 to max bits-1)
    logic [5:0]  max_cnt;   // Maximum number of bits to transmit based on sel

    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            state         <= IDLE;
            shift_reg     <= 64'd0;
            bit_cnt       <= 6'd0;
            max_cnt       <= 6'd0;
            serial_out    <= 1'b0;
            serial_clk    <= 1'b0;
            done          <= 1'b0;
        end else begin
            state <= next_state;
            case (state)
                IDLE: begin
                    serial_out <= 1'b0;
                    serial_clk <= 1'b0;  // Fixed state when idle
                    done       <= 1'b0;
                    if (sel != 3'b000) begin
                        // Determine transmission width and load corresponding data
                        case (sel)
                            3'b001: max_cnt <= 6'd8;
                            3'b010: max_cnt <= 6'd16;
                            3'b011: max_cnt <= 6'd32;
                            3'b100: max_cnt <= 6'd64;
                            default: max_cnt <= 6'd0;
                        endcase
                        case (sel)
                            3'b001: shift_reg <= data_in[7:0];
                            3'b010: shift_reg <= data_in[15:0];
                            3'b011: shift_reg <= data_in[31:0];
                            3'b100: shift_reg <= data_in;
                            default: shift_reg <= 64'd0;
                        endcase
                        bit_cnt <= 6'd0;
                        next_state = TRANSMIT;
                    end else begin
                        next_state = IDLE;
                    end
                end
                TRANSMIT: begin
                    bit_cnt <= bit_cnt + 1;
                    // Transmit LSB first
                    serial_out <= shift_reg[bit_cnt];
                    // Gated clock during transmission (equal to clk)
                    serial_clk <= clk;
                    if (bit_cnt == max_cnt - 1) begin
                        done <= 1'b1;
                        next_state = IDLE;
                    end else begin
                        done <= 1'b0;
                        next_state = TRANSMIT;
                    end
                end
            endcase
        end
    end
endmodule

module rx_block (
    input  logic         clk,
    input  logic         reset_n,
    input  logic         data_in,  // Serial input data
    input  logic [2:0]   sel,
    input  logic         serial_clk,
    output logic [63:0]  data_out,
    output logic         done
);
    // Define state machine types
    typedef enum logic {IDLE, RECEIVE} state_t;
    state_t state, next_state;

    // Registers for shifting in received bits
    logic [63:0] shift_reg;
    logic [5:0]  bit_cnt;   // Bit counter for received bits
    logic [5:0]  max_cnt;   // Maximum number of bits to receive based on sel

    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            state         <= IDLE;
            shift_reg     <= 64'd0;
            bit_cnt       <= 6'd0;
            max_cnt       <= 6'd0;
            data_out      <= 64'd0;
            done          <= 1'b0;
        end else begin
            state <= next_state;
            case (state)
                IDLE: begin
                    data_out <= 64'd0;
                    done     <= 1'b0;
                    if (sel != 3'b000) begin
                        // Determine reception width
                        case (sel)
                            3'b001: max_cnt <= 6'd8;
                            3'b010: max_cnt <= 6'd16;
                            3'b011: max_cnt <= 6'd32;
                            3'b100: max_cnt <= 6'd64;
                            default: max_cnt <= 6'd0;
                        endcase
                        bit_cnt <= 6'd0;
                        next_state = RECEIVE;
                    end else begin
                        next_state = IDLE;
                    end
                end
                RECEIVE: begin
                    // Sample on the active serial_clk (assumed synchronous with clk during transmission)
                    if (serial_clk) begin
                        // Shift in the new bit; accumulating LSB first
                        shift_reg <= {shift_reg[62:0], data_in};
                        bit_cnt <= bit_cnt + 1;
                        if (bit_cnt == max_cnt - 1) begin
                            // Reception complete; construct data_out based on sel
                            case (sel)
                                3'b001: data_out <= {56'd0, shift_reg[7:0]};
                                3'b010: data_out <= {48'd0, shift_reg[15:0]};
                                3'b011: data_out <= {32'd0, shift_reg[31:0]};
                                3'b100: data_out <= shift_reg;
                                default: data_out <= 64'd0;
                            endcase
                            done <= 1'b1;
                            next_state = IDLE;
                        end else begin
                            done <= 1'b0;
                            next_state = RECEIVE;
                        end
                    end else begin
                        next_state = RECEIVE;
                    end
                end
            endcase
        end
    end
endmodule

module sync_serial_communication_top (
    input  logic         clk,
    input  logic         reset_n,
    input  logic [63:0]  data_in,
    input  logic [2:0]   sel,
    output logic [63:0]  data_out,
    output logic         done
);
    // Wires connecting the transmitter and receiver blocks
    wire serial_out;
    wire serial_clk;

    // Instantiate the transmitter block
    tx_block u_tx (
        .clk        (clk),
        .reset_n    (reset_n),
        .data_in    (data_in),
        .sel        (sel),
        .serial_out (serial_out),
        .done       (),  // tx_block done not used in top-level
        .serial_clk (serial_clk)
    );

    // Instantiate the receiver block
    rx_block u_rx (
        .clk         (clk),
        .reset_n     (reset_n),
        .data_in     (serial_out),
        .sel         (sel),
        .serial_clk  (serial_clk),
        .data_out    (data_out),
        .done        (done)
    );
endmodule

output.rtl/thermostat.v:
module thermostat (
    input  wire         i_clk,    // Clock for sequential logic
    input  wire         i_rst,    // Asynchronous active-low reset
    input  wire [5:0]   i_temp_feedback, // Temperature feedback bits:
                                        // bit5: i_full_cold, bit4: i_medium_cold, bit3: i_low_cold,
                                        // bit2: i_low_hot,   bit1: i_medium_hot, bit0: i_full_hot
    input  wire         i_fan_on, // User control: fan on (1) or off (0)
    input  wire         i_enable, // Enable thermostat (1 = enabled, 0 = disabled)
    input  wire         i_fault,  // Fault condition (1 = fault, overrides outputs)
    input  wire         i_clr,    // Clear fault condition; returns FSM to AMBIENT on next clk
    output reg          o_heater_full,    // Heating control outputs
    output reg          o_heater_medium,
    output reg          o_heater_low,
    output reg          o_aircon_full,    // Cooling control outputs
    output reg          o_aircon_medium,
    output reg          o_aircon_low,
    output reg          o_fan,             // Fan control output
    output reg [2:0]    o_state            // Current FSM state
);

    // FSM state encoding
    localparam HEAT_LOW  = 3'b000;
    localparam HEAT_MED  = 3'b001;
    localparam HEAT_FULL = 3'b010;
    localparam AMBIENT   = 3'b011;
    localparam COOL_LOW  = 3'b100;
    localparam COOL_MED  = 3'b101;
    localparam COOL_FULL = 3'b110;

    reg [2:0] state; // Current state register

    // Sequential process: state and output update
    always @(posedge i_clk or negedge i_rst) begin
        if (!i_rst) begin
            // Asynchronous reset: force FSM to AMBIENT and all outputs to 0
            state          <= AMBIENT;
            o_heater_full  <= 1'b0;
            o_heater_medium<= 1'b0;
            o_heater_low   <= 1'b0;
            o_aircon_full  <= 1'b0;
            o_aircon_medium<= 1'b0;
            o_aircon_low   <= 1'b0;
            o_fan          <= 1'b0;
            o_state        <= AMBIENT;
        end else begin
            reg [2:0] next_state;
            // Determine next state based on override conditions and temperature feedback
            if (i_fault) begin
                // Fault condition: outputs forced 0; state remains unchanged unless cleared
                next_state = state;
                if (i_clr)
                    next_state = AMBIENT;
            end else if (!i_enable) begin
                // Disable condition: force outputs 0 and state to AMBIENT
                next_state = AMBIENT;
            end else begin
                // Normal operation: if clear is asserted, return to AMBIENT; otherwise, use temperature feedback
                if (i_clr)
                    next_state = AMBIENT;
                else begin
                    // Cold conditions have highest priority:
                    if (i_temp_feedback[5])
                        next_state = HEAT_FULL;  // i_full_cold asserted
                    else if (i_temp_feedback[4])
                        next_state = HEAT_MED;   // i_medium_cold asserted
                    else if (i_temp_feedback[3])
                        next_state = HEAT_LOW;   // i_low_cold asserted
                    // Hot conditions (mutually exclusive with cold conditions):
                    else if (i_temp_feedback[0])
                        next_state = COOL_FULL;  // i_full_hot asserted
                    else if (i_temp_feedback[1])
                        next_state = COOL_MED;   // i_medium_hot asserted
                    else if (i_temp_feedback[2])
                        next_state = COOL_LOW;   // i_low_hot asserted
                    else
                        next_state = AMBIENT;    // No heating or cooling required
                end
            end

            state <= next_state;

            // Output logic: if fault or disable, force outputs to 0; otherwise, drive outputs based on state
            if (i_fault || !i_enable) begin
                o_heater_full  <= 1'b0;
                o_heater_medium<= 1'b0;
                o_heater_low   <= 1'b0;
                o_aircon_full  <= 1'b0;
                o_aircon_medium<= 1'b0;
                o_aircon_low   <= 1'b0;
                o_fan          <= 1'b0;
            end else begin
                // Drive heater/aircon outputs based on current state
                case (state)
                    HEAT_LOW: begin
                        o_heater_low   <= 1'b1;
                        o_heater_full  <= 1'b0;
                        o_heater_medium<= 1'b0;
                        o_aircon_full  <= 1'b0;
                        o_aircon_medium<= 1'b0;
                        o_aircon_low   <= 1'b0;
                    end
                    HEAT_MED: begin
                        o_heater_medium<= 1'b1;
                        o_heater_full  <= 1'b0;
                        o_heater_low   <= 1'b0;
                        o_aircon_full  <= 1'b0;
                        o_aircon_medium<= 1'b0;
                        o_aircon_low   <= 1'b0;
                    end
                    HEAT_FULL: begin
                        o_heater_full  <= 1'b1;
                        o_heater_medium<= 1'b0;
                        o_heater_low   <= 1'b0;
                        o_aircon_full  <= 1'b0;
                        o_aircon_medium<= 1'b0;
                        o_aircon_low   <= 1'b0;
                    end
                    COOL_LOW: begin
                        o_aircon_low   <= 1'b1;
                        o_aircon_full  <= 1'b0;
                        o_aircon_medium<= 1'b0;
                        o_heater_full  <= 1'b0;
                        o_heater_medium<= 1'b0;
                        o_heater_low   <= 1'b0;
                    end
                    COOL_MED: begin
                        o_aircon_medium<= 1'b1;
                        o_aircon_full  <= 1'b0;
                        o_aircon_low   <= 1'b0;
                        o_heater_full  <= 1'b0;
                        o_heater_medium<= 1'b0;
                        o_heater_low   <= 1'b0;
                    end
                    COOL_FULL: begin
                        o_aircon_full  <= 1'b1;
                        o_aircon_medium<= 1'b0;
                        o_aircon_low   <= 1'b0;
                        o_heater_full  <= 1'b0;
                        o_heater_medium<= 1'b0;
                        o_heater_low   <= 1'b0;
                    end
                    AMBIENT: begin
                        o_heater_full  <= 1'b0;
                        o_heater_medium<= 1'b0;
                        o_heater_low   <= 1'b0;
                        o_aircon_full  <= 1'b0;
                        o_aircon_medium<= 1'b0;
                        o_aircon_low   <= 1'b0;
                    end
                endcase
                // Fan control: fan is on if any heater/aircon output is active OR if i_fan_on is asserted.
                o_fan <= (state != AMBIENT) || i_fan_on;
            end

            // Update FSM state output
            o_state <= state;
        end
    end

endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite (
  input  logic         clk,
  input  logic         reset,
  input  logic [3:0]   axi_addr,
  input  logic [31:0]  axi_wdata,
  input  logic         axi_write_en,
  input  logic         axi_read_en,
  output logic [31:0]  axi_rdata,
  output logic         interrupt
);

  //-------------------------------------------------------------------------
  // Register Definitions
  //-------------------------------------------------------------------------
  // All registers are 32-bit wide, but only the lower 16 bits are used.
  reg [31:0] count_reg;
  reg [31:0] match_value_reg;
  reg [31:0] reload_value_reg;
  reg [31:0] control_reg;
  reg [31:0] status_reg;

  //-------------------------------------------------------------------------
  // Control Register Bit Positions
  //-------------------------------------------------------------------------
  parameter ENABLE_BIT         = 0;
  parameter INTERVAL_MODE_BIT   = 1;
  parameter INTERRUPT_ENABLE_BIT= 2;

  //-------------------------------------------------------------------------
  // AXI-Lite Read Data Assignment
  //-------------------------------------------------------------------------
  always_comb begin
    unique case (axi_addr)
      4'h0: axi_rdata = count_reg;              // Count Register (lower 16 bits)
      4'h1: axi_rdata = match_value_reg;         // Match Value Register (lower 16 bits)
      4'h2: axi_rdata = reload_value_reg;        // Reload Value Register (lower 16 bits)
      4'h3: axi_rdata = control_reg;             // Control Register
      4'h4: axi_rdata = status_reg;              // Status Register
      default: axi_rdata = 32'd0;
    endcase
  end

  //-------------------------------------------------------------------------
  // Sequential Logic: Synchronous Operations
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      // Reset all registers and clear the interrupt flag.
      count_reg        <= 32'd0;
      match_value_reg  <= 32'd0;
      reload_value_reg <= 32'd0;
      control_reg      <= 32'd0;
      status_reg       <= 32'd0;
    end
    else begin
      //-------------------------------------------------------------------------
      // Process AXI-Lite Write Operations
      //-------------------------------------------------------------------------
      if (axi_write_en) begin
        unique case (axi_addr)
          4'h0: begin
                   // Count register is read-only; ignore writes.
                 end
          4'h1: begin
                   // Write to Match Value Register (only lower 16 bits used)
                   match_value_reg <= axi_wdata;
                 end
          4'h2: begin
                   // Write to Reload Value Register (only lower 16 bits used)
                   reload_value_reg <= axi_wdata;
                 end
          4'h3: begin
                   // Write to Control Register (enable, interval mode, interrupt enable)
                   control_reg <= axi_wdata;
                 end
          4'h4: begin
                   // Write to Status Register clears the interrupt flag.
                   // We update all bits except bit 0 is forced to 0.
                   status_reg <= {axi_wdata[31:1], 1'b0};
                 end
          default: ; // No operation for undefined addresses.
        endcase
      end

      //-------------------------------------------------------------------------
      // Timer/Counter Logic
      //-------------------------------------------------------------------------
      if (control_reg[ENABLE_BIT]) begin
        // Compute next count value.
        logic [31:0] next_count;
        next_count = count_reg + 1;

        // Check for match using the lower 16 bits.
        if (next_count[15:0] == match_value_reg[15:0]) begin
          // A match event has occurred.
          if (control_reg[INTERVAL_MODE_BIT]) begin
            // In interval mode, reload the counter.
            next_count = reload_value_reg;
          end
          else begin
            // In non-interval mode, hold the counter at the match value.
            next_count = match_value_reg;
          end
          // Set the match flag (interrupt flag) in the status register.
          status_reg <= 1;
        end
        else begin
          // No match event; clear the match flag.
          status_reg <= 0;
        end

        // Update the counter with the computed value.
        count_reg <= next_count;
      end
      // If not enabled, the counter remains unchanged.
    end
  end

  //-------------------------------------------------------------------------
  // Interrupt Output Assignment
  //-------------------------------------------------------------------------
  // The interrupt is asserted if the match flag is set and interrupts are enabled.
  assign interrupt = status_reg[0] & control_reg[INTERRUPT_ENABLE_BIT];

endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot (
    input         sign,
    input         size,
    input  [2:0]  one_hot_selector,
    input  [255:0] source_reg,
    output reg [511:0] destination_reg
);

  // In this implementation the destination register is always 512 bits wide.
  // To achieve this, the unpacking is performed over only a portion of source_reg
  // so that the total expanded width equals 512 bits.
  //
  // For one_hot_selector = 3'b001:
  //   Each 1-bit segment (from the lower 64 bits of source_reg) is expanded to 8 bits.
  //   (64 segments x 8 bits = 512 bits)
  //
  // For one_hot_selector = 3'b010:
  //   Each 2-bit segment (from the lower 128 bits of source_reg) is expanded to 8 bits.
  //   (64 segments x 8 bits = 512 bits)
  //
  // For one_hot_selector = 3'b100:
  //   When size = 1:
  //     Each 8-bit segment (all 256 bits of source_reg divided into 32 segments)
  //     is expanded to 16 bits.
  //     (32 segments x 16 bits = 512 bits)
  //
  //   When size = 0:
  //     Each 4-bit segment (all 256 bits divided into 64 segments)
  //     is expanded to 8 bits.
  //     (64 segments x 8 bits = 512 bits)
  //
  // Default case:
  //   The source_reg is directly assigned to the lower 256 bits of destination_reg
  //   (the upper 256 bits remain zero).

  integer i;
  reg [7:0] seg;  // temporary register to hold the extracted segment

  always @(*) begin
    // Default initialization: clear destination register
    destination_reg = 512'd0;

    case(one_hot_selector)
      3'b001: begin
        // Unpack lower 64 bits of source_reg:
        // Each 1-bit segment is expanded to an 8-bit segment.
        for(i = 0; i < 64; i = i + 1) begin
          // Extract the i-th bit from source_reg.
          if (sign)
            // Sign-extend: replicate the bit into all upper bits.
            destination_reg[8*i+7:8*i] = {{7{source_reg[i]}}, source_reg[i]};
          else
            // Zero-extend.
            destination_reg[8*i+7:8*i] = {7'b0, source_reg[i]};
        end
      end

      3'b010: begin
        // Unpack lower 128 bits of source_reg:
        // Each 2-bit segment is expanded to an 8-bit segment.
        // (There are 64 segments: 64 x 2 = 128 bits used from source_reg.)
        for(i = 0; i < 64; i = i + 1) begin
          seg = source_reg[2*i+1:2*i];  // extract 2 bits
          if (sign)
            destination_reg[8*i+7:8*i] = {{7{seg[1]}}, seg};
          else
            destination_reg[8*i+7:8*i] = {7'b0, seg};
        end
      end

      3'b100: begin
        if (size) begin
          // size = 1: Each 8-bit segment (from the full 256-bit source_reg)
          // is expanded to a 16-bit segment.
          // (256/8 = 32 segments; 32 x 16 = 512 bits)
          for(i = 0; i < 32; i = i + 1) begin
            seg = source_reg[8*i+7:8*i];  // extract 8 bits
            if (sign)
              destination_reg[16*i+15:16*i] = {{7{seg[7]}}, seg};
            else
              destination_reg[16*i+15:16*i] = {7'b0, seg};
          end
        end
        else begin
          // size = 0: Each 4-bit segment (from the full 256-bit source_reg)
          // is expanded to an 8-bit segment.
          // (256/4 = 64 segments; 64 x 8 = 512 bits)
          for(i = 0; i < 64; i = i + 1) begin
            seg = source_reg[4*i+3:4*i];  // extract 4 bits
            if (sign)
              destination_reg[8*i+7:8*i] = {{7{seg[3]}}, seg};
            else
              destination_reg[8*i+7:8*i] = {7'b0, seg};
          end
        end
      end

      default: begin
        // Default behavior: assign source_reg directly to the lower 256 bits
        // of destination_reg; the upper 256 bits remain zero.
        destination_reg = {256'd0, source_reg};
      end
    endcase
  end

endmodule

