module vending_machine (
  input  logic         clk,
  input  logic         rst,
  input  logic         item_button,
  input  logic [2:0]   item_selected,
  input  logic [3:0]   coin_input,
  input  logic         cancel,
  output logic         dispense_item,
  output logic         return_change,
  output logic [4:0]   item_price,
  output logic [4:0]   change_amount,
  output logic [2:0]   dispense_item_id,
  output logic         error,
  output logic         return_money
);

  //-------------------------------------------------------------------------
  // Local Parameters for FSM States
  //-------------------------------------------------------------------------
  typedef enum logic [2:0] {
    IDLE                = 3'd0,
    ITEM_SELECTION      = 3'd1,
    PAYMENT_VALIDATION  = 3'd2,
    DISPENSING_ITEM     = 3'd3,
    RETURN_CHANGE       = 3'd4,
    RETURN_MONEY        = 3'd5
  } state_t;

  //-------------------------------------------------------------------------
  // Internal Registers and Wires
  //-------------------------------------------------------------------------
  state_t state, next_state;
  logic [7:0] coins_accum;  // 8-bit accumulator for coin values
  logic [4:0] price_reg;    // Registered item price

  // Registers for one-cycle pulse outputs
  logic dispense_item_reg;
  logic return_change_reg;
  logic return_money_reg;
  logic error_reg;
  logic error_flag;  // Flag to indicate an error condition

  // Registers for detecting rising edges of toggle signals
  logic item_button_reg;
  logic cancel_reg;
  logic item_button_rising;
  logic cancel_rising;

  //-------------------------------------------------------------------------
  // Rising Edge Detection for Toggle Signals
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      item_button_reg <= 1'b0;
      cancel_reg      <= 1'b0;
    end else begin
      item_button_reg <= item_button;
      cancel_reg      <= cancel;
    end
  end

  assign item_button_rising = item_button && !item_button_reg;
  assign cancel_rising      = cancel      && !cancel_reg;

  //-------------------------------------------------------------------------
  // FSM: Sequential Logic
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state             <= IDLE;
      coins_accum       <= 8'd0;
      price_reg         <= 5'd0;
      dispense_item_reg <= 1'b0;
      return_change_reg <= 1'b0;
      return_money_reg  <= 1'b0;
      error_reg         <= 1'b0;
      error_flag        <= 1'b0;
    end else begin
      // Update rising edge registers (already done above)

      // Determine Next State based on current state and inputs
      case (state)
        IDLE: begin
          // In IDLE, if any coin is inserted without item_button, trigger error.
          if (coin_input != 4'd0) begin
            next_state = RETURN_MONEY;
          end else if (item_button_rising) begin
            next_state = ITEM_SELECTION;
          end else begin
            next_state = IDLE;
          end
        end

        ITEM_SELECTION: begin
          // If cancel is pressed, trigger error.
          if (cancel_rising) begin
            next_state = RETURN_MONEY;
          end else if (
            (item_selected == 3'b001) ||
            (item_selected == 3'b010) ||
            (item_selected == 3'b011) ||
            (item_selected == 3'b100)
          ) begin
            // Set price based on the selected item.
            case (item_selected)
              3'b001: price_reg = 5;    // Price: 5 units
              3'b010: price_reg = 10;   // Price: 10 units
              3'b011: price_reg = 15;   // Price: 15 units
              3'b100: price_reg = 20;   // Price: 20 units
              default: price_reg = 5'd0;
            endcase
            next_state = PAYMENT_VALIDATION;
          end else begin
            // Invalid item selection triggers error.
            next_state = RETURN_MONEY;
          end
        end

        PAYMENT_VALIDATION: begin
          // If cancel is pressed, trigger error.
          if (cancel_rising) begin
            next_state = RETURN_MONEY;
          end else if (
            (coin_input == 4'd1) ||
            (coin_input == 4'd2) ||
            (coin_input == 4'd5) ||
            (coin_input == 4'd10)
          ) begin
            // Accumulate valid coin input.
            coins_accum <= coins_accum + coin_input;
            if (coins_accum >= price_reg) begin
              next_state = DISPENSING_ITEM;
            end else begin
              next_state = PAYMENT_VALIDATION;
            end
          end else begin
            // Invalid coin value triggers error.
            next_state = RETURN_MONEY;
          end
        end

        DISPENSING_ITEM: begin
          // Dispense item for one clock cycle.
          if (cancel_rising) begin
            next_state = RETURN_MONEY;
          end else begin
            if (coins_accum > price_reg) begin
              next_state = RETURN_CHANGE;
            end else begin
              next_state = IDLE;
            end
          end
        end

        RETURN_CHANGE: begin
          // After dispensing, return change if any.
          next_state = IDLE;
        end

        RETURN_MONEY: begin
          // Refund all inserted coins due to cancellation or error.
          next_state = IDLE;
        end

        default: next_state = IDLE;
      endcase

      // Set error flag if transitioning to RETURN_MONEY due to an error.
      if (next_state == RETURN_MONEY) begin
        if (
          (state == ITEM_SELECTION && !(
            (item_selected == 3'b001) ||
            (item_selected == 3'b010) ||
            (item_selected == 3'b011) ||
            (item_selected == 3'b100)
          )) ||
          (state == PAYMENT_VALIDATION && !(
            (coin_input == 4'd1) ||
            (coin_input == 4'd2) ||
            (coin_input == 4'd5) ||
            (coin_input == 4'd10)
          )) ||
          (state == IDLE && coin_input != 4'd0)
        ) begin
          error_flag <= 1'b1;
        end else begin
          error_flag <= 1'b0;
        end
      end else begin
        error_flag <= 1'b0;
      end

      // Update coins_accum: if in PAYMENT_VALIDATION with valid coin, accumulate;
      // if an error occurs (transitioning to RETURN_MONEY), clear the accumulator.
      if (state == PAYMENT_VALIDATION && (
            (coin_input == 4'd1) ||
            (coin_input == 4'd2) ||
            (coin_input == 4'd5) ||
            (coin_input == 4'd10)
          )) begin
        coins_accum <= coins_accum + coin_input;
      end else if (next_state == RETURN_MONEY) begin
        coins_accum <= 8'd0;
      end

      // Generate one-cycle pulse outputs based on next state.
      dispense_item_reg   <= (next_state == DISPENSING_ITEM);
      return_change_reg   <= (next_state == RETURN_CHANGE);
      return_money_reg    <= (next_state == RETURN_MONEY);
      error_reg           <= (next_state == RETURN_MONEY && error_flag);

      // Update the state register.
      state <= next_state;
    end
  end

  //-------------------------------------------------------------------------
  // Output Assignments
  //-------------------------------------------------------------------------
  assign dispense_item   = dispense_item_reg;
  assign return_change   = return_change_reg;
  assign error           = error_reg;
  assign return_money    = return_money_reg;
  assign item_price      = price_reg;  // Displays the price once item is selected

  // change_amount is valid only in the RETURN_CHANGE state.
  assign change_amount   = (state == RETURN_CHANGE) ? (coins_accum - price_reg) : 5'd0;

  // dispense_item_id outputs the selected item ID only during dispensing.
  assign dispense_item_id = (state == DISPENSING_ITEM) ? item_selected : 3'd0;

endmodule

output.rtl/vga_controller.sv:
module vga_controller (
  input  logic clock,
  input  logic reset,
  input  logic [7:0] color_in,
  output logic hsync,
  output logic vsync,
  output logic [7:0] red,
  output logic [7:0] green,
  output logic [7:0] blue,
  output logic [9:0] next_x,
  output logic [9:0] next_y,
  output logic sync,
  output logic clk,
  output logic blank
);

  // Timing parameters for 640x480 VGA
  localparam integer H_ACTIVE   = 640;
  localparam integer H_FRONT    = 16;
  localparam integer H_PULSE    = 96;
  localparam integer H_BACK     = 48;
  localparam integer H_TOTAL    = H_ACTIVE + H_FRONT + H_PULSE + H_BACK; // 800 cycles

  localparam integer V_ACTIVE   = 480;
  localparam integer V_FRONT    = 10;
  localparam integer V_PULSE    = 2;
  localparam integer V_BACK     = 33;
  localparam integer V_TOTAL    = V_ACTIVE + V_FRONT + V_PULSE + V_BACK; // 525 lines

  // Counters for horizontal and vertical timing
  reg [9:0] h_counter;
  reg [9:0] v_counter;
  reg       line_done;  // Indicates end of horizontal line

  // Registered outputs (all logic updated on the positive clock edge)
  reg [7:0] red_reg;
  reg [7:0] green_reg;
  reg [7:0] blue_reg;
  reg [9:0] next_x_reg;
  reg [9:0] next_y_reg;
  reg       hsync_reg;
  reg       vsync_reg;
  reg       blank_reg;
  reg       sync_reg;
  reg       clk_reg;

  // Single always_ff block implementing state machines and output logic
  always_ff @(posedge clock or posedge reset) begin
    if (reset) begin
      h_counter  <= 10'd0;
      v_counter  <= 10'd0;
      line_done  <= 1'b0;
      hsync_reg  <= 1'b1;
      vsync_reg  <= 1'b1;
      red_reg    <= 8'd0;
      green_reg  <= 8'd0;
      blue_reg   <= 8'd0;
      next_x_reg <= 10'd0;
      next_y_reg <= 10'd0;
      blank_reg  <= 1'b0;
      sync_reg   <= 1'b0;
      clk_reg    <= 1'b0;
    end else begin
      // Determine if the current horizontal line is complete.
      // (Using the previous value of h_counter to set line_done.)
      if (h_counter == H_TOTAL - 1)
        line_done <= 1'b1;
      else
        line_done <= 1'b0;

      // Update horizontal counter.
      if (h_counter == H_TOTAL - 1)
        h_counter <= 10'd0;
      else
        h_counter <= h_counter + 1;

      // Update vertical counter only at the end of a horizontal line.
      if (line_done) begin
        if (v_counter == V_TOTAL - 1)
          v_counter <= 10'd0;
        else
          v_counter <= v_counter + 1;
      end

      // Generate hsync signal.
      // hsync is HIGH during H_ACTIVE, H_FRONT, and H_BACK periods;
      // it is LOW during the H_PULSE (sync pulse) period.
      if ((h_counter < H_ACTIVE) ||
          (h_counter >= H_ACTIVE && h_counter < H_ACTIVE + H_FRONT) ||
          (h_counter >= H_ACTIVE + H_FRONT + H_PULSE &&
           h_counter < H_ACTIVE + H_FRONT + H_PULSE + H_BACK))
        hsync_reg <= 1'b1;
      else
        hsync_reg <= 1'b0;

      // Generate vsync signal.
      // vsync is HIGH during V_ACTIVE+V_FRONT and V_BACK periods;
      // it is LOW during the V_PULSE (sync pulse) period.
      if ((v_counter < V_ACTIVE + V_FRONT) ||
          (v_counter >= V_ACTIVE + V_FRONT + V_PULSE &&
           v_counter < V_ACTIVE + V_FRONT + V_PULSE + V_BACK))
        vsync_reg <= 1'b1;
      else
        vsync_reg <= 1'b0;

      // Pixel position tracking: next_x and next_y are valid only during the active display area.
      if (h_counter < H_ACTIVE)
        next_x_reg <= h_counter;
      else
        next_x_reg <= 10'd0;

      if (v_counter < V_ACTIVE)
        next_y_reg <= v_counter;
      else
        next_y_reg <= 10'd0;

      // RGB output control.
      // When within the active region, scale color_in to 8-bit values:
      //   red   = {color_in[7:5], 5'd0};
      //   green = {color_in[4:2], 5'd0};
      //   blue  = {color_in[1:0], 6'd0};
      // Otherwise, output 0.
      if (h_counter < H_ACTIVE && v_counter < V_ACTIVE) begin
        red_reg    <= {color_in[7:5], 5'd0};
        green_reg  <= {color_in[4:2], 5'd0};
        blue_reg   <= {color_in[1:0], 6'd0};
      end else begin
        red_reg    <= 8'd0;
        green_reg  <= 8'd0;
        blue_reg   <= 8'd0;
      end

      // Blank signal: ACTIVE HIGH when not in the active display region.
      if ((h_counter >= H_ACTIVE) || (v_counter >= V_ACTIVE))
        blank_reg <= 1'b1;
      else
        blank_reg <= 1'b0;

      // Sync signal is fixed to LOW.
      sync_reg <= 1'b0;

      // VGA clock is directly connected to the input clock.
      clk_reg <= clock;
    end
  end

  // Drive module outputs from registered signals.
  assign hsync   = hsync_reg;
  assign vsync   = vsync_reg;
  assign red     = red_reg;
  assign green   = green_reg;
  assign blue    = blue_reg;
  assign next_x  = next_x_reg;
  assign next_y  = next_y_reg;
  assign sync    = sync_reg;
  assign clk     = clk_reg;
  assign blank   = blank_reg;

endmodule

module vga_controller (
    input  logic         clock,      // 25 MHz
    input  logic         reset,      // Active high
    input  logic [7:0]   color_in,   // Pixel color data (RRRGGGBB)
    output logic [9:0]   next_x,     // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0]   next_y,     // y-coordinate of NEXT pixel that will be drawn
    output logic         hsync,      // HSYNC (to VGA connector)
    output logic         vsync,      // VSYNC (to VGA connector)
    output logic [7:0]   red,        // RED (to resistor DAC VGA connector)
    output logic [7:0]   green,      // GREEN (to resistor DAC to VGA connector)
    output logic [7:0]   blue,       // BLUE (to resistor DAC to VGA connector)
    output logic         sync,       // SYNC to VGA connector
    output logic         clk,        // CLK to VGA connector
    output logic         blank,      // BLANK to VGA connector
    output logic [7:0]   h_state,    // States of Horizontal FSM
    output logic [7:0]   v_state     // States of Vertical FSM
);

    // Timing parameters for 640x480 VGA
    parameter logic [9:0] H_ACTIVE  = 10'd640;
    parameter logic [9:0] H_FRONT   = 10'd16;
    parameter logic [9:0] H_PULSE   = 10'd96;
    parameter logic [9:0] H_BACK    = 10'd48;
    parameter logic [9:0] V_ACTIVE  = 10'd480;
    parameter logic [9:0] V_FRONT   = 10'd10;
    parameter logic [9:0] V_PULSE   = 10'd2;
    parameter logic [9:0] V_BACK    = 10'd33;

    // Logic levels
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;

    // Horizontal FSM state encoding
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;

    // Vertical FSM state encoding
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;

    // Internal registers for sync signals
    logic hsync_reg;
    logic vsync_reg;

    // Internal counters and signals
    logic         line_done;
    logic [9:0]   h_counter;
    logic [9:0]   v_counter;

    // Always block: update horizontal and vertical FSMs and RGB outputs
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            // ---------------------------
            // Horizontal State Machine
            // ---------------------------
            case (h_state)
                H_ACTIVE_STATE: begin
                    if (h_counter < H_ACTIVE - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_ACTIVE_STATE;
                    end
                    else begin
                        h_state <= H_FRONT_STATE;
                    end
                    hsync_reg <= HIGH;
                end

                H_FRONT_STATE: begin
                    if (h_counter < H_FRONT - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_FRONT_STATE;
                    end
                    else begin
                        h_state <= H_PULSE_STATE;
                    end
                    hsync_reg <= HIGH;
                end

                H_PULSE_STATE: begin
                    if (h_counter < H_PULSE - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_PULSE_STATE;
                    end
                    else begin
                        h_state <= H_BACK_STATE;
                    end
                    hsync_reg <= LOW;
                end

                H_BACK_STATE: begin
                    if (h_counter < H_BACK - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_BACK_STATE;
                    end
                    else begin
                        h_state   <= H_ACTIVE_STATE;
                        h_counter <= 10'd0;
                        line_done <= HIGH;
                    end
                    hsync_reg <= HIGH;
                end
            endcase

            // ---------------------------
            // Vertical State Machine
            // Update vertical counter only at the end of a line (line_done == HIGH)
            // ---------------------------
            if (line_done == HIGH) begin
                case (v_state)
                    V_ACTIVE_STATE: begin
                        if (v_counter < V_ACTIVE - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_ACTIVE_STATE;
                        end
                        else begin
                            v_state <= V_FRONT_STATE;
                        end
                        vsync_reg <= HIGH;
                    end

                    V_FRONT_STATE: begin
                        if (v_counter < V_FRONT - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_FRONT_STATE;
                        end
                        else begin
                            v_state <= V_PULSE_STATE;
                        end
                        vsync_reg <= HIGH;
                    end

                    V_PULSE_STATE: begin
                        if (v_counter < V_PULSE - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_PULSE_STATE;
                        end
                        else begin
                            v_state <= V_BACK_STATE;
                        end
                        vsync_reg <= LOW;
                    end

                    V_BACK_STATE: begin
                        if (v_counter < V_BACK - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_BACK_STATE;
                        end
                        else begin
                            v_state   <= V_ACTIVE_STATE;
                            v_counter <= 10'd0;
                        end
                        vsync_reg <= HIGH;
                    end
                endcase
            end

            // ---------------------------
            // RGB Signal Handling
            // During active video period, output the input color.
            // During non-active periods, drive RGB to zero.
            // ---------------------------
            if ((h_state == H_ACTIVE_STATE) && (v_state == V_ACTIVE_STATE)) begin
                red   <= color_in;
                green <= color_in;
                blue  <= color_in;
            end
            else begin
                red   <= 8'd0;
                green <= 8'd0;
                blue  <= 8'd0;
            end
        end
    end

    // Output assignments
    assign hsync  = hsync_reg;
    assign vsync  = vsync_reg;
    assign blank  = hsync_reg & vsync_reg;
    assign clk    = clock;
    assign sync   = 1'b0;

    // Next pixel coordinates (active only during active video period)
    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

input.rtl/vga_controller.sv:
module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,     // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state  // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;


    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                   h_counter <= (h_counter == (H_ACTIVE - 1)) ? 10'd0 : (h_counter + 10'd1);
                   hsync     <= HIGH;
                   line_done <= LOW;
                   h_state   <= (h_counter == (H_ACTIVE - 1)) ? H_FRONT_STATE : H_ACTIVE_STATE;
                end
                H_FRONT_STATE: begin
                   h_counter <= (h_counter == (H_FRONT - 1)) ? 10'd0 : (h_counter + 10'd1);
                   hsync     <= HIGH;
                   h_state   <= (h_counter == (H_FRONT - 1)) ? H_PULSE_STATE : H_FRONT_STATE;
                end
                H_PULSE_STATE: begin
                  h_counter <= (h_counter == (H_PULSE - 1)) ? 10'd0 : (h_counter + 10'd1);
                  hsync     <= LOW;
                  h_state   <= (h_counter == (H_PULSE - 1)) ? H_BACK_STATE : H_PULSE_STATE;
                end
                H_BACK_STATE: begin
                  h_counter <= (h_counter == (H_BACK - 1)) ? 10'd0 : (h_counter + 10'd1);
                  hsync     <= HIGH;
                  h_state   <= (h_counter == (H_BACK - 1)) ? H_ACTIVE_STATE : H_BACK_STATE;
                  line_done <= (h_counter == (H_BACK - 1)) ? HIGH: LOW;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_ACTIVE - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_ACTIVE - 1) ? V_FRONT_STATE : V_ACTIVE_STATE;
                    end
                    vsync  <= HIGH;
                end
                V_FRONT_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_FRONT - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_FRONT - 1) ? V_PULSE_STATE : V_FRONT_STATE;
                    end
                    vsync  <= HIGH;
                end
                V_PULSE_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_PULSE - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_PULSE - 1) ? V_BACK_STATE : V_PULSE_STATE;
                    end
                    vsync  <= LOW;
                end
                V_BACK_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_BACK - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_BACK - 1) ? V_ACTIVE_STATE : V_BACK_STATE;
                    end
                    vsync  <= HIGH;
                end
            endcase
            if (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) begin
                red       <= {color_in[7:5], 5'd0};
                green     <= {color_in[4:2], 5'd0};
                blue      <= {color_in[1:0], 6'd0};
            end
            else begin
                red       <= 8'd0;
                green     <= 8'd0;
                blue      <= 8'd0;
            end
        end
    end


    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

output.rtl/vga_controller.sv:
module vga_controller (
    input  logic         clock,      // 25 MHz
    input  logic         reset,      // Active high
    input  logic [7:0]   color_in,   // Pixel color data (RRRGGGBB)
    output logic [9:0]   next_x,     // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0]   next_y,     // y-coordinate of NEXT pixel that will be drawn
    output logic         hsync,      // HSYNC (to VGA connector)
    output logic         vsync,      // VSYNC (to VGA connector)
    output logic [7:0]   red,        // RED (to resistor DAC VGA connector)
    output logic [7:0]   green,      // GREEN (to resistor DAC to VGA connector)
    output logic [7:0]   blue,       // BLUE (to resistor DAC to VGA connector)
    output logic         sync,       // SYNC to VGA connector
    output logic         clk,        // CLK to VGA connector
    output logic         blank,      // BLANK to VGA connector
    output logic [7:0]   h_state,    // States of Horizontal FSM
    output logic [7:0]   v_state     // States of Vertical FSM
);

  // Timing parameters
  parameter logic [9:0] H_ACTIVE  =  10'd640;
  parameter logic [9:0] H_FRONT   =  10'd16;
  parameter logic [9:0] H_PULSE   =  10'd96;
  parameter logic [9:0] H_BACK    =  10'd48;
  parameter logic [9:0] V_ACTIVE  =  10'd480;
  parameter logic [9:0] V_FRONT   =  10'd10;
  parameter logic [9:0] V_PULSE   =  10'd2;
  parameter logic [9:0] V_BACK    =  10'd33;
  parameter logic        LOW       = 1'b0;
  parameter logic        HIGH      = 1'b1;
  parameter logic [7:0]  H_ACTIVE_STATE  = 8'd0;
  parameter logic [7:0]  H_FRONT_STATE   = 8'd1;
  parameter logic [7:0]  H_PULSE_STATE   = 8'd2;
  parameter logic [7:0]  H_BACK_STATE    = 8'd3;
  parameter logic [7:0]  V_ACTIVE_STATE  = 8'd0;
  parameter logic [7:0]  V_FRONT_STATE   = 8'd1;
  parameter logic [7:0]  V_PULSE_STATE   = 8'd2;
  parameter logic [7:0]  V_BACK_STATE    = 8'd3;

  // Sequential logic registers
  logic         line_done;
  logic [9:0]   h_counter;
  logic [9:0]   v_counter;

  // Optimized sequential block: using if/else in place of nested ternaries
  always_ff @(posedge clock or posedge reset) begin
    if (reset) begin
      h_counter <= 10'd0;
      v_counter <= 10'd0;
      h_state   <= H_ACTIVE_STATE;
      v_state   <= V_ACTIVE_STATE;
      line_done <= LOW;
    end else begin
      // Horizontal state update (reduces multiplexer depth)
      case (h_state)
        H_ACTIVE_STATE: begin
          if (h_counter == H_ACTIVE - 1) begin
            h_counter <= 10'd0;
            h_state   <= H_FRONT_STATE;
          end else begin
            h_counter <= h_counter + 10'd1;
            h_state   <= H_ACTIVE_STATE;
          end
          hsync     <= HIGH;
          line_done <= LOW;
        end
        H_FRONT_STATE: begin
          if (h_counter == H_FRONT - 1) begin
            h_counter <= 10'd0;
            h_state   <= H_PULSE_STATE;
          end else begin
            h_counter <= h_counter + 10'd1;
            h_state   <= H_FRONT_STATE;
          end
          hsync     <= HIGH;
        end
        H_PULSE_STATE: begin
          if (h_counter == H_PULSE - 1) begin
            h_counter <= 10'd0;
            h_state   <= H_BACK_STATE;
          end else begin
            h_counter <= h_counter + 10'd1;
            h_state   <= H_PULSE_STATE;
          end
          hsync     <= LOW;
        end
        H_BACK_STATE: begin
          if (h_counter == H_BACK - 1) begin
            h_counter <= 10'd0;
            h_state   <= H_ACTIVE_STATE;
            line_done <= HIGH;
          end else begin
            h_counter <= h_counter + 10'd1;
            h_state   <= H_BACK_STATE;
            line_done <= LOW;
          end
          hsync     <= HIGH;
        end
      endcase

      // Vertical state update: update only when line_done is high
      if (line_done == HIGH) begin
        case (v_state)
          V_ACTIVE_STATE: begin
            if (v_counter == V_ACTIVE - 1) begin
              v_counter <= 10'd0;
              v_state   <= V_FRONT_STATE;
            end else begin
              v_counter <= v_counter + 10'd1;
              v_state   <= V_ACTIVE_STATE;
            end
            vsync  <= HIGH;
          end
          V_FRONT_STATE: begin
            if (v_counter == V_FRONT - 1) begin
              v_counter <= 10'd0;
              v_state   <= V_PULSE_STATE;
            end else begin
              v_counter <= v_counter + 10'd1;
              v_state   <= V_FRONT_STATE;
            end
            vsync  <= HIGH;
          end
          V_PULSE_STATE: begin
            if (v_counter == V_PULSE - 1) begin
              v_counter <= 10'd0;
              v_state   <= V_BACK_STATE;
            end else begin
              v_counter <= v_counter + 10'd1;
              v_state   <= V_PULSE_STATE;
            end
            vsync  <= LOW;
          end
          V_BACK_STATE: begin
            if (v_counter == V_BACK - 1) begin
              v_counter <= 10'd0;
              v_state   <= V_ACTIVE_STATE;
            end else begin
              v_counter <= v_counter + 10'd1;
              v_state   <= V_BACK_STATE;
            end
            vsync  <= HIGH;
          end
        endcase
      end else begin
        // When not at end-of-line, drive vsync based on current vertical state
        vsync  <= (v_state == V_PULSE_STATE) ? LOW : HIGH;
      end

      // Drive color outputs only during active video
      if (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) begin
        red   <= {color_in[7:5], 5'd0};
        green <= {color_in[4:2], 5'd0};
        blue  <= {color_in[1:0], 6'd0};
      end else begin
        red   <= 8'd0;
        green <= 8'd0;
        blue  <= 8'd0;
      end
    end
  end

  // Combinational assignments
  assign clk   = clock;
  assign sync  = 1'b0;
  assign blank = hsync & vsync;
  assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
  assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

output.rtl/virtual2physical_tlb.sv:
module virtual2physical_tlb #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, TLB_SIZE = 4, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    output [PAGE_WIDTH-1:0] physical_address,
    output hit, miss
);
    wire tlb_write_enable, flush, ready;
    wire [PAGE_WIDTH-1:0] page_table_entry;

    // Instantiate TLB module
    TLB #(.TLB_SIZE(TLB_SIZE), .ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH)) tlb (
        .clk(clk),
        .reset(reset),
        .virtual_address(virtual_address),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush),
        .page_table_entry(page_table_entry),
        .physical_address(physical_address),
        .hit(hit),
        .miss(miss)
    );

    // Instantiate Page Table Handler
    PageTableHandler #(.ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH), .PAGE_TABLE_SIZE(PAGE_TABLE_SIZE)) page_table_handler(
        .clk(clk),
        .reset(reset),
        .miss(miss),
        .virtual_page(virtual_address),
        .page_table_entry(page_table_entry),
        .ready(ready)
    );

    // Instantiate Control Unit
    ControlUnit control_unit (
        .clk(clk),
        .reset(reset),
        .hit(hit),
        .miss(miss),
        .ready(ready),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush)
    );
endmodule

// -------------------------------------------------------------------
// TLB Module: Implements a small cache of virtual-to-physical translations.
// Supports hit/miss detection, dynamic entry replacement (round-robin),
// and flush functionality.
// -------------------------------------------------------------------
module TLB #(parameter TLB_SIZE = 4, ADDR_WIDTH = 8, PAGE_WIDTH = 8) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    input tlb_write_enable,
    input flush,
    input [PAGE_WIDTH-1:0] page_table_entry,
    output reg [PAGE_WIDTH-1:0] physical_address,
    output reg hit,
    output reg miss
);
    // Storage arrays for virtual tags and physical pages
    reg [ADDR_WIDTH-1:0] virtual_tags[TLB_SIZE-1:0];
    reg [PAGE_WIDTH-1:0] physical_pages[TLB_SIZE-1:0];
    reg valid_bits[TLB_SIZE-1:0];
    // Replacement index for round-robin update
    reg [$clog2(TLB_SIZE)-1:0] replacement_index;
    integer i;

    // Combinational block: Check for a TLB hit by comparing virtual address tags.
    always_comb begin
        hit = 1'b0;
        miss = 1'b1;
        physical_address = {PAGE_WIDTH{1'b0}};
        for (i = 0; i < TLB_SIZE; i = i + 1) begin
            if (valid_bits[i] && (virtual_tags[i] == virtual_address)) begin
                hit = 1'b1;
                miss = 1'b0;
                physical_address = physical_pages[i];
            end
        end
    end

    // Sequential block: Update the TLB on write enable or flush.
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Invalidate all entries on reset.
            for (i = 0; i < TLB_SIZE; i = i + 1) begin
                valid_bits[i] <= 1'b0;
                virtual_tags[i] <= {ADDR_WIDTH{1'b0}};
                physical_pages[i] <= {PAGE_WIDTH{1'b0}};
            end
            replacement_index <= 0;
        end else begin
            if (flush) begin
                // Flush all TLB entries.
                for (i = 0; i < TLB_SIZE; i = i + 1) begin
                    valid_bits[i] <= 1'b0;
                    virtual_tags[i] <= {ADDR_WIDTH{1'b0}};
                    physical_pages[i] <= {PAGE_WIDTH{1'b0}};
                end
                replacement_index <= 0;
            end else if (tlb_write_enable) begin
                // Update the entry at the current replacement index.
                physical_pages[replacement_index] <= page_table_entry;
                virtual_tags[replacement_index] <= virtual_address;
                valid_bits[replacement_index] <= 1'b1;
                // Move to the next index (round-robin replacement).
                replacement_index <= (replacement_index + 1) % TLB_SIZE;
            end
        end
    end
endmodule

// -------------------------------------------------------------------
// Page Table Handler: Simulates a page table memory access.
// On a TLB miss, it retrieves the corresponding page table entry.
// -------------------------------------------------------------------
module PageTableHandler #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input miss,
    input [ADDR_WIDTH-1:0] virtual_page,
    output reg [PAGE_WIDTH-1:0] page_table_entry,
    output reg ready
);
    // Simulated page table memory (for simulation purposes)
    reg [PAGE_WIDTH-1:0] page_table_memory [0:PAGE_TABLE_SIZE-1];

    // Combinational assignment for page table lookup.
    assign page_table_entry = page_table_memory[virtual_page];

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Initialize page table memory on reset.
            page_table_memory[0] <= 8'h00;
            page_table_memory[1] <= 8'h01;
            page_table_memory[2] <= 8'h02;
            page_table_memory[3] <= 8'h03;
            page_table_memory[4] <= 8'h04;
            page_table_memory[5] <= 8'h05;
            page_table_memory[6] <= 8'h06;
            page_table_memory[7] <= 8'h07;
            page_table_memory[8] <= 8'h08;
            page_table_memory[9] <= 8'h09;
            page_table_memory[10] <= 8'h0A;
            page_table_memory[11] <= 8'h0B;
            page_table_memory[12] <= 8'h0C;
            page_table_memory[13] <= 8'h0D;
            page_table_memory[14] <= 8'h0E;
            page_table_memory[15] <= 8'h0F;
            ready <= 1'b0;
        end else if (miss) begin
            // Simulate memory access delay; in a real design, ready would be asserted after a delay.
            ready <= 1'b1;
        end else begin
            ready <= 1'b0;
        end
    end
endmodule

// -------------------------------------------------------------------
// Control Unit: Manages the state transitions for TLB miss handling,
// page table retrieval, and TLB update.
// -------------------------------------------------------------------
module ControlUnit (
    input clk,
    input reset,
    input hit,
    input miss,
    input ready,
    output reg tlb_write_enable,
    output reg flush
);
    reg [1:0] state;

    localparam IDLE   = 2'b00,
               FETCH  = 2'b01,
               UPDATE = 2'b10;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
            tlb_write_enable <= 1'b0;
            flush <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    // Stay idle if hit; if miss, move to FETCH state.
                    if (miss) begin
                        state <= FETCH;
                    end
                    tlb_write_enable <= 1'b0;
                    flush <= 1'b0;
                end
                FETCH: begin
                    // Wait until the page table entry is ready.
                    if (ready) begin
                        state <= UPDATE;
                    end
                    tlb_write_enable <= 1'b0;
                    flush <= 1'b0;
                end
                UPDATE: begin
                    // Enable TLB write to update the TLB with the new page table entry.
                    tlb_write_enable <= 1'b1;
                    state <= IDLE;
                    flush <= 1'b0;
                end
                default: begin
                    state <= IDLE;
                    tlb_write_enable <= 1'b0;
                    flush <= 1'b0;
                end
            endcase
        end
    end
endmodule

output.rtl/wishbone_to_ahb_bridge.sv:
module wishbone_to_ahb_bridge (
  // Wishbone Ports (from WB Master)
  input  logic         clk_i,
  input  logic         rst_i,
  input  logic         cyc_i,
  input  logic         stb_i,
  input  logic [3:0]   sel_i,
  input  logic         we_i,
  input  logic [31:0]  addr_i,
  input  logic [31:0]  data_i,

  // AHB Ports (from AHB Slave)
  input  logic         hclk,
  input  logic         hreset_n,
  input  logic [31:0]  hrdata,
  input  logic [1:0]   hresp,

  // Wishbone Outputs
  output logic [31:0]  data_o,
  output logic         ack_o,

  // AHB Outputs
  output logic [1:0]   htrans,
  output logic [2:0]   hsize,
  output logic [2:0]   hburst,
  output logic         hwrite,
  output logic [31:0]  haddr,
  output logic [31:0]  hwdata
);

  //-------------------------------------------------------------------------
  // Internal Functions: Calculate Transfer Size and Byte Count
  //-------------------------------------------------------------------------
  // Function to calculate the transfer size (in bytes) based on sel_i.
  // Assumes contiguous selection starting from LSB.
  function automatic int calc_bytes (input logic [3:0] sel);
    if (sel[0]) begin
      if (sel[1]) begin
        if (sel[2]) begin
          if (sel[3])
            return 4;  // Word transfer
          else
            return 4;  // For simplicity, treat as word if non-contiguous upper nibble
        end else begin
          return 2;  // Halfword transfer
        end
      end else begin
        return 1;  // Byte transfer
      end
    end
    return 1; // Default to 1 byte if no LSB selected
  endfunction

  // Function to calculate AHB hsize signal based on transfer size.
  // AHB hsize: 3'b000 = byte, 3'b001 = halfword, 3'b010 = word.
  function automatic logic [2:0] calc_hsize (input logic [3:0] sel);
    int bytes;
    bytes = calc_bytes(sel);
    if (bytes == 4)
      return 3'b010; // Word
    else if (bytes == 2)
      return 3'b001; // Halfword
    else
      return 3'b000; // Byte
  endfunction

  // Function to perform endian conversion (byte swap).
  function automatic logic [31:0] swap_endian (input logic [31:0] data);
    return { data[7:0], data[15:8], data[23:16], data[31:24] };
  endfunction

  //-------------------------------------------------------------------------
  // Internal Registers and State Machine
  //-------------------------------------------------------------------------
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    NONSEQ  = 2'b01,
    BUSY    = 2'b10
  } state_t;

  state_t state, next_state;

  // Registers to hold transaction attributes for AHB phase.
  logic [31:0] haddr_reg;
  logic [2:0]  hsize_reg;
  logic        hwrite_reg;
  logic [31:0] hwdata_reg;

  // Register to capture Wishbone transaction info.
  logic [31:0] wb_addr_reg;
  logic [31:0] wb_data_reg;
  logic [3:0]  wb_sel_reg;
  logic        wb_we_reg;

  // FSM next state logic
  always_comb begin
    next_state = state;
    // Default outputs for AHB signals in combinational block.
    htrans      = 2'b00; // Default IDLE
    hburst      = 3'b000; // Always SINGLE transfer
    hwrite      = 1'b0;
    haddr       = 32'h0;
    hwdata      = 32'h0;
    ack_o       = 1'b0;
    data_o      = 32'h0;

    case (state)
      IDLE: begin
        // On valid Wishbone transaction, capture inputs and move to NONSEQ.
        if (cyc_i && stb_i) begin
          wb_addr_reg  = addr_i;
          wb_data_reg  = data_i;
          wb_sel_reg   = sel_i;
          wb_we_reg    = we_i;
          next_state   = NONSEQ;
        end
      end

      NONSEQ: begin
        // Latch transaction attributes for AHB phase.
        haddr_reg   = wb_addr_reg & (~({32{calc_bytes(wb_sel_reg)-1}})); // Align address to transfer size
        hsize_reg   = calc_hsize(wb_sel_reg);
        hwrite_reg  = wb_we_reg;
        hwdata_reg  = wb_we_reg ? swap_endian(wb_data_reg) : 32'h0;
        // Issue NONSEQ phase.
        htrans      = 2'b01;
        haddr       = haddr_reg;
        hsize       = hsize_reg;
        hburst      = 3'b000;
        hwrite      = hwrite_reg;
        hwdata      = hwdata_reg;
        next_state  = BUSY;
      end

      BUSY: begin
        // Hold transaction attributes until AHB slave is ready.
        htrans      = 2'b10;
        haddr       = haddr_reg;
        hsize       = hsize_reg;
        hburst      = 3'b000;
        hwrite      = hwrite_reg;
        hwdata      = hwdata_reg;
        // Once hready is asserted, complete the transaction.
        if (hready) begin
          // Endian convert read data from AHB to Wishbone.
          data_o = swap_endian(hrdata);
          ack_o  = 1'b1;
          next_state = IDLE;
        end
      end

      default: next_state = IDLE;
    endcase
  end

  // Synchronize state and transaction attributes.
  always_ff @(posedge clk_i or posedge rst_i) begin
    if (rst_i) begin
      state <= IDLE;
    end else begin
      state <= next_state;
    end
  end

  // Note: In a real design, separate clock domains for clk_i and hclk would require
  // proper synchronization. For simplicity, this example assumes a single clock domain.

endmodule

output.rtl/Word_Change_Pulse.sv:
module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8 // Default word width
) (
    input  wire                  clk,               // Clock signal for synchronizing operations
    input  wire                  reset,             // Reset signal to initialize the module
    input  wire [DATA_WIDTH-1:0] data_in,           // Input data, width defined by parameter DATA_WIDTH
    input  wire [DATA_WIDTH-1:0] mask,              // Mask signal to enable/disable change detection for each bit
    input  wire [DATA_WIDTH-1:0] match_pattern,     // Pattern to match for generating the pulse
    input  wire                  enable,            // Enable signal to allow module operation
    input  wire                  latch_pattern,     // Signal to latch the match pattern
    output reg                   word_change_pulse, // Output signal indicating a change in any bit of data_in
    output reg                   pattern_match_pulse, // Output signal indicating a match with the pattern
    output reg [DATA_WIDTH-1:0]  latched_pattern    // Latched pattern for comparison
);

    wire [DATA_WIDTH-1:0] change_pulses;

    reg [DATA_WIDTH-1:0] masked_data_in;
    reg [DATA_WIDTH-1:0] masked_change_pulses;
    reg                  match_detected;

    genvar i;

    // Instantiate Bit_Change_Detector modules for each bit
    generate
        for(i = 0; i < DATA_WIDTH; i = i + 1) begin : gen_bit_change
            Bit_Change_Detector u_bit_change (
                .clk(clk),
                .reset(reset),
                .bit_in(data_in[i]),
                .change_pulse(change_pulses[i])
            );
        end
    endgenerate

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            masked_data_in         <= {DATA_WIDTH{1'b0}};
            masked_change_pulses   <= {DATA_WIDTH{1'b0}};
            word_change_pulse      <= 1'b0;
            match_detected         <= 1'b0;
            pattern_match_pulse    <= 1'b0;
            latched_pattern        <= {DATA_WIDTH{1'b0}};
        end else if (enable) begin
            // Latch the match pattern when latch_pattern is asserted
            if (latch_pattern)
                latched_pattern <= match_pattern;

            // Apply the mask to the data input and to the change pulses
            masked_data_in         <= data_in & mask;
            masked_change_pulses   <= change_pulses & mask;

            // Generate a word-level pulse if any masked bit has changed
            word_change_pulse      <= |masked_change_pulses;

            // Check for pattern match: compare masked data with (latched_pattern & mask)
            if (masked_data_in == (latched_pattern & mask))
                match_detected <= 1'b1;
            else
                match_detected <= 1'b0;

            // Drive the pattern match pulse
            pattern_match_pulse    <= match_detected;
        end else begin
            // When enable is low, clear the outputs
            word_change_pulse      <= 1'b0;
            pattern_match_pulse    <= 1'b0;
        end
    end

endmodule


// Bit_Change_Detector Module
module Bit_Change_Detector (
   input  wire clk,          // Clock signal
   input  wire reset,       // Reset signal to initialize the module
   input  wire bit_in,      // Single bit input to detect changes
   output reg  change_pulse // Pulse signal indicating a change in the input bit
);

    reg bit_in_d;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            bit_in_d     <= 1'b0;
            change_pulse <= 1'b0;
        end else begin
            bit_in_d <= bit_in;
        end
    end

    always @(*) begin
        // Generate a pulse if the current bit differs from the previous value
        change_pulse = (bit_in != bit_in_d);
    end

endmodule

output.rtl/Data_Reduction.sv:
module Data_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter DATA_WIDTH         = 4,      // Width of each data element
    parameter DATA_COUNT         = 4,      // Number of data elements
    localparam TOTAL_INPUT_WIDTH = DATA_WIDTH * DATA_COUNT
)
(
    input  wire [TOTAL_INPUT_WIDTH-1:0] data_in,
    output reg  [DATA_WIDTH-1:0]        reduced_data_out
);

    generate
        genvar bit_index;
        // Iterate over each bit position within a single data word
        for (bit_index = 0; bit_index < DATA_WIDTH; bit_index = bit_index + 1) begin : bit_processing
            wire [DATA_COUNT-1:0] extracted_bits;
            genvar j;
            // Extract the corresponding bit from each data element
            for (j = 0; j < DATA_COUNT; j = j + 1) begin : extract_bit
                assign extracted_bits[j] = data_in[j*DATA_WIDTH + bit_index];
            end
            // Instantiate Bitwise_Reduction module for the current bit position
            Bitwise_Reduction #(
                .REDUCTION_OP(REDUCTION_OP),
                .BIT_COUNT(DATA_COUNT)
            ) bit_red_inst (
                .input_bits(extracted_bits),
                .reduced_bit(reduced_data_out[bit_index])
            );
        end
    endgenerate

endmodule


module Bitwise_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter BIT_COUNT          = 4       // Number of bits to reduce
)
(
    input  wire [BIT_COUNT-1:0] input_bits,
    output reg                  reduced_bit
);

    // Reduction Operation Codes
    localparam [2:0] AND_OP  = 3'b000;
    localparam [2:0] OR_OP   = 3'b001;
    localparam [2:0] XOR_OP  = 3'b010;
    localparam [2:0] NAND_OP = 3'b011;
    localparam [2:0] NOR_OP  = 3'b100;
    localparam [2:0] XNOR_OP = 3'b101;

    int i;
    reg temp_result; // Intermediate result

    always @(*) begin
        // Initialize result with the first bit
        temp_result = input_bits[0];

        // Reduce bits using the selected operation
        for (i = 1; i < BIT_COUNT; i = i + 1) begin
            case (REDUCTION_OP)
                AND_OP, NAND_OP  : temp_result = temp_result & input_bits[i];
                OR_OP,  NOR_OP   : temp_result = temp_result | input_bits[i];
                XOR_OP, XNOR_OP  : temp_result = temp_result ^ input_bits[i];
                default          : temp_result = temp_result & input_bits[i];
            endcase
        end

        // For NAND, NOR, and XNOR operations, invert the result
        case (REDUCTION_OP)
            NAND_OP: reduced_bit = ~temp_result;
            NOR_OP : reduced_bit = ~temp_result;
            XNOR_OP: reduced_bit = ~temp_result;
            default: reduced_bit = temp_result;
        endcase
    end
endmodule

